-- Poems batch 423
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-4766','萨真人夜断碧桃花・幺篇','无名氏','元','元曲','yuanqu','','[]','他那里恼乱春风卒未休，(梅香云)姐姐，这场事怎生结果也？(正旦唱)则着我独立花前黯自愁，泪不住点儿流。',83,'元曲/yuanqu.json','["他那里恼乱春风卒未休，(梅香云)姐姐，这场事怎生结果也？(正旦唱)则着我独立花前黯自愁，泪不住点儿流。", "(做背科，唱)他须是我天缘配偶，常言道女大不中留。", "(同梅香下)。"]'),
('yuanqu-4767','萨真人夜断碧桃花・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','则我这杏脸藏春，柳眉标恨，萦方寸。',28,'元曲/yuanqu.json','["则我这杏脸藏春，柳眉标恨，萦方寸。", "无奈东君。", "花落春将尽。"]'),
('yuanqu-4768','萨真人夜断碧桃花・混江龙','无名氏','元','元曲','yuanqu','','[]','消不的一天愁闷，清明时节雨纷纷。',69,'元曲/yuanqu.json','["消不的一天愁闷，清明时节雨纷纷。", "慵施粉黛，倦点朱唇。", "恰便似薄命照君青冢恨，少年倩女绿窗魂。", "这其间可正是我愁时分，则见那巢空翡翠，冢卧麒麟。"]'),
('yuanqu-4769','萨真人夜断碧桃花・油葫芦','无名氏','元','元曲','yuanqu','','[]','为甚么我一上青山便化身？端的愁杀人，常只是安排肠断又黄昏，害了个恹渐渐的鬼病儿，积趱下重重叠叠恨。',120,'元曲/yuanqu.json','["为甚么我一上青山便化身？端的愁杀人，常只是安排肠断又黄昏，害了个恹渐渐的鬼病儿，积趱下重重叠叠恨。", "做了个虚飘飘的恶梦儿，捱不出凄凄凉凉运。", "一会家急急煎煎腹内焦，一会家寻寻思思心内忍。", "闪的我悲悲切切孤儿寡儿无投奔，因此上凄凄惨惨，无语暗消魂。"]'),
('yuanqu-4770','萨真人夜断碧桃花・天下乐','无名氏','元','元曲','yuanqu','','[]','可怜见梦里形容病里身，则今春，憔悴损，比着这花枝更添瘦几分。',53,'元曲/yuanqu.json','["可怜见梦里形容病里身，则今春，憔悴损，比着这花枝更添瘦几分。", "也无心对镜鸾。", "也无心整鬓云，我只怕韶光也妒人。"]'),
('yuanqu-4771','萨真人夜断碧桃花・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','俺只待看是何人？他那里呀的开门。',165,'元曲/yuanqu.json','["俺只待看是何人？他那里呀的开门。", "(张道南做见科，云)花阴下好一个女子也！看他那云鬟雾鬓，杏脸桃腮，柳眉星眼，不由咱不动心也。", "俺试问他咱：那壁小娘子，谁氏人家？夤夜到此何故？(正旦唱)哎，你个题诗的相如，休问我听琴的文君，(张道南云)小生只为春色困人，闲观月色，不期遇着小娘子。", "(正旦唱)元来是恼春色孤眠不稳，早难道为贱妾断梦劳魂。"]'),
('yuanqu-4772','萨真人夜断碧桃花・寄生草','无名氏','元','元曲','yuanqu','','[]','他把那寒温叙，礼数勤。',122,'元曲/yuanqu.json','["他把那寒温叙，礼数勤。", "(张道南云)此一会小官三生有圭也。", "(正旦唱)则见他曲躬躬笑把言词问，好着我羞答答忙把身躯褪。", "我只索悄冥冥俞把容颜认。", "(云)敢问相公高姓？(张道南云)小生姓张，双名道南。", "(正旦唱)可正是月明千里故人来，惭愧你东风一夜传芳讯。"]'),
('yuanqu-4773','萨真人夜断碧桃花・醉中天','无名氏','元','元曲','yuanqu','','[]','妾身抱天地无穷恨，蒙雨露有深思。',123,'元曲/yuanqu.json','["妾身抱天地无穷恨，蒙雨露有深思。", "(张道南云)住处有甚邻舍？(正旦唱)常则和野草闲花作比邻。", "(张道南云)小娘子家有多远？(正旦唱)俺住处路接天台近。", "(张道南云)你那里还有何人？(正旦唱)俺那里有的是秦人晋人，你可也休将咱盘问，则管里絮叨叨拔树寻根。"]'),
('yuanqu-4774','萨真人夜断碧桃花・金盏儿','无名氏','元','元曲','yuanqu','','[]','他将我厮温存，我将他索殷勤。',430,'元曲/yuanqu.json','["他将我厮温存，我将他索殷勤。", "口儿未说早心儿顺，俺两个正是那不因亲者强来亲。", "(张道南云)趁此月色，共饮几杯，、岂不美乎？(正旦唱)你待要花前同酌酒，灯细论文。", "(张道南云)如此好天良夜，只合早成就了洞房花烛，有甚心情还论文哩？(正旦唱)你则待风清明月夜，成就了花烛洞房春。", "(云)相公，贱妾千金之体，一旦委之足下，只愿你他日休负了人者。", "(张道南云)小娘子放心，我若负了心呵，天不盖，地不载，日月不照临。", "我着你稳取五花官诰，驷马香车，永为秦晋之匹也。", "(正旦云)妾身与相公成此亲事，或诗或词，求一首珠玉，以为后会张本。", "(张道南云)只是小官学问短浅，焉敢在小娘子跟前卖弄手作！(正旦云)愿求珠玉。", "(张道南做写科)(词云)缟衣仙子来何处？咫尺近桃源路。", "说是武陵溪畔住，玉纤微露，金莲稳步，只恐莺花妒。", "邂逅刘郎垂一顾，何事匆匆便归去。", "临别叮咛嘱咐。", "柳亭花馆，月窗云户，休把春辜负。", "右调寄青玉案。", "张道南作。", "(正旦云)相公是好高才也。", "(张道南云)芜词拙笔，徒污仙眼耳。", "(正旦唱)。"]'),
('yuanqu-4775','萨真人夜断碧桃花・后庭花','无名氏','元','元曲','yuanqu','','[]','写的来银钩般字字真，珠玑般句句新。',134,'元曲/yuanqu.json','["写的来银钩般字字真，珠玑般句句新。", "端的是笔落惊风雨，诗成泣鬼神。", "不是我意相亲，听了这一篇谈沦。", "他能书如王右军，能文似扬子云。", "现如今拥双凫做宰臣，许下我五花诰为县君。", "(正旦云)相公，妾身收下这词，永为家宝。", "(张道南云)量小生之词，有何才能，蒙小娘子如此珍重？(正旦唱)。"]'),
('yuanqu-4776','萨真人夜断碧桃花・柳叶儿','无名氏','元','元曲','yuanqu','','[]','则要的言而有信，不索你唬鬼瞒神。',56,'元曲/yuanqu.json','["则要的言而有信，不索你唬鬼瞒神。", "端的个十分才更有十分俊，休使我心儿困。", "常将这脚儿勤，咱两个拚则在梦儿中暮雨朝云。"]'),
('yuanqu-4777','萨真人夜断碧桃花・赚煞尾','无名氏','元','元曲','yuanqu','','[]','从今后将红叶不题济，准备着青鸟先传信。',292,'元曲/yuanqu.json','["从今后将红叶不题济，准备着青鸟先传信。", "(张道南云)小官焉敢负小娘子，但有负心，神明鉴察。", "(正旦唱)则要你说下言词有准，休着我为你个薄幸王魁告海神。", "(张道南云)小官见小娘子千娇百媚，早把俺那片魂灵儿勾引去了。", "(正旦唱)则你这俏心儿引惹了三魂，今日托终身，和你待燕尔新婚。", "(张道南云)此一宵欢爱，如锦鸳成对，似彩凤成双，岂不是一夜夫妻百夜恩？(正旦唱)休忘了一夜夫妻百夜恩，(张道南云)只愿小娘子早谐连理，共效于飞，以足生平之愿，(正旦唱)则要你日亲日近，俺可便相随相趁，(张道南云)小官感蒙小娘子厚情，我只愿学那张敞，断然不敢做王魁也。", "(正旦唱)哎，你个画眉人可休做了那负心人。", "(下)。"]'),
('yuanqu-4778','萨真人夜断碧桃花・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','则他这暮景相催，叹桑榆半竿红日，恨无情兔走乌飞。',60,'元曲/yuanqu.json','["则他这暮景相催，叹桑榆半竿红日，恨无情兔走乌飞。", "被莺花。", "闲魔障，他可都笑人憔翠。", "到如今翠减双眉，羞见这鬓边霜将镜鸾懒对。"]'),
('yuanqu-4779','萨真人夜断碧桃花・醉春风','无名氏','元','元曲','yuanqu','','[]','我这里叹世事若浮云，想光阴如逝水。',208,'元曲/yuanqu.json','["我这里叹世事若浮云，想光阴如逝水。", "常则在大人家服侍了许多年，端的是喜，喜。", "赤紧的小姐谦和，相公宽厚。", "更遇着大人贤慧。", "(嬷嬷云)可早来到也。", "兴儿，你报复去，说徐亲家差嬷嬷问安哩。", "(兴儿报科，云)相公，有徐家嬷嬷，在于门首。", "(张道南云)快请进，(见科)(嬷嬷云)相公，老身奉老相公言语，本待自来问候，恐怕相公病体，迎接不便，径着老身来探近日病体如何？(张道南云)我害的病，不阴不阳，发寒发热，不知是甚么症侯？(嬷嬷唱)。"]'),
('yuanqu-4780','萨真人夜断碧桃花・普天乐','无名氏','元','元曲','yuanqu','','[]','你莫不是断王事费精神？(张道南云)不是。',190,'元曲/yuanqu.json','["你莫不是断王事费精神？(张道南云)不是。", "(嬷嬷唱)莫不是因茶饭伤脾胃？(张道南云)也不是。", "(嬷嬷唱)莫不是风寒感冒，因病成疾？(张道南云)也不是。", "(嬷嬷唱)莫不是文章上若用心？(张道南云)也不是。", "(嬷嬷唱)莫不是鞍马上多劳力？(张道南云)这都不是。", "(做叹气科)(嬷嬷唱)哎，他那里无语无言只是长吁气，多敢怕等闲问泄漏了天机。", "他又不肯明明的说破，则这般恹恹的瘦损，好教我暗暗的猜疑。"]'),
('yuanqu-4781','萨真人夜断碧桃花・石榴花','无名氏','元','元曲','yuanqu','','[]','他口夸大语说是赛卢医，卖弄那声价有谁及，医方脉诀幼曾习。',193,'元曲/yuanqu.json','["他口夸大语说是赛卢医，卖弄那声价有谁及，医方脉诀幼曾习。", "(净做看脉科)(嬷嬷唱)这病呵是风寒暑湿，巩饱劳役？(云)太医你下甚么苎？(太医云)我下服建中汤，减了附子，加上官桂，就着他疾病痊可也。", "(嬷嬷唱)你用着建中汤去附子，加官桂必然见功效神奇。", "(太医云)这寸关尺三指脉微沉细，常是寒热往来，则怕这病候有些差迟，休说我医生不会看脉。", "(嬷嬷唱)怎又道寸关尺三部脉都沉细，还只怕这病候有差迟。"]'),
('yuanqu-4782','萨真人夜断碧桃花・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','元来是风月上留情，全不是寒热间害疾。',70,'元曲/yuanqu.json','["元来是风月上留情，全不是寒热间害疾。", "你则待送雨行云，那些儿于家为国？常言道心病从来无药医，这等干相思不似你，空则想梦里佳人，做了个色中饿鬼。"]'),
('yuanqu-4783','萨真人夜断碧桃花・上小楼','无名氏','元','元曲','yuanqu','','[]','那小姐十分整齐，千般娇媚。',119,'元曲/yuanqu.json','["那小姐十分整齐，千般娇媚。", "他生的纤纤玉笋，小小银钩，淡淡蛾眉。", "(张道南云)他有见识么？(嬷嬷唱)他可便有见识。", "(张道南云)他有福气么？(嬷嬷唱)他可便有福气，堪为匹配，(张道南云)他来我家，便是夫人也。", "(嬷嬷唱)也不辱没了五花诰县君名位。"]'),
('yuanqu-4784','萨真人夜断碧桃花・幺篇','无名氏','元','元曲','yuanqu','','[]','怎么的问着呵越不应？道着呵越不理？(带云)我如今猜着了也。',91,'元曲/yuanqu.json','["怎么的问着呵越不应？道着呵越不理？(带云)我如今猜着了也。", "(张道南云)你猜着甚么？(嬷嬷唱)你恋着雨爱云欢，海誓山盟，月约星期。", "他那里恼一会，叹一会，不知何意？我便是女杨修难猜哑谜。"]'),
('yuanqu-4785','萨真人夜断碧桃花・满庭芳','无名氏','元','元曲','yuanqu','','[]','待招你个先生做女婿，他早是一言既出，你可休心下疑惑。',150,'元曲/yuanqu.json','["待招你个先生做女婿，他早是一言既出，你可休心下疑惑。", "(张道南云)他也识字么？(嬷嬷唱)那小姐诗书上索是攻习，(张道南云)可伶俐么？(嬷嬷唱)那小姐忒温柔俊雅忒伶俐，(张道南云)他伶俐杀也比不的孟光么？(嬷嬷唱)他比孟德耀还多艳质，则你这张京兆怎画蛾眉？真个是天缘对，你可便将息贵体，管教你运至遇良医。"]'),
('yuanqu-4786','萨真人夜断碧桃花・煞尾','无名氏','元','元曲','yuanqu','','[]','向你个相公行且告别。',70,'元曲/yuanqu.json','["向你个相公行且告别。", "(张道南云)嬷嬷。", "你这般惯做媒那？(嬷嬷唱)休道是我惯做媒，我说的这事和谐费了多少元阳气，则索先报与夫人相公喜。", "(下)。"]'),
('yuanqu-4787','萨真人夜断碧桃花・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','帅父将法力施，火将把神通显。',42,'元曲/yuanqu.json','["帅父将法力施，火将把神通显。", "这些时急急煎煎。", "向后园中到处搜寻遍，险闹了那一座森罗殿。"]'),
('yuanqu-4788','萨真人夜断碧桃花・滚绣球','无名氏','元','元曲','yuanqu','','[]','这一个戗金铠身上穿。',102,'元曲/yuanqu.json','["这一个戗金铠身上穿。", "那一个蘸钢鞭腕上悬，一个个气昂昴性儿不善，他每都叫吼吼捋袖拉拳，走的我腿又酸脚又软，不由我不心惊胆战，索陪着笑脸儿褪后趋前。", "你觑那昏昏怨雾迷千里，更和那惨惨浮云散几天，端的是苦海无边。"]'),
('yuanqu-4789','萨真人夜断碧桃花・呆骨朵','无名氏','元','元曲','yuanqu','','[]','告师父那雷连怒息听分辨，待妾身细泌根源。',454,'元曲/yuanqu.json','["告师父那雷连怒息听分辨，待妾身细泌根源。", "(真人云)你敢是思凡的神女么？(正旦唱)我也不足神女思凡，(真人云)敢是天魔地仙么？(正旺唱)也不是天魔地仙。", "(真人云)你是甚么鬼怪？从头实实的说来！(正旦云)妾身是潮阳徐知县之女，小字碧桃。", "俺父亲将我许与张道南为妻。", "当日我父亲不在家，我与梅香往后花园中散心去。", "不想张道南走了白鹦鹉，越墙而过，寻此鹦鹉，偶与妾身相见。", "说话中间，俺父亲来到，张道南害羞而走。", "俺父亲将妾身百般嗔怒，我回绣房中，一气而死，今经三年光景也。", "俺父亲就将俺葬在后花园中，墓顶上长一颗碧桃花树。", "因妾身有二十年阳寿未尽，以此一灵真性不散。", "谁想张道南应举及第，在潮阳为理，妾身念此旧盟，与他重谐匹配。", "张道南曾做〔青玉案〕词留证。", "只此本情，伏望上仙尊鉴不错。", "(真人云)你既然身死，却怎生阴府下不收你那三魂七魄？(正旦唱)我有那二十载阳间寿，(真人云)你既还有阳寿，天曹地府不管，你却这等兴妖作怪？(正旦唱)更有那一万种心头怨。", "(真人云)你怨呵，可怨甚的。", "(正旦唱)辜负我梦行云十二峰，断送的闭荒坟三四年。"]'),
('yuanqu-4790','萨真人夜断碧桃花・倘秀才','无名氏','元','元曲','yuanqu','','[]','直到那判生死阎王殿前，(真人云)你还到那里？(正旦唱)更到那掌善恶曹司案边，他道我这枉死情由实可怜。',73,'元曲/yuanqu.json','["直到那判生死阎王殿前，(真人云)你还到那里？(正旦唱)更到那掌善恶曹司案边，他道我这枉死情由实可怜。", "姻缘注五百载，阳寿有二十年，因此上把刚魂放免。"]'),
('yuanqu-4791','萨真人夜断碧桃花・倘秀才','无名氏','元','元曲','yuanqu','','[]','他可便拂金星砚将龙香墨研，染紫霜毫把笺纸展，(真人云)哦，他写甚么来？(正旦唱)他将那(青玉案)新词写一篇。',123,'元曲/yuanqu.json','["他可便拂金星砚将龙香墨研，染紫霜毫把笺纸展，(真人云)哦，他写甚么来？(正旦唱)他将那(青玉案)新词写一篇。", "(真人云)那秀才只恁的恋酒贪花也。", "(正旦唱)他可便酒肠宽似海，端的是色胆大如天，(真人云)你为甚么便随顺他？(正旦唱)不由我不将他来顾恋。"]'),
('yuanqu-4792','萨真人夜断碧桃花・滚绣球','无名氏','元','元曲','yuanqu','','[]','他将山盟海誓言，向罗帏锦帐眠，(真人云)他这般病了，如何不怕死？(正旦唱)他可便惜花心死而无怨，(真人云)你是甚么时侯，向他跟前去？(正旦唱)止不过赴佳期月下星',223,'元曲/yuanqu.json','["他将山盟海誓言，向罗帏锦帐眠，(真人云)他这般病了，如何不怕死？(正旦唱)他可便惜花心死而无怨，(真人云)你是甚么时侯，向他跟前去？(正旦唱)止不过赴佳期月下星前。", "(真人云)你不去呵，也由得你。", "(正旦唱)他将我死命的留。", "我将他死命的缠，俺两个得成双称心满愿。", "(真人云)他后来告归养病，你不得和他同去，你可敢还思想着他么？(正旦唱)到如今愁和闷有万万千千。", "(真人云)你愁甚么？(正旦唱)我愁的是北邙衰草藏狐兔，恨的是西岭斜阳泣杜鹃，题起来雨泪涟涟。"]'),
('yuanqu-4793','萨真人夜断碧桃花・倘秀才','无名氏','元','元曲','yuanqu','','[]','这一个掌姻缘簿的标写着无缘有缘，那一个掌生死案门先注定十年五年，可正是书案傍边一句言。',105,'元曲/yuanqu.json','["这一个掌姻缘簿的标写着无缘有缘，那一个掌生死案门先注定十年五年，可正是书案傍边一句言。", "(真人云)兀那碧桃，我着你还魂去，夫妻重配，父母团圆，你心下可是如何？(正旦唱)但能勾夫妻敢匹配。", "父母再团圆，我则索谢天！。"]'),
('yuanqu-4794','萨真人夜断碧桃花・随煞尾','无名氏','元','元曲','yuanqu','','[]','谢师父承正法常看诸处行方便，开阐教广与众生解倒悬。',101,'元曲/yuanqu.json','["谢师父承正法常看诸处行方便，开阐教广与众生解倒悬。", "成就夫妻是夙缘，匹配鸾凰趁心愿。", "喜的是前度张郎正少年，早晚灾除病体痊，我也不爱他诗礼儒风祖代传，也不爱他簪笏荣名圣主宣，单则爱那惜玉怜香性儿软。", "(下)。"]'),
('yuanqu-4795','萨真人夜断碧桃花・双调/新水令','无名氏','元','元曲','yuanqu','','[]','则我这俏身躯三载土中埋，今日个得还魂似升天界。',52,'元曲/yuanqu.json','["则我这俏身躯三载土中埋，今日个得还魂似升天界。", "寒灰重发焰，枯树再花开。", "也是我苦尽甘来，常言道否极早生泰。"]'),
('yuanqu-4796','萨真人夜断碧桃花・步步娇','无名氏','元','元曲','yuanqu','','[]','我与你款款前来深深拜，(徐端云)孩儿，你拜甚么？(正旦唱)可怜我白头父母都年迈，间别来可便三二载，(徐端云)可怎么有二三载？(正旦云)你孩儿自离了父母去呵。',172,'元曲/yuanqu.json','["我与你款款前来深深拜，(徐端云)孩儿，你拜甚么？(正旦唱)可怜我白头父母都年迈，间别来可便三二载，(徐端云)可怎么有二三载？(正旦云)你孩儿自离了父母去呵。", "(唱)我正是几度南柯梦中来。", "(徐端云)这是怎么说？(正旦云)你孩儿是碧桃也！(唱)将小名儿道的明白，(徐端云)你道是碧桃，他已死过三年了，你一向在那里？(正旦唱)你孩儿半开中落在那荒郊外。"]'),
('yuanqu-4797','萨真人夜断碧桃花・折桂令','无名氏','元','元曲','yuanqu','','[]','原来是有朋自远方来，你道是济济衣冠，楚楚人才。',123,'元曲/yuanqu.json','["原来是有朋自远方来，你道是济济衣冠，楚楚人才。", "俺也只为情重如山，恩深似海，险害的你骨瘦如柴。", "再不索闹攘攘大惊小怪，这一场悄促促似鬼使神差。", "(张道南云)我几曾与你相见？你是这等说？(正旦唱)想着俺缱绻情怀，鱼水和谐。", "我为你曾下巫山，你为我误入天台。"]'),
('yuanqu-4798','萨真人夜断碧桃花・沽美酒','无名氏','元','元曲','yuanqu','','[]','当日个花园中成眷爱，美欢娱在书斋，则他那海誓山盟是谁道来？哎，你这读书的秀才，俺两个谋成合不谋败。',49,'元曲/yuanqu.json','["当日个花园中成眷爱，美欢娱在书斋，则他那海誓山盟是谁道来？哎，你这读书的秀才，俺两个谋成合不谋败。"]'),
('yuanqu-4799','萨真人夜断碧桃花・太平令','无名氏','元','元曲','yuanqu','','[]','请你个假古忄敝的官人休怪，我这里把新词袖里忙抬。',75,'元曲/yuanqu.json','["请你个假古忄敝的官人休怪，我这里把新词袖里忙抬。", "(出词科，唱)一字字堪怜堪爱，一句句难学难赛。", "我对着众客展开，表白，这(青玉案)是那个的亲笔儿留在？。"]'),
('yuanqu-4800','萨真人夜断碧桃花・豆叶黄','无名氏','元','元曲','yuanqu','','[]','叮怜我滞魄游魂，流落在海角天涯，长伴着野草闲花，残烟断霭。',99,'元曲/yuanqu.json','["叮怜我滞魄游魂，流落在海角天涯，长伴着野草闲花，残烟断霭。", "我只道晓色何曾到夜台，谁承望万里归来，喜喜欢欢，再拜我爹爹奶奶。", "(夫人云)儿也，你便还魂了，只可惜我玉兰孩儿，兀的不苦痛杀我也。", "(正旦唱)。"]'),
('yuanqu-4801','萨真人夜断碧桃花・七兄弟','无名氏','元','元曲','yuanqu','','[]','这也是你的运衰，他的命该，留不得两裙钗。',112,'元曲/yuanqu.json','["这也是你的运衰，他的命该，留不得两裙钗。", "若不是萨真人显出神通大，则我这墓顶上签钉远乡牌，可不的一灵儿永欠下鸳鸯债。", "(张道南云)你既是碧桃小姐，当初相见之时，何不就明对我说？却教我做出这一场病症来，争些儿害杀我也。", "(正旦唱)。"]'),
('yuanqu-4802','萨真人夜断碧桃花・梅花酒','无名氏','元','元曲','yuanqu','','[]','非是我假虚脾爱使乖，也只怕粉脸香腮，引动你蜜意幽怀，倒做了黄祸之灾。',94,'元曲/yuanqu.json','["非是我假虚脾爱使乖，也只怕粉脸香腮，引动你蜜意幽怀，倒做了黄祸之灾。", "因此上把鬼名儿潜换改，真姓也暗藏埋，况阳寿尚未该，婚姻簿又明载，天对付俏身材？云和雨好安排。", "连理树稳情栽，合欢花纵心摘。"]'),
('yuanqu-4803','萨真人夜断碧桃花・收江南','无名氏','元','元曲','yuanqu','','[]','呀，今日个月明千里故人来，镜鸾重整向妆台，这的是换人肌骨夺人胎。',49,'元曲/yuanqu.json','["呀，今日个月明千里故人来，镜鸾重整向妆台，这的是换人肌骨夺人胎。", "休得要乱猜，你不见桃花依旧待春开。"]'),
('yuanqu-4804','黄钟・人月圆','赵雍','元','元曲','yuanqu','','[]','人生能几浑如梦，梦里奈愁何？别时犹记，眸盈秋水，泪湿春罗。',118,'元曲/yuanqu.json','["人生能几浑如梦，梦里奈愁何？别时犹记，眸盈秋水，泪湿春罗。", "绿杨台榭，梨花院宇，重想经过。", "水遥山远，鱼沉雁渺，分外情多！相思何日重相见，山远水偏长。", "风弦虽断，鸾胶难接，愁满离肠。", "最伤情处，鲛绡遗恨，翠靥留香。", "故人何在？浓荫深院，斜月幽窗。"]'),
('yuanqu-4805','仙吕・八声甘州','鲜于枢','元','元曲','yuanqu','','[]','江天暮雪，最可爱青帘摇曳长杠。',54,'元曲/yuanqu.json','["江天暮雪，最可爱青帘摇曳长杠。", "生涯闲散，占断水国渔邦。", "烟浮草屋梅近砌，水绕柴扉山对窗。", "时复竹篱旁，吠犬汪汪。"]'),
('yuanqu-4806','大安乐・从人笑我愚和戆，潇湘影里且妆呆，不谈刘项与孙庞。近小窗，','鲜于枢','元','元曲','yuanqu','','[]','谁羡碧油幢？。',7,'元曲/yuanqu.json','["谁羡碧油幢？。"]'),
('yuanqu-4807','元和令・粳米炊长腰，鳊鱼煮缩项。闷携村酒饮空缸，是非一任讲。恣情','鲜于枢','元','元曲','yuanqu','','[]','拍手棹渔歌，高低不论腔。',12,'元曲/yuanqu.json','["拍手棹渔歌，高低不论腔。"]'),
('yuanqu-4809','同乐院燕青博鱼・幺篇','李文蔚','元','元曲','yuanqu','','[]','罢波，我枉舍了火也似热热的一丹心，早没了我镜也似朗朗的双明目，可着谁养赡我这七尺之躯。',70,'元曲/yuanqu.json','["罢波，我枉舍了火也似热热的一丹心，早没了我镜也似朗朗的双明目，可着谁养赡我这七尺之躯。", "想弟兄每虎据了山东路，则捻了个不出力的燕青去。", "(下)。"]'),
('yuanqu-4810','同乐院燕青博鱼・大石调/六国朝','李文蔚','元','元曲','yuanqu','','[]','我揣巴些残汤剩水，打叠起浪酒闲茶，我着些气呵暖我这冻拳头，再着些唾揩光我这冷鼻凹。',153,'元曲/yuanqu.json','["我揣巴些残汤剩水，打叠起浪酒闲茶，我着些气呵暖我这冻拳头，再着些唾揩光我这冷鼻凹。", "瘦的来我这身子儿没个麻秸大，兀的不消磨了我剌绣的青黛和这朱砂。", "眼见的穷活路觅不出衣和饭，怕不道酷寒亭把我来冻饿杀。", "全不见那昏惨惨云遮了银汉，则听的淅零零雪糁琼沙，我、我、我待踮着个鞋底儿去拣那浅中行，先绰的这棒头来向深处插。"]'),
('yuanqu-4811','同乐院燕青博鱼・喜秋风','李文蔚','元','元曲','yuanqu','','[]','我与你便吖吖叫，我与你便磨磨擦。',99,'元曲/yuanqu.json','["我与你便吖吖叫，我与你便磨磨擦。", "我为甚将这脚尖儿细细踏？我怕只怕这路儿有些步步滑。", "(带云)似我这模样，像个甚的？(唱)将那前街后巷我便如盘卦，刚才个渐渐里呵的我这手温和，可又早切切里冻的我这脚麻辣。"]'),
('yuanqu-4812','同乐院燕青博鱼・归塞北','李文蔚','元','元曲','yuanqu','','[]','天那！您不肯道是相赍发，专与俺这穷汉做冤家。',139,'元曲/yuanqu.json','["天那！您不肯道是相赍发，专与俺这穷汉做冤家。", "这雪呵，他如柳絮不添我身上絮，似梨花却变做了眼前花，则我这拄杖冻难拿。", "(带云)有那等人道：\"兀的君子，那东京城里有的是买卖营生，你寻些做可不好那？\"我道哥也，你岂知我无眼那？他便道：\"寻你那无眼营生去做。", "\"哥也，您那里知道咱。", "(唱)。"]'),
('yuanqu-4813','同乐院燕青博鱼・憨货郎','李文蔚','元','元曲','yuanqu','','[]','莫不是千化身观音菩萨，救了我这双无目沿街的叫化。',76,'元曲/yuanqu.json','["莫不是千化身观音菩萨，救了我这双无目沿街的叫化。", "他道是妙手通灵，圣心无假。", "哥也，多谢你个良医肯把金针下，我又没甚的米麦丝麻，哥也，你则可怜见我这穷汉瞎。"]'),
('yuanqu-4814','同乐院燕青博鱼・归塞北','李文蔚','元','元曲','yuanqu','','[]','他把我眼角儿才针罢，则我这疮口儿未结痂。',68,'元曲/yuanqu.json','["他把我眼角儿才针罢，则我这疮口儿未结痂。", "早将我两只手揉开了这一对眼，(带云)是好手段也！(唱)则当一枚外挑去了一重沙，恰便似日日退残霞。"]'),
('yuanqu-4815','同乐院燕青博鱼・初问口','李文蔚','元','元曲','yuanqu','','[]','俺也曾那草坡前把滥官拿，则俺那梁山泊上宋江，须不比那帮源洞里的方腊。',102,'元曲/yuanqu.json','["俺也曾那草坡前把滥官拿，则俺那梁山泊上宋江，须不比那帮源洞里的方腊。", "你将我这蝼蚁残生厮救拔，我把哥哥那山海也似恩临厮报答。", "从今日拜辞了主人家，绰着这过眼齐眉的枣子棍，依旧到杀人放火蓼儿洼，须认的俺狠那吒。"]'),
('yuanqu-4816','同乐院燕青博鱼・尾声','李文蔚','元','元曲','yuanqu','','[]','你道是他打了我呵似房檐上揭瓦，不信道我打了他呵就着我这脖项上披枷。',115,'元曲/yuanqu.json','["你道是他打了我呵似房檐上揭瓦，不信道我打了他呵就着我这脖项上披枷。", "调动我这莽拳头，拓动我这长捎靶，我向那前街后巷便去爪寻他。", "(带云)若见了他呵，(唱)我一只手揪住那厮黄头发，一只手把腰脚牢掐，我可敢滴溜扑活撺那厮在马直下。", "(下)。"]'),
('yuanqu-4817','同乐院燕青博鱼・仙吕/点绛唇','李文蔚','元','元曲','yuanqu','','[]','刚留的我这没影孤身，借人资本，为营运。',36,'元曲/yuanqu.json','["刚留的我这没影孤身，借人资本，为营运。", "避不得艰辛，则要这两家\"衣食\"准。"]'),
('yuanqu-4818','同乐院燕青博鱼・混江龙','李文蔚','元','元曲','yuanqu','','[]','可怜咱十分贫窘，恰才那打鱼人赊与俺这卖鱼人。',124,'元曲/yuanqu.json','["可怜咱十分贫窘，恰才那打鱼人赊与俺这卖鱼人。", "凭着我六文家铜馒，博的是这三尺金鳞。", "鱼也你在荷叶盘中犹跌尾，怎不想桃花浪里一翻身。", "我去那新红盒子内，拿着这常占胜，不占输，只愁富，不愁穷，明丢丢的几个头钱问。", "钱那！若是告一场响豁，便是我半路里落的这殷勤。"]'),
('yuanqu-4819','同乐院燕青博鱼・那吒令','李文蔚','元','元曲','yuanqu','','[]','这鱼呵，重七斤八斤，你若是博呵，要五纯六纯，着小人呵，也觅一文半文。',69,'元曲/yuanqu.json','["这鱼呵，重七斤八斤，你若是博呵，要五纯六纯，着小人呵，也觅一文半文。", "(带云)主人家有么？(唱)快与我抹下浅盆，磨下刀刃你看我雪片也似批鳞。"]'),
('yuanqu-4820','同乐院燕青博鱼・金盏儿','李文蔚','元','元曲','yuanqu','','[]','比及问五陵人，先顶礼二郎神，哥也，你便博一千博，我这胳膊也无些儿困。',128,'元曲/yuanqu.json','["比及问五陵人，先顶礼二郎神，哥也，你便博一千博，我这胳膊也无些儿困。", "我将那竹根的绳拂子绰了这地皮尘，(云)哥也，老实的博。", "(燕大云)我只是博耍子，有甚么老实不老实？(正末唱)不要你蹲着腰虚土里纵，叠着指漫砖上墩；则要你平着身往下撇，不要你探着手可便往前分。"]'),
('yuanqu-4821','同乐院燕青博鱼・油葫芦','李文蔚','元','元曲','yuanqu','','[]','则这新染来的头钱不甚昏，可不算选的准，手心里明明白白摆定一文文。',125,'元曲/yuanqu.json','["则这新染来的头钱不甚昏，可不算选的准，手心里明明白白摆定一文文。", "(燕大做博科，云)我博了六个镘儿，我赢了也。", "(正末唱)呀呀呀，我则见五个镘儿乞丢磕塔稳，更和一个字儿急留骨碌滚。", "唬的我咬定下唇，掐定指纹，又被这个不防头爱撇的砖儿稳，可是他便一博六浑纯。"]'),
('yuanqu-4822','同乐院燕青博鱼・金盏儿','李文蔚','元','元曲','yuanqu','','[]','我这里抢起折支巾，拽起夜叉裙，(杨衙内做见搽旦科，云)姐姐休怪，我来迟了也。',250,'元曲/yuanqu.json','["我这里抢起折支巾，拽起夜叉裙，(杨衙内做见搽旦科，云)姐姐休怪，我来迟了也。", "(正末做扳杨衙内科，云)哥也，唱着喏去！(做打杨衙内科)(杨衙内打筋斗科)(正末唱)拳着处早可扑的精砖上盹。", "(燕大云)你打死他了也。", "(正末云)哥，你休怕者。", "(唱)看那厮眼朦胧正着昏，我将这大拇指去那厮人中里掐。", "(带云)主人家有水将的些来。", "(唱)新汲水那厮面皮上喷。", "(杨衙内做叹气科)(正末云)哥也，他不死哩。", "(唱)那厮热拖拖的才出气，(杨衙内舒身科)(燕大云)他早翻过身哩。", "(正末云)他怎么肯死？(唱)那厮他跌躞躞的恰还魂。"]'),
('yuanqu-4823','同乐院燕青博鱼・赚煞尾','李文蔚','元','元曲','yuanqu','','[]','你看这鬏髻上扭的出那棘针油，面皮上刮的下那桃花粉，只这两棒儿管做了你个哥哥的祸根。',168,'元曲/yuanqu.json','["你看这鬏髻上扭的出那棘针油，面皮上刮的下那桃花粉，只这两棒儿管做了你个哥哥的祸根。", "穿着些素淡衣服越风韵，兀的不是天生成玉软香温。", "我见他扭回身，抖擞下精神，则被他那眼角眉尖断送了春。", "(正末做打耳喑科，云)哥也，可是这般。", "(燕大云)我知道了也。", "(正末唱)我恰才舌贴着你那耳轮，敢可也一言难尽，哎，哥也你是个好男儿休戴着这一顶屎头巾。", "(下)。"]'),
('yuanqu-4824','同乐院燕青博鱼・中吕/粉蝶儿','李文蔚','元','元曲','yuanqu','','[]','鼓打初更，是谁人推出这一轮明镜，原来是配金乌那兔魄东生。',67,'元曲/yuanqu.json','["鼓打初更，是谁人推出这一轮明镜，原来是配金乌那兔魄东生。", "这早晚玉绳高，银河浅，恰正是夜阑人静。", "端的这月白风清。", "我则见滴溜溜倒垂着斗柄。"]'),
('yuanqu-4825','同乐院燕青博鱼・叫声','李文蔚','元','元曲','yuanqu','','[]','我恰才便横饮到两三巡，灌得我来酩酊、酩酊，犹未醒，(带云)怪道我这脚趔趄站不定呵，(唱)原来那一盏盏都是瓮头甭。',56,'元曲/yuanqu.json','["我恰才便横饮到两三巡，灌得我来酩酊、酩酊，犹未醒，(带云)怪道我这脚趔趄站不定呵，(唱)原来那一盏盏都是瓮头甭。"]'),
('yuanqu-4826','同乐院燕青博鱼・醉春风','李文蔚','元','元曲','yuanqu','','[]','我铺的这艾呀纹藤席净。',84,'元曲/yuanqu.json','["我铺的这艾呀纹藤席净。", "掇过这桃花瓣石枕冷，醉魂儿偏喜月波凉，就这搭儿里挺挺。", "满鼻凹清风，拍胸膛爽气，落的这彻骨毛索性。", "(带云)我是听这上衙更鼓咱。", "(做打二鼓科)(唱)。"]'),
('yuanqu-4827','同乐院燕青博鱼・倘秀才','李文蔚','元','元曲','yuanqu','','[]','鼓打到一更也那二更，犬吠到三声也那四声。',151,'元曲/yuanqu.json','["鼓打到一更也那二更，犬吠到三声也那四声。", "(搽旦同杨衙内上，搽旦云)衙内，咱两个往那黑地里走，休往月亮处，着人瞧见，要说短说长的。", "咱两个打着个暗号：赤、赤、赤！(杨衙内搽旦做跳过正末身科)(正末唱)我这里呵欠罢翻身打个呓挣，(搽旦云)赤、赤、赤！(杨衙内云)赤、赤、赤！(正末唱)蓦见那女娉婷引着个后生。"]'),
('yuanqu-4828','同乐院燕青博鱼・叫声','李文蔚','元','元曲','yuanqu','','[]','眼见的八九分是奸情，是谁家鬼精、鬼精，做出这乔行径？(搽旦云)穿的那衣服，拖天扫地的，一脚踹着，不险些儿绊倒了？捋起衣服来，走、走，赤、赤、赤！(杨衙内云)赤、',104,'元曲/yuanqu.json','["眼见的八九分是奸情，是谁家鬼精、鬼精，做出这乔行径？(搽旦云)穿的那衣服，拖天扫地的，一脚踹着，不险些儿绊倒了？捋起衣服来，走、走，赤、赤、赤！(杨衙内云)赤、赤、赤！(正末唱)怎知道黑影里偏撞着俺这泼燕青。"]'),
('yuanqu-4829','同乐院燕青博鱼・滚绣球','李文蔚','元','元曲','yuanqu','','[]','俺这里将怪眼睁，(搽旦云)把脚抬的轻着些儿，不要走的响了着人听见，又捏舌也。',410,'元曲/yuanqu.json','["俺这里将怪眼睁，(搽旦云)把脚抬的轻着些儿，不要走的响了着人听见，又捏舌也。", "(正末唱)他那里抬的脚步儿轻，他若是但回身，我在这背阴中掩映。", "(杨衙内扯搽旦科)(搽旦云)折了你那手爪子，走便走，这么扯扯拽拽的做甚么？(正末唱)则见他厮扯拽悄地前行。", "(杨衙内云)赤赤赤、(搽旦云)赤赤赤、(正末唱)那厮赤的唤了一声，那妮子赤的应了一声。", "早是这吃敲才胆硬，(搽旦云)咱来到这亭子上也，推开这门进来了。", "关上门，打开吊窗，把这芭蕉扇合着这酒，把这梨花样磁钵遮着暗灯。", "但有人说，你就打吊窗里跳出去，怕做甚么？咱两个自在吃几钟儿。", "(杨衙内云)好，好，我和你吃的醉了，方才有兴。", "(正末云)这厮亭子上去了也。", "(唱)我见他笑吟吟的推入门木呈，比及我唾润开窗纸偷晴觑，他也可背靠定球楼侧耳听，(搽旦云)我这般赤心的待你，只怕你忘了我好处，我要你说个誓来。", "(杨衙内云)我若负了你的心呵，灯草打折脚古拐，现报在你眼里。", "(正末唱)他说甚么海誓也山盟。"]'),
('yuanqu-4830','同乐院燕青博鱼・幺篇','李文蔚','元','元曲','yuanqu','','[]','你这个养汉精，假撇清。',474,'元曲/yuanqu.json','["你这个养汉精，假撇清。", "你道是没奸夫抵死来瞒定，恰才个谁推开这半破窗棂？(搽旦云)我支开亮窗，这里趁风歇凉来。", "(正末唱)谁揉的你这鬓角儿松？(搽旦云)我恰才呼猫，是花枝儿抓着来。", "(正末唱)谁捏的你这腮斗的儿青？(搽旦云)我恰才睡着了，是鬼捏青来。", "(正末唱)可也不须你折证，见放着一个不语先生。", "谁着这芭蕉叶纸扇翻合着酒？谁着这花梨花样磁钵倒暗着灯？这公事要辩个分明。", "(正末云)哥也，这等妇人要做甚么？与我杀了者。", "(燕大云)兄弟，我便要杀他，也没有刀那。", "(正末拔刀科，云)兀的不是刀？(燕大做杀搽旦科)(搽旦云)我那亲哥哥，如今天气热，你便杀了我，到那寒冬腊月里害脚冷，谁与你焐脚？(燕大云)兄弟，不争我杀坏了他，谁与我焐脚？我委实下不的手。", "(正末云)哥也，你杀不的，我替你杀。", "(搽旦叫科，云)有杀人贼也！(杨衙内领随从冲上，云)这厮无故杀人，令人！与我拿住这两个杀人的，都下在死囚牢里去者！(随从做拿住正末、燕大科)(搽旦云)好也，好也！如今都绑下在死囚牢里去了，看你可有本事再来杀我！(燕大云)兄弟也，似此可怎了！(正末云)哥，我恰才不说来，(唱)。"]'),
('yuanqu-4831','同乐院燕青博鱼・煞尾','李文蔚','元','元曲','yuanqu','','[]','则你个纸做的瓶儿怎拔干的井，蜡打的锹儿怎撅的坑？你道他有体态，有聪明，知你的意，会你的情，有他时春自生，没他时坐不宁。',160,'元曲/yuanqu.json','["则你个纸做的瓶儿怎拔干的井，蜡打的锹儿怎撅的坑？你道他有体态，有聪明，知你的意，会你的情，有他时春自生，没他时坐不宁。", "怎知他欠本分，少至诚，忒淫滥苏小卿，不值钱王桂英。", "拿住奸夫你又杀不成，倒被他拖入囚牢死狗似撑。", "也不是我病僧劝患僧，有一日押向云阳市上行，只等的高叫开刀和那声，方才道悔不当初你可便恁时节省。", "(同燕大下)。"]'),
('yuanqu-4832','同乐院燕青博鱼・双调/新水令','李文蔚','元','元曲','yuanqu','','[]','正风清月郎碧天高，(带云)好怪那！(唱)可怎生打独磨觅不着官道？(燕大云)兄弟，若有人追来时，我可躲在那里？(正末唱)你去那大北坡踉跄走，(燕大云)兄弟你呢？(',114,'元曲/yuanqu.json','["正风清月郎碧天高，(带云)好怪那！(唱)可怎生打独磨觅不着官道？(燕大云)兄弟，若有人追来时，我可躲在那里？(正末唱)你去那大北坡踉跄走，(燕大云)兄弟你呢？(正末唱)咱则去那小道儿上隔斜抄。", "行不到半里其高，则听的脑背后喊声闹。"]'),
('yuanqu-4833','同乐院燕青博鱼・沉醉东风','李文蔚','元','元曲','yuanqu','','[]','你去这白革坡潜踪蹑脚，(燕大云)兄弟也，你呢？(正末唱)我在这黄叶林屈脊低腰。',94,'元曲/yuanqu.json','["你去这白革坡潜踪蹑脚，(燕大云)兄弟也，你呢？(正末唱)我在这黄叶林屈脊低腰。", "我曲躬躬的向地皮上伏，立钦钦的把松枝来靠，直挺挺按定枷稍。", "我这里听沉了我时静悄悄，我则见火把和那灯笼可都去了。"]'),
('yuanqu-4834','同乐院燕青博鱼・搅筝琶','李文蔚','元','元曲','yuanqu','','[]','急的我心儿跳，好似热油浇。',287,'元曲/yuanqu.json','["急的我心儿跳，好似热油浇。", "为甚么乾支剌吐着舌头，呆不腾瞪着眼脑？鼻凹里冷气出，咽喉内热涎潮，元来是一缕麻绦，谁把个活套头将他拴住了？(带云)我若来的迟呵，(唱)争些儿一命难逃。", "(燕大云)兄弟，我被那奸夫淫妇，险些儿断送了也。", "(正末云)哥也，我和你赶那厮去来。", "(同下)(燕二上，云)我趁着这月色微明，连夜趱到汴梁，救拔我那燕青兄弟去也。", "(正末上，做撞见科)(喝云)咄！那里来的是甚么人？(燕二云)你说你是那个？(正末云)则我梁山泊好汉，燕青的便是。", "(燕二云)兄弟，我便是卷毛虎燕顺。", "(燕大云)喏，报、报、报！(燕二云)怎的？(燕大云)元来是我兄弟燕二，大家耍一会。", "(正末唱)。"]'),
('yuanqu-4835','同乐院燕青博鱼・乔木查','李文蔚','元','元曲','yuanqu','','[]','俺撩开衣，拽起脚，刚转过这林薄。',131,'元曲/yuanqu.json','["俺撩开衣，拽起脚，刚转过这林薄。", "只听的可磕擦闪出个人来到，元来是俺哥哥厮撞着。", "(云)哥哥，我问你，黑夜里到那里去？(燕二云)兄弟，我如今也在梁山泊上，做个头领了。", "闻知你和大哥被杨衙内拿下死囚牢里，只在早晚要杀坏你两个，因此上告了一个月假限，特来救你。", "(正末唱)。"]'),
('yuanqu-4836','同乐院燕青博鱼・甜水令','李文蔚','元','元曲','yuanqu','','[]','我则道你法灸神针，周流湖海，发卖医药，元来你也要弄俺这家刀。',57,'元曲/yuanqu.json','["我则道你法灸神针，周流湖海，发卖医药，元来你也要弄俺这家刀。", "可怎生在旷野荒郊，月黑时光，风高天道，独自个背着衣包。"]'),
('yuanqu-4837','同乐院燕青博鱼・折桂令','李文蔚','元','元曲','yuanqu','','[]','我有甚犯法违条，只为那淫妇奸夫，险送了你个共乳同胞。',127,'元曲/yuanqu.json','["我有甚犯法违条，只为那淫妇奸夫，险送了你个共乳同胞。", "你待要使用金银，打通关节，救拔囚牢，则俺燕青呵，须不是鹰心雁爪，早跳出虎穴狼巢。", "（燕二云）且喜兄弟今日逍遥无事了也。", "(正末唱）你说甚无事逍遥，争知我怒气难消。", "我若不杀的这两个无徒也，怎显的我半世英豪！。"]'),
('yuanqu-4838','同乐院燕青博鱼・离亭宴歇指煞','李文蔚','元','元曲','yuanqu','','[]','半合儿歇息在牛王庙，一直的走到梁山泊。',116,'元曲/yuanqu.json','["半合儿歇息在牛王庙，一直的走到梁山泊。", "若见俺公明太保，还了俺这石榴色茜红巾，柳叶砌乌油甲，荷叶样烟毡帽，百炼钢打就的长朴刀，五色绒刺下的香绵袄。", "(带云)便是俺大哥也，(唱)一齐的去那皖子城中送老，上稍里不眠花，下场头少不的落一会草。"]'),
('yuanqu-4839','仙吕・八声甘州','王嘉甫','元','元曲','yuanqu','','[]','莺花伴侣，效卓氏弹琴，司马题桥。',55,'元曲/yuanqu.json','["莺花伴侣，效卓氏弹琴，司马题桥。", "情深意远，争奈分浅缘薄。", "香笺寄恨红锦囊，声断传情碧玉箫。", "都为可憎他，梦断魂劳。"]'),
('yuanqu-4840','六幺遍・更身儿倬，庞儿俏。倾城倾国，难画难描。窄弓弓撇道，溜刀刀','王嘉甫','元','元曲','yuanqu','','[]','渌老。',24,'元曲/yuanqu.json','["渌老。", "称霞腮一点米樱小，妖娆，更那堪杨柳小蛮腰。"]'),
('yuanqu-4841','穿窗月・忆双双凤友鸾交，料应咱没分消，真真彼此都相乐。花星儿照，','王嘉甫','元','元曲','yuanqu','','[]','彩云儿飘，不提防坏美众生搅。',14,'元曲/yuanqu.json','["彩云儿飘，不提防坏美众生搅。"]'),
('yuanqu-4842','元和令・谩赢得自己羞，空惹得外人笑。多情却是不多情，好模样歹做作。','王嘉甫','元','元曲','yuanqu','','[]','相逢争似不相逢，有上梢没下梢。',15,'元曲/yuanqu.json','["相逢争似不相逢，有上梢没下梢。"]'),
('yuanqu-4843','赚尾・那回期，今番约，花木瓜儿看好。旧路高高筑起界墙，尽今生永不','王嘉甫','元','元曲','yuanqu','','[]','踏着。',41,'元曲/yuanqu.json','["踏着。", "唱道言许心违，说的誓寻思畅好脱卯。", "待等些气高，难禁脚拗，不由人又走了两三遭。"]'),
('yuanqu-4844','马丹阳度脱刘行首・仙吕/点绛唇','杨景贤','元','元曲','yuanqu','','[]','五祖传因，二师垂训，向甘河镇。',27,'元曲/yuanqu.json','["五祖传因，二师垂训，向甘河镇。", "悟德全真，想大道从心运。"]'),
('yuanqu-4845','马丹阳度脱刘行首・混江龙','杨景贤','元','元曲','yuanqu','','[]','神仙有分，披毡化我出凡尘。',87,'元曲/yuanqu.json','["神仙有分，披毡化我出凡尘。", "脱离了火院，大走入玄门。", "七朵金莲浮水面，一双银海照乾坤。", "奉吾师法旨，我可便普天下都寻尽。", "(带云)寻谁来？(唱)寻俺那丘、刘、谈、马，大古里六个真人。"]'),
('yuanqu-4846','马丹阳度脱刘行首・油葫芦','杨景贤','元','元曲','yuanqu','','[]','袖拂清风足蹑云，行步稳，向人间来往两三春。',121,'元曲/yuanqu.json','["袖拂清风足蹑云，行步稳，向人间来往两三春。", "我这般穷身泼命谁瞅问？蓬头垢面妆痴钝。", "他每不识高共低，不分个假共真。", "(云)有人道：\"兀那抄化的先生，怎生不做几件道衣穿？\"(叹介)(云)嗨！恁世人不知，(唱)则我这丹田有宝能滋润，觑不的他满眼尽愚民。"]'),
('yuanqu-4847','马丹阳度脱刘行首・天下乐','杨景贤','元','元曲','yuanqu','','[]','端的便谁识蓬莱洞里人？你则待贪也波嗔，红尘中空白滚，遮莫恁有金赀怎离三尺坟？君不见霸主强，君不见汉主狠，他每都向北邙山内隐。',131,'元曲/yuanqu.json','["端的便谁识蓬莱洞里人？你则待贪也波嗔，红尘中空白滚，遮莫恁有金赀怎离三尺坟？君不见霸主强，君不见汉主狠，他每都向北邙山内隐。", "(云)来到这西安府城外，别无人家，又无宫观寺院。", "这的是北邙山口，我在这山角下松阴内坐一夜咱。", "贫道观此山下，必有妖精鬼魅。", "我试看咱。", "(唱)。"]'),
('yuanqu-4848','马丹阳度脱刘行首・(醉中天','杨景贤','元','元曲','yuanqu','','[]','我则见水浪生寒气，山势吐妖云。',90,'元曲/yuanqu.json','["我则见水浪生寒气，山势吐妖云。", "这搭儿非鬼非灵决有神，料想我难安稳。", "(带云)你看这云遮月色呵。", "(唱)月暗东西不分，赤力力风操动松韵，(云)我道是甚么那，(唱)原来是鹤飞来相伴我黄昏。"]'),
('yuanqu-4849','马丹阳度脱刘行首・一半儿','杨景贤','元','元曲','yuanqu','','[]','我则见柳垂绿线草铺茵，星撒残棋月挂轮，石亡鹿皮铺垫的稳。',47,'元曲/yuanqu.json','["我则见柳垂绿线草铺茵，星撒残棋月挂轮，石亡鹿皮铺垫的稳。", "松下有白云，我且做一半儿朦胧一半儿盹。"]'),
('yuanqu-4850','马丹阳度脱刘行首・金盏儿','杨景贤','元','元曲','yuanqu','','[]','我则听的语言勤，曲腔真。',77,'元曲/yuanqu.json','["我则听的语言勤，曲腔真。", "梦回明月歌声近。", "他向那青森森树底显香魂。", "(带云)待道不是鬼来呵。", "(唱)可怎生迎风衣不动，对月影难分？这厮他入山山作怪，入水水为神。"]'),
('yuanqu-4851','马丹阳度脱刘行首・醉中天','杨景贤','元','元曲','yuanqu','','[]','一句句依着前韵，一字字和的清新。',100,'元曲/yuanqu.json','["一句句依着前韵，一字字和的清新。", "咱说破超凡入圣因，你怎不把前生认？(旦云)师父脱度鬼魂咱！(正末唱)我度你个无影无形鬼魂，(带云)你既为女人呵，可怎生不还宿债？(唱)则你那宿根未尽，怎生般脱离凡尘？。"]'),
('yuanqu-4852','马丹阳度脱刘行首・后庭花','杨景贤','元','元曲','yuanqu','','[]','你先将那冤业分，次将那宿债准。',51,'元曲/yuanqu.json','["你先将那冤业分，次将那宿债准。", "那其间才脱红尘难，方归那大道门。", "用些殷勤，休辞劳困，我着你重做个妇女身。"]'),
('yuanqu-4853','马丹阳度脱刘行首・赚煞','杨景贤','元','元曲','yuanqu','','[]','我着你托化在雨云乡，还宿债在莺花阵，休迷却前生道本。',102,'元曲/yuanqu.json','["我着你托化在雨云乡，还宿债在莺花阵，休迷却前生道本。", "虽和那野草闲花作近邻，则你那主人公休离了玄门。", "你与我逞精神，送旧迎新，二十载还元见老君。", "欲要见五祖七真，先受些千随百顺，早则不冷清清和月伴荒坟。", "(下)。"]'),
('yuanqu-4854','马丹阳度脱刘行首・正宫/端正好','杨景贤','元','元曲','yuanqu','','[]','下瑶台，离蓬岛，趁西风鹤翅飘摇。',30,'元曲/yuanqu.json','["下瑶台，离蓬岛，趁西风鹤翅飘摇。", "蓬头垢面无人晓，就里藏玄妙。"]'),
('yuanqu-4855','马丹阳度脱刘行首・滚绣球','杨景贤','元','元曲','yuanqu','','[]','我身穿着百衲袍，腰缠着碌簌绦，头直上丫髻三角。',86,'元曲/yuanqu.json','["我身穿着百衲袍，腰缠着碌簌绦，头直上丫髻三角。", "任东西散诞逍遥，抄化的酒一壶饭一瓢。", "困来时醉眠芳草，煞强如极品随朝。", "把似你受惊受怕将家私办，争如我无辱无荣将道德学，行满功高。"]'),
('yuanqu-4856','马丹阳度脱刘行首・倘秀才','杨景贤','元','元曲','yuanqu','','[]','恰离了数万丈云埋华岳，(云)稽首。',165,'元曲/yuanqu.json','["恰离了数万丈云埋华岳，(云)稽首。", "(唱)又撞着二十载还魂的故交。", "(旦云)这先生好乔也。", "我二十一岁，可怎生是你二十年前的故交？你莫不见鬼来？(正末云)可知见鬼哩，谁道是见人来？(旦云)我问你路，你便说一声儿，那里不是积福处？(正末唱)你怎生才出家来，可又早迷了正道？村性格，劣心苗，(带云)那里来，那里去，(唱)怎生不常常的记着？。"]'),
('yuanqu-4857','马丹阳度脱刘行首・滚绣球','杨景贤','元','元曲','yuanqu','','[]','你不将那大道行，(旦云)大道上有人。',292,'元曲/yuanqu.json','["你不将那大道行，(旦云)大道上有人。", "(正末笑科)(唱)可怎生往小路上抄？(旦云)小路上幽静也。", "(正末云)呆贱人，你那小路上敢热闹也。", "(唱)到如今越不知个颠倒。", "(旦云)你指与我路咱。", "(正末唱)我若指与你呵，你便上青霄。", "(旦云)我如今东西南北不知往那里去。", "(正末唱)你如今东不知南不知，你北不着西不着，(旦云)你休误了我官身。", "(正末云)你道误了你官身呵。", "(唱)早；春了你在先躯壳。", "(旦云)休误了我庆重阳。", "(正末唱)你若是有俺那重阳呵，你便得逍遥。", "(旦云)你是个不着坟墓风魔汉。", "(正末唱)你道我不着坟墓风魔汉，小鬼头我寻你个未入玄门花月妖，(旦云)缠杀人也。", "(正末唱)我便缠杀人有甚蹊跷？。"]'),
('yuanqu-4858','马丹阳度脱刘行首・滚绣球','杨景贤','元','元曲','yuanqu','','[]','你怕不杨柳腰，容貌好，久以后那里每着落，你跟着我脱凡尘倒大清高。',160,'元曲/yuanqu.json','["你怕不杨柳腰，容貌好，久以后那里每着落，你跟着我脱凡尘倒大清高。", "(旦云)你在那个庵里住？(正末唱)俺那里洞门无锁钥，白云笼罩着。", "砍青松自烧丹灶，跨苍龙同宴蟠桃。", "若得俺山中鹤氅壶中药，免了你那脚上驴蹄面上毛，怕甚么地网天牢。", "(乐探上，云)刘行首，你疾快去来。", "(正末扯科)(旦云)你放我去。", "(正末云)你跟我出家去来。", "(唱)。"]'),
('yuanqu-4859','马丹阳度脱刘行首・叨叨令','杨景贤','元','元曲','yuanqu','','[]','你低声闹，高声闹，怎锁住心猿闹？(旦云)我如今花星照，福星照，正好受用哩。',193,'元曲/yuanqu.json','["你低声闹，高声闹，怎锁住心猿闹？(旦云)我如今花星照，福星照，正好受用哩。", "(正末唱)你道是花星照，福星照，怎不怕灾星照？(旦云)你放我去。", "我去的迟了，俺奶奶骂我。", "(正末唱)则听的虔婆教，五奴教，怎不受神仙教？(旦云)去的迟了，官人每怪我也。", "(正末唱)你只怕官人叫，令史叫，怎不怕阎王叫？(带云)刘行首。", "(唱)你今日可便省的也么哥，可便省，的也么哥，你会唱升严乐，太平乐，怎不唱逍遥乐？。"]'),
('yuanqu-4860','马丹阳度脱刘行首・脱布衫','杨景贤','元','元曲','yuanqu','','[]','走将来唱叫粗豪，口不住絮絮叨叨。',45,'元曲/yuanqu.json','["走将来唱叫粗豪，口不住絮絮叨叨。", "你道他走的慢连催了两遭，哥哥也，你便做行的快也跳不出六道。"]'),
('yuanqu-4861','马丹阳度脱刘行首・小梁州','杨景贤','元','元曲','yuanqu','','[]','你道祗候处官人每等待着，休辜负值千金一刻春宵。',46,'元曲/yuanqu.json','["你道祗候处官人每等待着，休辜负值千金一刻春宵。", "你向尊前席上逞妖娆，妆圈套，大古里色是杀人刀。"]'),
('yuanqu-4862','马丹阳度脱刘行首・幺篇','杨景贤','元','元曲','yuanqu','','[]','争知苦口是良药，劝着你不采分毫，则恋那莺燕交。',45,'元曲/yuanqu.json','["争知苦口是良药，劝着你不采分毫，则恋那莺燕交。", "不想那林泉乐，争如你随着贫道，向溪上访渔樵。"]'),
('yuanqu-4863','马丹阳度脱刘行首・煞尾','杨景贤','元','元曲','yuanqu','','[]','你不肯顶簪冠，披鹤氅，闲遥遥，稳拍拍，蓬莱方丈把玄机晓；则要你穿背子，戴冠梳，急煎煎，闹炒炒，柳陌花街将罪业招。',145,'元曲/yuanqu.json','["你不肯顶簪冠，披鹤氅，闲遥遥，稳拍拍，蓬莱方丈把玄机晓；则要你穿背子，戴冠梳，急煎煎，闹炒炒，柳陌花街将罪业招。", "跟着我骑白鹤，上青霄，跨青鸾，远市朝，引仙童，采药苗，伴仙翁，纵酒瓢。", "奉吾师法令，教下人间度艳娇。", "不回头不忖度，二十年都忘了。", "我着你做神仙倒撒拗，空着我驾一片祥云下蓬岛。", "(下)。"]'),
('yuanqu-4864','马丹阳度脱刘行首・中吕/粉蝶儿','杨景贤','元','元曲','yuanqu','','[]','休笑我妆钝妆呆，看了几千场杨凋花谢，笑兴亡自古豪杰。',60,'元曲/yuanqu.json','["休笑我妆钝妆呆，看了几千场杨凋花谢，笑兴亡自古豪杰。", "遮莫你越邦兴，吴国破，争如我不生不灭？枉费了唇舌，他逃不出一生冤业。"]'),
('yuanqu-4865','马丹阳度脱刘行首・醉春风','杨景贤','元','元曲','yuanqu','','[]','这一个无记性的马丹阳，我直度你不回头的刘大姐。',75,'元曲/yuanqu.json','["这一个无记性的马丹阳，我直度你不回头的刘大姐。", "当街上吃了这一场泼举踢，着我去谁根前说，说？(带云)我度你呵，(唱)恰便似沙里淘金，石中取火，水中捞月。"]'),
('yuanqu-4866','马丹阳度脱刘行首・迎仙客','杨景贤','元','元曲','yuanqu','','[]','自哽咽，暗伤嗟，(云)贫道哭呵，不为别一件。',156,'元曲/yuanqu.json','["自哽咽，暗伤嗟，(云)贫道哭呵，不为别一件。", "(旦云)你为甚么？(正末指旦科)(唱)哭你那二十年道心在何处也？(云)你跟贫道出家去来。", "(旦云)我嫁了林员外也。", "(正末唱)你当日古墓里将祖师参，(旦云)今日嫁了林员外也。", "(正末唱)你今日向林员外将贫道撇。", "比着往日全别。", "(带云)我着你做神仙呵，(唱)怎倒惹的你愁眉结？。"]'),
('yuanqu-4867','马丹阳度脱刘行首・普天乐','杨景贤','元','元曲','yuanqu','','[]','你恰便发凡心，施乖劣。',108,'元曲/yuanqu.json','["你恰便发凡心，施乖劣。", "(带云)你成道呵，(唱)比乘风的未似，比立雪的争些。", "三百年守在古坟，二十载还了烟月。", "师父当时分明说，若见我急早来者。", "(带云)我不度你呵，你嫁了林员外也。", "(唱)早则不敲番莺燕，分开翡翠，拆散蜂蝶。"]'),
('yuanqu-4868','马丹阳度脱刘行首・快活三','杨景贤','元','元曲','yuanqu','','[]','一壁厢婴儿将衣袂扯，姹女将带揪者。',37,'元曲/yuanqu.json','["一壁厢婴儿将衣袂扯，姹女将带揪者。", "你和那墙花路柳厮和协，到和亲媳妇无疼热。"]'),
('yuanqu-4869','马丹阳度脱刘行首・鲍老儿','杨景贤','元','元曲','yuanqu','','[]','自火院深沉向未彻，怎管的闲花风月？自冤业无明火未断绝，又生出闲枝节。',70,'元曲/yuanqu.json','["自火院深沉向未彻，怎管的闲花风月？自冤业无明火未断绝，又生出闲枝节。", "(带云)林员外，你早不娶了刘行首也。", "(唱)花残月缺，弦断镜破，瓶坠簪折。"]'),
('yuanqu-4870','马丹阳度脱刘行首・耍孩儿','杨景贤','元','元曲','yuanqu','','[]','劝修行心念无明夜，呆弟子今朝省也。',73,'元曲/yuanqu.json','["劝修行心念无明夜，呆弟子今朝省也。", "奉吾师法令到蓬莱，着我便提拔出你虎窟狼穴。", "休占风月门庭闹，莫厌蓬莱途路赊。", "回首是神仙阙，你将气心财性，权且离别。"]'),
('yuanqu-4871','马丹阳度脱刘行首・三煞','杨景贤','元','元曲','yuanqu','','[]','为钱呵搬的人爷娘恩爱忘，夫妻情分绝，典房卖地将家私舍。',63,'元曲/yuanqu.json','["为钱呵搬的人爷娘恩爱忘，夫妻情分绝，典房卖地将家私舍。", "形消骨化皆因此，家破人亡不为别。", "舍性命轻抛撇，则恋着星眸皓齿，杏脸莺舌。"]'),
('yuanqu-4872','马丹阳度脱刘行首・二煞','杨景贤','元','元曲','yuanqu','','[]','将郎君脑盖敲，子弟每筋髓撅，怎当他转关儿有百计千谋设。',73,'元曲/yuanqu.json','["将郎君脑盖敲，子弟每筋髓撅，怎当他转关儿有百计千谋设。", "逼得人剜墙钻窟将金资觅，仗剑提刀将财物劫。", "都积趱下来生业，跟着我，我着你化灾变福，改正除邪。"]'),
('yuanqu-4873','马丹阳度脱刘行首・煞尾','杨景贤','元','元曲','yuanqu','','[]','我出门。',78,'元曲/yuanqu.json','["我出门。", "(做推卜儿科)(唱)你入门，(卜儿哭云)哎，儿也，兀的不痛杀我也。", "(正末唱)暂时间且略别。", "三日后向城西传取长生诀，管着你跨凤乘鸾赴仙阙。", "(同旦下)。"]'),
('yuanqu-4874','马丹阳度脱刘行首・双调/新水令','杨景贤','元','元曲','yuanqu','','[]','小庵虽窄隐幽微，包含着一合天地。',39,'元曲/yuanqu.json','["小庵虽窄隐幽微，包含着一合天地。", "草荒巢鸟宿，云淡雨龙归。", "淡饭黄齑、才得个中味。"]'),
('yuanqu-4875','马丹阳度脱刘行首・驻马听','杨景贤','元','元曲','yuanqu','','[]','水火相随，做出无穷造化机；坎离相继，烧开往日雨云期。',55,'元曲/yuanqu.json','["水火相随，做出无穷造化机；坎离相继，烧开往日雨云期。", "灵台拂去是和非，丹田养就元阳气。", "存正理，何愁不到蓬瀛内？。"]'),
('yuanqu-4876','马丹阳度脱刘行首・风入松','杨景贤','元','元曲','yuanqu','','[]','清浊混沌把心迷，静者动之基。',44,'元曲/yuanqu.json','["清浊混沌把心迷，静者动之基。", "人能清静常存息，寸心天地皆归。", "壶里乾坤只自知，空忙杀这顽皮。"]'),
('yuanqu-4877','马丹阳度脱刘行首・拨不断','杨景贤','元','元曲','yuanqu','','[]','洞云迷，野猿啼，柴门半倚闻鹤唳。',77,'元曲/yuanqu.json','["洞云迷，野猿啼，柴门半倚闻鹤唳。", "菊蕊丛丛绽竹篱，松花点点铺苔砌。", "端的个山中七日，世上千年，兴亡不管，生死无忧。", "(带云)你觑波，(唱)则俺这里别是一般天气。"]'),
('yuanqu-4878','马丹阳度脱刘行首・雁儿落','杨景贤','元','元曲','yuanqu','','[]','脱红裙着布衣，改云鬟为丫髻。',28,'元曲/yuanqu.json','["脱红裙着布衣，改云鬟为丫髻。", "发宁心养性功。", "罢妙舞轻歌艺。"]'),
('yuanqu-4879','马丹阳度脱刘行首・水仙子','杨景贤','元','元曲','yuanqu','','[]','雨云乡打抄散燕莺期，风月所掀腾翡翠帏，烟花阵搅散了鸳鸯会。',63,'元曲/yuanqu.json','["雨云乡打抄散燕莺期，风月所掀腾翡翠帏，烟花阵搅散了鸳鸯会。", "这清闲谁似你？任纷纷兔走乌飞。", "草庵内谈玄妙，蒲团上讲道德，万事休题。"]'),
('yuanqu-4880','马丹阳度脱刘行首・锦上花','杨景贤','元','元曲','yuanqu','','[]','淡饭粗衣。',40,'元曲/yuanqu.json','["淡饭粗衣。", "山中活计。", "落托清闲，倒大幽微。", "采蕨寻芝，绕山转水。", "炼药烧丹，驱神捉鬼。"]'),
('yuanqu-4881','马丹阳度脱刘行首・幺篇','杨景贤','元','元曲','yuanqu','','[]','困来那一眠，闲来那一醉。',42,'元曲/yuanqu.json','["困来那一眠，闲来那一醉。", "一任渔樵，说是谈非。", "笑杀儿曹，走南料北。", "空叹英雄，争高竞低。"]'),
('yuanqu-4882','马丹阳度脱刘行首・江儿水','杨景贤','元','元曲','yuanqu','','[]','人生快活能行几？过一岁无一岁。',38,'元曲/yuanqu.json','["人生快活能行几？过一岁无一岁。", "将军使机谋，宰相施忠义。", "都在俺这老先生淡笑里。"]'),
('yuanqu-4883','马丹阳度脱刘行首・川拨棹','杨景贤','元','元曲','yuanqu','','[]','恁两个用心机，出门来逢着太岁。',53,'元曲/yuanqu.json','["恁两个用心机，出门来逢着太岁。", "我则见剥下衣袂，后拥前推，刀剑依随。", "谁教你出门来贼心便起？到今日说个甚的？。"]'),
('yuanqu-4884','马丹阳度脱刘行首・七弟兄','杨景贤','元','元曲','yuanqu','','[]','你怎不察知就里？这总是你家门贼。',49,'元曲/yuanqu.json','["你怎不察知就里？这总是你家门贼。", "怎将蓼儿洼强猜做蓝桥驿？梁山泊权当做武陵溪？太行山错认做桃源内？。"]'),
('yuanqu-4885','马丹阳度脱刘行首・梅花酒','杨景贤','元','元曲','yuanqu','','[]','呀！你今日悔后迟，可笑愚痴，不辨个高低，畅叫扬疾。',71,'元曲/yuanqu.json','["呀！你今日悔后迟，可笑愚痴，不辨个高低，畅叫扬疾。", "人无害虎心，虎无伤人意。", "你可便甚所为将亲女做娼妓？逼的他觅衣食，谩天网四方围，陷人坑当面砌。"]'),
('yuanqu-4886','马丹阳度脱刘行首・收江南','杨景贤','元','元曲','yuanqu','','[]','呀！当日个敲人骨髓剥人皮，今日个餐刀吃剑有谁知？争如俺粗衣淡饭在山扉。',53,'元曲/yuanqu.json','["呀！当日个敲人骨髓剥人皮，今日个餐刀吃剑有谁知？争如俺粗衣淡饭在山扉。", "又不图着甚的，毕竟是那一个得便宜？。"]'),
('yuanqu-4887','仙吕・一半儿题情','王和卿','元','元曲','yuanqu','','[]','鸦翎般水鬓似刀裁，小颗颗芙蓉花额儿窄，待不梳妆怕娘左猜。',163,'元曲/yuanqu.json','["鸦翎般水鬓似刀裁，小颗颗芙蓉花额儿窄，待不梳妆怕娘左猜。", "不免插金钗，一半儿松一半儿歪。", "书来和泪怕开缄，又不归来空再三，这样病儿谁惯耽？越恁瘦岩岩，一半儿增添一半儿减。", "将来书信手拈着，灯下姿姿观觑了，两三行字真带草。", "提起来越心焦，一半儿丝ㄎ一半儿烧！别来宽褪缕金衣，粉悴烟憔减玉肌，泪点儿只除衫袖知。", "盼佳期，一半儿才干一半儿湿。"]'),
('yuanqu-4888','商调・百字知秋令','王和卿','元','元曲','yuanqu','','[]','绛蜡残半明不灭寒灰看时看节落，沉烟烬细里末里微分间即里渐里消。',107,'元曲/yuanqu.json','["绛蜡残半明不灭寒灰看时看节落，沉烟烬细里末里微分间即里渐里消。", "碧纱窗外风弄雨昔留昔零打芭蕉，恼碎芳心近砌下啾啾唧唧寒蛩闹，惊回幽梦丁丁当当檐间铁马敲。", "半欹单枕乞留乞良捱彻今宵，只被这一弄儿凄凉断送的愁人登时间病了。"]'),
('yuanqu-4889','越调・天净沙咏秃','王和卿','元','元曲','yuanqu','','[]','笠儿深掩过双肩，头巾牢抹到眉边，款款的把笠檐儿试掀。',41,'元曲/yuanqu.json','["笠儿深掩过双肩，头巾牢抹到眉边，款款的把笠檐儿试掀。", "连荒道一句：君子人不见头面！。"]'),
('yuanqu-4890','大石调・蓦山溪闺情','王和卿','元','元曲','yuanqu','','[]','冬天易晚，又早黄昏后。',37,'元曲/yuanqu.json','["冬天易晚，又早黄昏后。", "修竹小阑干，空倚遍寒生翠袖。", "萧郎宝马，何处也恣狂游。"]'),
('yuanqu-4891','幺篇・人已静，夜将阑，不承望今番又。大抵为人图甚么，况彼各青春年','王和卿','元','元曲','yuanqu','','[]','似恁的厮禁持，寻思来白了人头。',15,'元曲/yuanqu.json','["似恁的厮禁持，寻思来白了人头。"]'),
('yuanqu-4892','女冠子・过一期，胜九秋，强拈针线，把一扇鞋儿绣。蓦听的马嘶人语，','王和卿','元','元曲','yuanqu','','[]','不甫能盼的他来到，他却又早醺醺的带酒。',19,'元曲/yuanqu.json','["不甫能盼的他来到，他却又早醺醺的带酒。"]'),
('yuanqu-4893','好观音・枉了教人深闺候，疏狂性惯纵的来自由。不承望今番做的漏斗，','王和卿','元','元曲','yuanqu','','[]','衣纽儿尚然不曾扣。',23,'元曲/yuanqu.json','["衣纽儿尚然不曾扣。", "等的他酒醒时，将他来都明透。"]'),
('yuanqu-4894','雁过南楼煞・问着时节只办的摆手，骂着时节永不开口。我将你耳朵儿揪，','王和卿','元','元曲','yuanqu','','[]','你可也共谁人两个欢偶？我将你锦片也似前程，花朵儿身躯，遥望着梅梢上月牙儿咒！。',39,'元曲/yuanqu.json','["你可也共谁人两个欢偶？我将你锦片也似前程，花朵儿身躯，遥望着梅梢上月牙儿咒！。"]'),
('yuanqu-4895','南吕・一枝花为打球子作','王和卿','元','元曲','yuanqu','','[]','夭桃绽锦囊，嫩柳垂金线。',57,'元曲/yuanqu.json','["夭桃绽锦囊，嫩柳垂金线。", "梨花喷白雪，芳草绿铺茵。", "春日郊园，出凤城闲游玩。", "选高原胜地面，就华屋芳妍，将步リ家风习演。"]'),
('yuanqu-4896','三煞・四周浓绿围屏甸，一簇深红罩短垣，习行打远乐霞川。据那义让廉','王和卿','元','元曲','yuanqu','','[]','和，有仁德高低无怨，要知左右识体面。',32,'元曲/yuanqu.json','["和，有仁德高低无怨，要知左右识体面。", "担捧笼叫须奴趁圈，尽日连年。"]'),
('yuanqu-4897','二・轻轮月杖惊花片，慢辊星丸荡柳线，一行步从紧相连。诸传戏都难，','王和卿','元','元曲','yuanqu','','[]','唯摇丸元无酌献，自古与流传。',31,'元曲/yuanqu.json','["唯摇丸元无酌献，自古与流传。", "想常胜寻思意非浅，但犯着死处休言。"]'),
('yuanqu-4898','一・旧作杖结束得都虬健，绒约手扎拴的彩色鲜。锦衣抛胜各争先，得胜','王和卿','元','元曲','yuanqu','','[]','的欣然，画方基荷茵庭院。',40,'元曲/yuanqu.json','["的欣然，画方基荷茵庭院。", "安员王将袖梢先卷，觑上下，观高低，望远近，料得周正无偏。"]'),
('yuanqu-4899','尾・畅道引臂员扇，棒过处飞星如箭，茂林中法头不善。指觑窝落在花柳','王和卿','元','元曲','yuanqu','','[]','场边，不吊上也无一步远。',12,'元曲/yuanqu.json','["场边，不吊上也无一步远。"]'),
('yuanqu-4900','商调・梧叶儿春夜','吴西逸','元','元曲','yuanqu','','[]','评花担，折柳杯，诗酒醉淋漓。',166,'元曲/yuanqu.json','["评花担，折柳杯，诗酒醉淋漓。", "觅句鸾笺重，笼灯翠袖随。", "别院漏声迟，扶醉人销金帐里。", "春情香随梦，肌褪雪，锦字记离别。", "春去情难再，更长愁易结。", "花外月儿斜，淹粉泪微微睡些。", "京城访友桃凝露，杏倚云，花院望星辰。", "尘土东华梦，簪缨上苑春。", "趿履谒侯门，吟眼乱难寻故人。", "摩空赋，醉月觞，无地不疏狂。", "貂帽簪花重，鸳帏倚玉香。", "清楚绿鬟妆，扶我入温柔醉乡。"]'),
('yuanqu-4901','越调・天净沙闲题','吴西逸','元','元曲','yuanqu','','[]','长江万里归帆，西风几度阳关，依旧红尘满眼。',132,'元曲/yuanqu.json','["长江万里归帆，西风几度阳关，依旧红尘满眼。", "夕阳新雁，此情时拍阑干。", "楚云飞满长空，湘江不断流东，何事离多恨冗？夕阳低送，小楼数点残鸿。", "数声短笛沧州，半江远水孤舟，愁更浓如病酒。", "夕阳时候，断肠人倚西楼。", "江亭远树残霞，淡烟芳草平沙，绿柳阴中系马。", "夕阳西下，水村山郭人家。"]'),
('yuanqu-4902','越调・柳营曲赏春','吴西逸','元','元曲','yuanqu','','[]','花艳冶，柳欹斜，粉墙低画楼人困也。',215,'元曲/yuanqu.json','["花艳冶，柳欹斜，粉墙低画楼人困也。", "庭院星列，罗绮云叠，簇簇闹蜂蝶。", "紫霞杯我辈豪侠，绿云鬟仕女奇绝。", "乌丝栏看醉草，红牙板唱声揭。", "别，同载七香车。", "避暑偶成共翠娥，酌金波，湖上晚风摇芰荷。", "丝管情多，帘幕凉过，暑气尽消磨。", "扇停风几缕柔歌，袜凌波一掬香罗。", "醉魂偏浩荡，诗兴费吟哦。", "睃，老子正婆娑。", "秋闺笼太纤，拜银蟾，恰团圆几时云又掩。", "尘淡妆奁，风透朱帘，无语望雕檐。", "博山炉香冷慵添。", "阳春曲唱和难タ。", "新凉开扇影，清恨蹙眉尖。", "嫌，何处可消淹？。"]'),
('yuanqu-4903','双调・清江引秋居','吴西逸','元','元曲','yuanqu','','[]','白雁乱飞秋似雪，清露生凉夜。',71,'元曲/yuanqu.json','["白雁乱飞秋似雪，清露生凉夜。", "扫却石边云，醉踏松根月，星斗满天人睡也。", "春事桃花满溪春水深，鸾镜人孤甚。", "云屏掩梦寒，腕玉和愁枕，故人不来何处饮？。"]'),
('yuanqu-4904','双调・寿阳曲四时','吴西逸','元','元曲','yuanqu','','[]','传心素，托简书，问春归欲归何处？送春词不题风共雨，止埋怨落花飞絮。',241,'元曲/yuanqu.json','["传心素，托简书，问春归欲归何处？送春词不题风共雨，止埋怨落花飞絮。", "贪新酿，趁晚凉，笑相呼凭肩歌唱。", "最多情女郎心外想，打鸳鸯采莲湖上。", "萦心事，惹恨词，更那堪动人秋思。", "画楼边几声新雁儿，不传书摆成个愁字。", "年华尽，腊味醇，睡不温晓寒成阵。", "折梅花不传心上人，村煞我陇头春信。", "咏所见人如玉，鬓似云，动春心半含娇俊。", "近装奁懒将花貌匀，旋窝儿粉香成晕。", "酒散旗亭散，歌韵歇，暖风轻柳摇台榭。", "杏花墙夕阳春去也，马蹄香宝鞍敲月。", "效香奁体惚蝉鬓，怯镜鸾，雁声寒不禁肠断。", "碧纱窗夜长鸳梦短，怕黄昏一灯相伴。"]'),
('yuanqu-4905','双调・殿前欢','吴西逸','元','元曲','yuanqu','','[]','懒云窝，懒云堆里即无何。',324,'元曲/yuanqu.json','["懒云窝，懒云堆里即无何。", "半间茅屋容高卧，往事南柯。", "红尘自网罗，白日闲酬和，青眼偏空阔。", "风波远我，我远风波。", "懒云仙，蓬莱深处恣高眠。", "笔床茶灶添香篆，尽意留连。", "闲吟白雪篇，静阅丹砂传，不羡青云选。", "林泉爱我，我爱林泉。", "懒云巢，碧天无际雁行高。", "玉箫鹤背青松道，乐笑游遨，溪翁解冷淡嘲，山鬼放揶揄笑，村妇唱糊涂调。", "风涛险我，我险风涛。", "懒云关，一泓流水绕弯环。", "半窗斜日留晴汉，鸟倦知还。", "高眠仿谢安，归计寻张翰，作赋思王粲。", "溪山恋我，我恋溪山。", "懒云翁，一襟风月笑谈中。", "生平傲杀繁华梦，已悟真空。", "茶香水玉钟，酒竭玻璃翁，云绕蓬莱洞。", "冥鸿笑我，我笑冥鸿。", "懒云凹，按行松菊讯桑麻。", "声名不在渊明下，冷淡生涯。", "味偏长凤髓茶，梦已随胡蝶化，身不入麒麟画。", "莺花厌我，我厌莺花。"]'),
('yuanqu-4906','双调・雁儿落过得胜令春游','吴西逸','元','元曲','yuanqu','','[]','人衔白玉杯，马纵黄金辔。',275,'元曲/yuanqu.json','["人衔白玉杯，马纵黄金辔。", "帘栊燕影闲，院落莺声碎。", "酒瓮浸玻璃，睡帐揭金泥。", "醉写评花句，梦随芳草池。", "别离，天远书难寄。", "芳菲，红残春又归。", "题情春闲芍药瓶，尘淡菱花镜。", "香消翡翠炉，扇冷犀红柄。", "终日倚山屏，无意理银筝。", "独坐愁偏甚，孤眠睡不成。", "长更，月冷鸳衾剩。", "愁凝，最无情窗下灯。", "叹世高阳酒更酡，栗里诗难和。", "风清弦管声，月淡珠玑唾。", "青镜苦消磨，白发尽婆娑。", "门外桑榆景，庭前荆棘科。", "蹉跎，白日空闲过。", "风波，浮生无奈何。", "春花闻杜鹃，秋月看归燕。", "人情薄似云，风景疾如箭，留下买花钱，趱入种桑园。", "茅苫三间厦，秧肥数顷田。", "床边，放一册冷淡渊明传。", "窗前，抄几联清新杜甫篇。"]'),
('yuanqu-4907','水调歌头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','秋灯明翠巾莫，夜案览芸编。',121,'元曲/yuanqu.json','["秋灯明翠巾莫，夜案览芸编。", "今来古往，其间故事几多般。", "少甚佳人才子，也有神仙幽怪，琐碎不堪观。", "正是：不关风化体，纵好也徒然。", "论传奇，乐人易，动人难。", "知音君子，这般另做眼儿看。", "休论插科打诨，也不寻宫数调，只看子孝与妻贤。", "骅骝方独步，万马敢争先？。"]'),
('yuanqu-4908','沁园春','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','赵女姿容，蔡邕文业，两月夫妻。',137,'元曲/yuanqu.json','["赵女姿容，蔡邕文业，两月夫妻。", "奈朝廷黄榜，遍招贤士，高堂严命，强赴春闱。", "一举螯头，再婚牛氏，利绾名牵竟不归。", "饥荒岁，双亲俱丧，此际实堪悲。", "堪悲赵女支持，剪下香云送舅姑。", "罗裙包土，筑成坟墓；琵琶写怨，竟往京畿。", "孝矣伯喈，贤哉牛氏，书馆相逢最惨凄。", "重庐墓，一夫二妇，旌表耀门闾。"]'),
('yuanqu-4909','瑞鹤仙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','十载亲灯火，论高才绝学，休夸班马。',61,'元曲/yuanqu.json','["十载亲灯火，论高才绝学，休夸班马。", "风云太平日，正骅骝欲骋，鱼龙将化。", "沈吟一和，怎离双亲膝下？尽心甘旨，功名富贵，付之大也。"]'),
('yuanqu-4911','宝鼎儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','小门深巷里，春到芳草，人闲清昼。',16,'元曲/yuanqu.json','["小门深巷里，春到芳草，人闲清昼。"]'),
('yuanqu-4912','锦堂月','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','帘幕风柔，庭帏昼永，朝来峭寒轻透。',69,'元曲/yuanqu.json','["帘幕风柔，庭帏昼永，朝来峭寒轻透。", "人在高堂，一喜又还一忧。", "惟愿取百岁椿萱，长似他三春花柳。", "(合)酌春酒，看取花下高歌，共祝眉寿。", "(旦唱)。"]'),
('yuanqu-4913','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','还愁，白发蒙头，红英满眼，心惊去年时候。',57,'元曲/yuanqu.json','["还愁，白发蒙头，红英满眼，心惊去年时候。", "只恐时光，催人去也难留。", "惟愿取黄卷青灯，及早换金章紫绶。", "(合前)(净唱)。"]'),
('yuanqu-4914','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','还忧，松竹门幽，桑榆暮景，明年知他健否安否？叹兰玉萧条，一朵桂花难茂。',60,'元曲/yuanqu.json','["还忧，松竹门幽，桑榆暮景，明年知他健否安否？叹兰玉萧条，一朵桂花难茂。", "惟愿取连理芳年，得早遂孙枝荣秀。", "(合前)(生唱)。"]'),
('yuanqu-4915','醉翁子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','回首，看瞬息乌飞兔走。',65,'元曲/yuanqu.json','["回首，看瞬息乌飞兔走。", "(旦唱)喜爹妈双全，谢天相佑。", "(生唱)不谬，更清淡安闲，乐事如今谁更有？(合)相庆处，但酌酒高歌，共祝眉寿。"]'),
('yuanqu-4916','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','卑陋，论做人要光前耀后。',54,'元曲/yuanqu.json','["卑陋，论做人要光前耀后。", "劝我儿青云，万里驰骤。", "(生唱)听剖，真乐在田园，何必当今公与侯？(合前)(生旦唱)。"]'),
('yuanqu-4917','侥侥令','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','春花明彩袖，春酒满金瓯。',37,'元曲/yuanqu.json','["春花明彩袖，春酒满金瓯。", "但愿岁岁年年人长在，父母共夫妻相劝酬。", "(外净唱)。"]'),
('yuanqu-4918','十二时','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','山青水绿还依旧，叹人生青春难又，惟有快活是良谋。',24,'元曲/yuanqu.json','["山青水绿还依旧，叹人生青春难又，惟有快活是良谋。"]'),
('yuanqu-4919','雁儿舞','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','深院重重，怎不怨苦？要寻个男儿，并无门路。',42,'元曲/yuanqu.json','["深院重重，怎不怨苦？要寻个男儿，并无门路。", "甚年能勾，和一丈夫，一处里双双雁儿舞？，。"]'),
('yuanqu-4920','西江月','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','白打从来逞势，官场自小驰名。',69,'元曲/yuanqu.json','["白打从来逞势，官场自小驰名。", "如今年老脚□肷疼，圆社无心驰骋。", "空使绣襦汗湿，谩罗袜生尘。", "兀的是少年子弟俏门庭，不似宝妆行径。", "(丑)斗百草耍。"]'),
('yuanqu-4921','西江月','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','香径里扳残草色，雕阑畔折损花容。',71,'元曲/yuanqu.json','["香径里扳残草色，雕阑畔折损花容。", "又无巧艺动王公，枉费了工夫何用？惊起娇莺语燕，打开浪蝶狂烽。", "若还寻得并头红，早把你芳心引动。", "(净丑)打秋千耍。"]'),
('yuanqu-4922','西江月','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','玉体轻流香汗，绣裙荡漾明霞。',206,'元曲/yuanqu.json','["玉体轻流香汗，绣裙荡漾明霞。", "纤纤玉手把彩绳拿，真个堪描堪画。", "本是北方戎戏，移来上苑豪家。", "女娘撩乱隔墙花，好似半仙戏耍。", "(净丑)恁地便打秋千。", "只是那里有秋千架？(末)我这花园里那讨秋千架？一来相公不忻，二来娘子又不好，纵有也拆了。", "(丑)院公，没奈何，咱每三个在这里，厮论做个秋千架，一人打，两人抬。", "(做架介)(末)谁先打？(净丑)我两人抬，院公，你先打。", "(介)(贴旦在戏房内叫)老姥姥，将我的《列女传》那里去了？。"]'),
('yuanqu-4923','祝英台近','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','绿成阴，红似雨，春事已无有。',14,'元曲/yuanqu.json','["绿成阴，红似雨，春事已无有。"]'),
('yuanqu-4924','玉楼春','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','清明时节单衣试，争奈昼长人静重门闭？(贴白)我芳心不解乱萦牵，羞见游丝与飞絮。',102,'元曲/yuanqu.json','["清明时节单衣试，争奈昼长人静重门闭？(贴白)我芳心不解乱萦牵，羞见游丝与飞絮。", "(丑白)绣窗欲待拈针指，忽听莺燕双双语。", "(贴白)无情何处管多情？任取春光自来去。", "(丑白)娘子。", "有甚法度教惜春休闷了？(贴唱)。"]'),
('yuanqu-4925','祝英台序','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','把几分春三月景，分付与东流。',14,'元曲/yuanqu.json','["把几分春三月景，分付与东流。"]'),
('yuanqu-4926','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','春昼，只见燕双飞，蝶引队，莺浯似求友。',139,'元曲/yuanqu.json','["春昼，只见燕双飞，蝶引队，莺浯似求友。", "(贴白)你是人物，说那虫蚁做甚么？(丑唱)那更柳外画轮，花底雕鞍，都是少年闲游。", "(贴白)这贱人，你是妇人家，说那少年事做甚么？(丑唱)难守，孤房清冷无人，也寻一个佳偶。", "(贴白)呀，贱人！你到思量男儿。", "(丑唱)这般说，终身休配鸾俦。", "(贴唱)。"]'),
('yuanqu-4927','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','知否？我为何不卷珠帘，独坐爱清幽？(丑白)清幽，清幽，争奈人愁！(贴唱)千斛闷怀，百种春愁，难上我的眉头。',86,'元曲/yuanqu.json','["知否？我为何不卷珠帘，独坐爱清幽？(丑白)清幽，清幽，争奈人愁！(贴唱)千斛闷怀，百种春愁，难上我的眉头。", "(丑白)只怕你不长恁地。", "(贴唱)休忧，任他春色年年，我的芳心依旧。"]'),
('yuanqu-4928','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','今后，方信你彻底澄清，我好没来由。',117,'元曲/yuanqu.json','["今后，方信你彻底澄清，我好没来由。", "(贴白)你怎的不收拾了心下？(丑唱)想象暮云，分付东风，情到不堪回首。", "(贴白)你怎不学我？(丑唱)听剖：你是蕊宫琼苑神仙，不比尘凡相诱。", "(贴白)恁地，自随我习些女工便了。", "(丑唱)谨随侍，窗下拈针挑绣。"]'),
('yuanqu-4929','一剪梅','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','浪暖桃香欲化鱼，期逼春闱，诏赴春闱。',36,'元曲/yuanqu.json','["浪暖桃香欲化鱼，期逼春闱，诏赴春闱。", "郡中空有辟贤书，心恋亲闱，难舍亲闱。"]'),
('yuanqu-4930','宜春令','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','虽然读，万卷书，论功名非吾意儿。',63,'元曲/yuanqu.json','["虽然读，万卷书，论功名非吾意儿。", "只愁亲老，梦魂不到春闱里。", "便教我做到九棘三槐，怎撇得萱花椿树？我这，衷肠一点孝心，对谁人语？。"]'),
('yuanqu-4931','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','相邻并，相依倚，往常间有事来相报知。',114,'元曲/yuanqu.json','["相邻并，相依倚，往常间有事来相报知。", "(生白)来的却是张大公。", "公公拜揖。", "(末)解元拜揖。", "解元：(唱)试期逼矣，早办行装前途去。", "(生白)双亲老了，不敢去。", "(末笑介唱)子虽念亲老孤唯，亲须望孩儿荣贵。", "解元，趁此，青春不去，更待何日？。"]'),
('yuanqu-4932','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','时光短，雪鬓垂，守清贫不图着甚的。',74,'元曲/yuanqu.json','["时光短，雪鬓垂，守清贫不图着甚的。", "有儿聪慧，但得他为官吾足矣。", "(外末相见介)(外唱)孩儿，天子诏招取贤良，秀才每都求着科试。", "快赴春闱，急急整着行李。"]'),
('yuanqu-4933','吴小四','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','眼又昏，耳又聋，家私空又空。',38,'元曲/yuanqu.json','["眼又昏，耳又聋，家私空又空。", "只有孩儿肚内聪，他若做得官时运通，我两人不怕穷。"]'),
('yuanqu-4934','绣带儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','亲年老光阴有儿？行孝正是今日。',83,'元曲/yuanqu.json','["亲年老光阴有儿？行孝正是今日。", "终不然为着一领蓝袍，却落后了戏彩斑衣。", "思之，此行荣贵虽可拟，怕亲老等不得荣贵。", "(外唱)春闱里纷纷大儒，难道是没爹娘的孩儿方去？(末唱)。"]'),
('yuanqu-4935','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','休迷！男儿汉凌云志气，何必苦恁淹滞？可不干费了十载青灯，枉捱半世黄艹齑？须知，。',40,'元曲/yuanqu.json','["休迷！男儿汉凌云志气，何必苦恁淹滞？可不干费了十载青灯，枉捱半世黄艹齑？须知，。"]'),
('yuanqu-4936','太师引','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他意儿难提起，这其间就里我自知。',16,'元曲/yuanqu.json','["他意儿难提起，这其间就里我自知。"]'),
('yuanqu-4937','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他意里只要供甘旨，又何曾贪欢恋妻。',91,'元曲/yuanqu.json','["他意里只要供甘旨，又何曾贪欢恋妻。", "自古道曾参纯孝，何曾去应举及第？功名富贵天付与，天若与不求须来至。", "(生唱)娘行是望爹行听取。", "(生白)孩儿恋媳妇不肯去呵，(唱)天须鉴孩儿不孝的情罪。"]'),
('yuanqu-4938','三学士','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','谢得公公意甚美，凡事仗托维持。',53,'元曲/yuanqu.json','["谢得公公意甚美，凡事仗托维持。", "假饶一举登科日，难道是双亲未老时。", "只恐锦衣归故里，双亲的怕不见儿。", "(外唱)。"]'),
('yuanqu-4939','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','萱室蝽庭衰老矣，指望你换了门闾。',72,'元曲/yuanqu.json','["萱室蝽庭衰老矣，指望你换了门闾。", "你休道无人供奉。", "你做得官呵，三牲五鼎供朝夕，须胜似啜菽并饮水。", "你若锦衣归故里，我便死呵，一灵儿终是喜。", "(末唱)。"]'),
('yuanqu-4940','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','托在邻家相倚依，专当效峰区区。',63,'元曲/yuanqu.json','["托在邻家相倚依，专当效峰区区。", "秀才，你为甚在十年窗下无人问？只图个一举成名天下知。", "你若不锦衣归故里，谁知你读万卷书？(净唱)。"]'),
('yuanqu-4941','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','一旦分离掌上珠，我这老景凭谁？忍将父母饥寒死，博换得孩儿名利归。',49,'元曲/yuanqu.json','["一旦分离掌上珠，我这老景凭谁？忍将父母饥寒死，博换得孩儿名利归。", "你纵然衣锦归故里，补不得你名行亏。"]'),
('yuanqu-4942','谒金门','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','春梦断，临镜绿云撩乱。',58,'元曲/yuanqu.json','["春梦断，临镜绿云撩乱。", "闻道才郎游上苑，又添离别叹。", "(生接唱)苦被爹行逼遣，脉咏此情何限。", "骨肉一朝成拆散，可怜难舍拚。"]'),
('yuanqu-4943','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我哭哀哀推辞了万千，他闹炒炒抵死来相劝。',41,'元曲/yuanqu.json','["我哭哀哀推辞了万千，他闹炒炒抵死来相劝。", "将我深罪，不由人分辨。", "(旦白)罪你甚么？。"]'),
('yuanqu-4944','沉醉东风','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你爹行见得你好偏，只一子不留在身畔。',82,'元曲/yuanqu.json','["你爹行见得你好偏，只一子不留在身畔。", "(介)我和你去说咱。", "休休，他只道我不贤，要将你迷恋。", "苦！这其间怎不悲怨？(合)为爹泪涟，为娘泪涟，何曾为着夫妻上意牵？(生唱)。"]'),
('yuanqu-4945','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','做孩儿节孝怎全？做爹行不从人几谏。',56,'元曲/yuanqu.json','["做孩儿节孝怎全？做爹行不从人几谏。", "呀！俺为人子，不当恁地说。", "也不是要埋冤，影只形单，我出去有谁来看管。", "(合前)。"]'),
('yuanqu-4946','腊梅花','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我孩儿出去在今日中，爹爹妈妈来相送。',38,'元曲/yuanqu.json','["我孩儿出去在今日中，爹爹妈妈来相送。", "但愿得鱼化龙，青云得路，桂枝高折步蟾宫。"]'),
('yuanqu-4947','园林好','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','儿今去，爹妈休得要意悬。',50,'元曲/yuanqu.json','["儿今去，爹妈休得要意悬。", "儿今去今年便还，但愿得双亲康健。", "(合)须有日拜堂前，须有日拜堂前。", "(外唱)。"]'),
('yuanqu-4948','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我孩儿不须挂牵，爹只望孩儿贵显。',41,'元曲/yuanqu.json','["我孩儿不须挂牵，爹只望孩儿贵显。", "若得你名登高选，(合)须早把信音传，须早把信音传。"]'),
('yuanqu-4949','江儿水','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','膝下娇儿去，堂前老母单，临行只得密缝针线。',63,'元曲/yuanqu.json','["膝下娇儿去，堂前老母单，临行只得密缝针线。", "眼巴巴望着关山远，冷清清倚定门儿遍，教我如何消遣？(合)要解愁烦，须是寄个音书回转。"]'),
('yuanqu-4950','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','妾的衷肠事，万万千，说来又怕添萦绊。',52,'元曲/yuanqu.json','["妾的衷肠事，万万千，说来又怕添萦绊。", "六十日夫妻恩情断，八十岁父母如何展？教我如何不怨？(合前)(末唱)。"]'),
('yuanqu-4951','五供养','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','贫穷老汉，托在邻家，事体相关。',74,'元曲/yuanqu.json','["贫穷老汉，托在邻家，事体相关。", "此行须勉强，不必恁留连。", "你爹娘早晚，早晚里我专来陪伴。", "丈夫非无泪，不洒别离间。", "(合)骨肉分离，寸肠割断。", "(生跪介唱)。"]'),
('yuanqu-4952','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','公公可怜，俺的爹娘，望你周全。',70,'元曲/yuanqu.json','["公公可怜，俺的爹娘，望你周全。", "此身还贵显，自当效衔环。", "(旦唱)有孩儿也枉然，你爹娘到教别人来看管。", "此际情何限，偷把泪珠弹。", "(合前)(外唱)。"]'),
('yuanqu-4953','玉交枝','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','别离休叹，我心下非不痛酸。',74,'元曲/yuanqu.json','["别离休叹，我心下非不痛酸。", "非爹苦要轻拆散，也只是要图你荣显。", "(净唱)蟾宫桂枝须早扳，北堂萱草时光短。", "(合)又不知何日再圆？又不知何日再圆？(生唱)。"]'),
('yuanqu-4954','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','双亲衰倦，你扶持着他老年。',63,'元曲/yuanqu.json','["双亲衰倦，你扶持着他老年。", "饥时劝他加餐饭，寒时频与衣穿。", "(旦唱)做媳妇事舅姑不待你言，你做孩儿离父母何日返？(合前)(外唱)。"]'),
('yuanqu-4955','川拨棹','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','归休晚，莫教人凝望眼。',53,'元曲/yuanqu.json','["归休晚，莫教人凝望眼。", "(生唱)但有日回到家园，怕回来双亲老年。", "(合)怎教人心放宽？不由人不泪弹。", "(旦唱)。"]'),
('yuanqu-4956','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我的埋冤怎尽言？我的一身难上难。',46,'元曲/yuanqu.json','["我的埋冤怎尽言？我的一身难上难。", "(生唱)娘子，你宁可将我来埋冤，莫将我爹娘来冷看。", "(合前)。"]'),
('yuanqu-4957','尾犯','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','懊恨别离轻，悲岂断弦，愁非分镜。',65,'元曲/yuanqu.json','["懊恨别离轻，悲岂断弦，愁非分镜。", "只虑高堂，怕风烛不定。", "(生唱)肠已断欲离未忍，泪难收无言自零。", "(合)空留恋，天涯海角，只在须臾顷。"]'),
('yuanqu-4958','尾犯序','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','无限别离情，两月夫妻，一旦孤另。',65,'元曲/yuanqu.json','["无限别离情，两月夫妻，一旦孤另。", "此去经年，望迢迢玉京。", "思省，奴不虑山遥路远，奴不虑衾寒枕冷；奴只虑，公婆没主一旦冷清清。", "(生唱)。"]'),
('yuanqu-4959','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','儒衣才换青，快着归鞭，早办回程。',65,'元曲/yuanqu.json','["儒衣才换青，快着归鞭，早办回程。", "十里红楼，休重娶娉婷。", "叮咛，不念我芙蓉帐冷，也思亲桑榆暮景。", "亲祝付，知他记否空自语惺惺。", "(生唱)。"]'),
('yuanqu-4960','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','宽心须待等，我肯恋花柳，甘为萍梗？只怕万里关山，那更音信难凭。',68,'元曲/yuanqu.json','["宽心须待等，我肯恋花柳，甘为萍梗？只怕万里关山，那更音信难凭。", "须听，我没奈何分情破爱，谁下得亏心短行？(合)从今去，相思两处一样泪盈盈。"]'),
('yuanqu-4961','鹧鸪天','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','万里关山万里愁。',41,'元曲/yuanqu.json','["万里关山万里愁。", "(旦唱)一般心事一般忧。", "(生唱)亲闱暮景应难保，客馆风光怎久留？。"]'),
('yuanqu-4962','字字双','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我做媒婆甚妖娆，谈笑。',46,'元曲/yuanqu.json','["我做媒婆甚妖娆，谈笑。", "说开说合口如刀，波俏。", "合婚问卜若都好，有钞。", "只怕假做庚帖被人告，吃拷。"]'),
('yuanqu-4963','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我做媒婆甚艰辛，寻趁。',47,'元曲/yuanqu.json','["我做媒婆甚艰辛，寻趁。", "有个新郎要求亲，最紧。", "我每只得便忙奔，讨信。", "(介)路上更有早行人，心闷。"]'),
('yuanqu-4964','花心动','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','幽阁深沉，问佳人：为何懒添眉黛？针线日长，图史春闲，谁解屡傍妆台？绛罗深护奇葩小，还不许蜂识莺猜。',66,'元曲/yuanqu.json','["幽阁深沉，问佳人：为何懒添眉黛？针线日长，图史春闲，谁解屡傍妆台？绛罗深护奇葩小，还不许蜂识莺猜。", "(净丑唱)笑琐窗，多少玉人无赖！。"]'),
('yuanqu-4965','惜奴娇','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','孩儿来，杏脸桃腮，又当有松筠节操，蕙兰襟怀。',81,'元曲/yuanqu.json','["孩儿来，杏脸桃腮，又当有松筠节操，蕙兰襟怀。", "闺中言语，不出阃阈之外。", "老姥姥，不教孩儿伊之罪。", "惜春，这风情今休再。", "(合)记再来，但把不出闺门的，语言相戒。", "(贴唱)。"]'),
('yuanqu-4966','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','堪哀，萱室先摧。',63,'元曲/yuanqu.json','["堪哀，萱室先摧。", "叹妇仪姆训，未曾谙解。", "蒙爹严命，从今怎敢不改！老姥姥，早晚望伊家将奴诲。", "惜春，改前非休违背。", "(合前)(净唱)。"]'),
('yuanqu-4967','黑麻序','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','听浼：父母心，婚姻事要早谐。',64,'元曲/yuanqu.json','["听浼：父母心，婚姻事要早谐。", "劝相公，早毕儿女之债。", "(外唱)休呆，如何女子前，将此口乱开。", "(合)记今来，但把不出闺门的，语言相戒。"]'),
('yuanqu-4968','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','轻浼，我受寂寞担烦恼，教我怎捱？细思之，怎不教人珠泪盈腮？(贴唱)宽待，温衣并美食，何须苦挂怀？<合前)。',53,'元曲/yuanqu.json','["轻浼，我受寂寞担烦恼，教我怎捱？细思之，怎不教人珠泪盈腮？(贴唱)宽待，温衣并美食，何须苦挂怀？<合前)。"]'),
('yuanqu-4969','满庭芳','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','飞絮沾衣，残花随马，轻寒轻暖芳辰。',58,'元曲/yuanqu.json','["飞絮沾衣，残花随马，轻寒轻暖芳辰。", "江山风物，偏动别离人。", "回首高堂渐远，叹当时恩爱轻分。", "伤情处，数声杜宇，客泪满衣襟。"]'),
('yuanqu-4970','浣溪沙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','千里莺啼绿映红，(丑白)水村山郭酒旗风，(净白)行人如在画图中。',63,'元曲/yuanqu.json','["千里莺啼绿映红，(丑白)水村山郭酒旗风，(净白)行人如在画图中。", "(末白)不暖不寒天气好，或来或往旅人逢，(合)此时谁不叹西东。"]'),
('yuanqu-4971','甘州歌','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','衷肠闷损，叹路途千里，日日思亲。',85,'元曲/yuanqu.json','["衷肠闷损，叹路途千里，日日思亲。", "青梅如豆，难寄陇头音信。", "高堂已添双鬓雪，俺客路空瞻一片云。", "(合)途中味，客里身，争如流水蘸柴门？休回首，欲断魂，数声啼鸟不堪闻。", "(末唱)。"]'),
('yuanqu-4972','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','风光正暮春，便纵然劳役，何必愁闷？绿英红雨，征袍上染惹芳尘。',86,'元曲/yuanqu.json','["风光正暮春，便纵然劳役，何必愁闷？绿英红雨，征袍上染惹芳尘。", "云梯月殿图贵显，水宿风餐莫厌贫。", "(合)乘桃浪，跃锦鳞，一声雷动过龙门。", "荣归去，绿绶新，休教妻嫂笑苏秦。", "(净唱)。"]'),
('yuanqu-4973','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','谁家近水滨，见画桥烟柳，朱门隐隐。',89,'元曲/yuanqu.json','["谁家近水滨，见画桥烟柳，朱门隐隐。", "秋千影里，墙头半出红粉。", "他无情笑语声渐杳，却不道恼杀多情墙外人。", "(合)思乡远，愁路贫，肯如十度谒侯门？行看取，朝紫宸，凤池鳌禁听丝纶。", "(丑唱)。"]'),
('yuanqu-4974','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','遥望雾霭纷，想洛阳宫阙，行行将近。',88,'元曲/yuanqu.json','["遥望雾霭纷，想洛阳宫阙，行行将近。", "程途劳倦，欲待共饮芳樽。", "垂杨瘦马莫暂停，只见那古树昏鸦栖渐尽。", "(合)天将暝，日已曛，一声残角断樵门。", "寻宿处，行步紧，前村灯火已黄昏。", "(合唱)。"]'),
('yuanqu-4975','余文','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','向人家，忙投奔，解鞍沽酒共论文，今夜雨打梨花深闭门。',26,'元曲/yuanqu.json','["向人家，忙投奔，解鞍沽酒共论文，今夜雨打梨花深闭门。"]'),
('yuanqu-4976','破齐阵','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','翠减祥鸾罗幌，香销宝鸭金炉。',54,'元曲/yuanqu.json','["翠减祥鸾罗幌，香销宝鸭金炉。", "楚馆云闲，秦楼月冷，动是离人愁思。", "目断天涯云山远，人在高堂雪鬓疏，缘何书也无？。"]'),
('yuanqu-4977','古风','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','明明匣中镜，盈盈晓来妆。',289,'元曲/yuanqu.json','["明明匣中镜，盈盈晓来妆。", "忆昔事君子，鸡鸣下君床。", "临镜理笄总，随君问高堂。", "一旦远别离，镜匣掩清光。", "流尘暗绮练，青苔生洞房。", "零落金钗钿，惨淡罗衣裳。", "伤哉憔悴容，无复蕙兰芳。", "有怀凄以苦，有路阻且长。", "妾身岂叹此，所忧在姑嫜。", "念彼猿猱远，眷此桑榆光。", "愿言尽妇道，游子不可望。", "勿弹绿绮琴，弦绝令人伤。", "勿听白头吟，哀音断人肠。", "人事多错迕，羞彼双鸳鸯。", "奴家嫁与伯喈，才方两月。", "指望与他同侍双亲，偕老百年。", "谁知公公严命，强他赴选。", "自从去后，到今并无一个消息。", "把公婆抛撇在家，教奴家独自应承。", "奴家一来要成丈夫之孝，二来要尽为妇之道，尽心竭力，朝夕奉养。", "正是：天涯海角有穷时，只有此情无尽处。", "(唱)。"]'),
('yuanqu-4978','临江仙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','日映宫花明翠巾莫，蓝袍嫩绿新裁。',71,'元曲/yuanqu.json','["日映宫花明翠巾莫，蓝袍嫩绿新裁。", "五花门外榜初开，金鞍乘骏马，敕赐上天阶。", "十里红楼帘尽卷，美人争看名魁。", "黄旗影里闹咳咳，大家齐雅静，看取状元来。"]'),
('yuanqu-4979','哭岐婆','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','洛阳富贵，花如锦绮。',36,'元曲/yuanqu.json','["洛阳富贵，花如锦绮。", "红楼数里，无非娇媚。", "春风得意马蹄疾，天街赏遍方归去。"]'),
('yuanqu-4980','水底鱼儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','朝省尚书，昨日蒙圣旨：道状元及第，教咱去陪宴席。',80,'元曲/yuanqu.json','["朝省尚书，昨日蒙圣旨：道状元及第，教咱去陪宴席。", "(马跳过丑身上)(丑叫)跌坏了人胎！(末介马不行介)越着鞭越退，遣人心下疑。", "转头回望，(丑叫介)叫我的还是谁？。"]'),
('yuanqu-4981','北叨叨令','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','闹炒炒街市上游人乱，(末白)你马惊了？(丑唱)乖头口抵死要回身转。',67,'元曲/yuanqu.json','["闹炒炒街市上游人乱，(末白)你马惊了？(丑唱)乖头口抵死要回身转。", "(末白)怎的不勒过？(丑唱)战兢兢只怕缰绳断，(末白)为甚不打他？。"]'),
('yuanqu-4982','哭岐婆','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','玉鞭袅袅，如龙骄骑。',36,'元曲/yuanqu.json','["玉鞭袅袅，如龙骄骑。", "黄旗影里，笙歌鼎沸。", "如今端的是男儿，行看锦衣归故里。"]'),
('yuanqu-4983','五供养','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','文章高晁董，对丹墀已膺天宠。',14,'元曲/yuanqu.json','["文章高晁董，对丹墀已膺天宠。"]'),
('yuanqu-4984','山花子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','玳筵开处游人拥，争看五百名英雄。',16,'元曲/yuanqu.json','["玳筵开处游人拥，争看五百名英雄。"]'),
('yuanqu-4985','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','三千礼乐如泉涌，一笔万丈长虹。',39,'元曲/yuanqu.json','["三千礼乐如泉涌，一笔万丈长虹。", "看奎光飞缠紫宫，光摇万玉班中。", "(合前)(主唱)。"]'),
('yuanqu-4986','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','青云路通，一举能高中，三千水击飞冲。',44,'元曲/yuanqu.json','["青云路通，一举能高中，三千水击飞冲。", "又何必扶桑挂弓？也强如剑倚在崆峒。", "(合前)(丑唱)。"]'),
('yuanqu-4987','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','恩深九重，络绎八珍送，无非翠釜驼峰。',52,'元曲/yuanqu.json','["恩深九重，络绎八珍送，无非翠釜驼峰。", "(末唱)看吾皇待贤恁隆，也不枉了十年窗下把书来攻。", "(合前)(生唱)。"]'),
('yuanqu-4988','大和佛','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','宝篆沉烟香喷浓，(合)浓云罗绣丛。',17,'元曲/yuanqu.json','["宝篆沉烟香喷浓，(合)浓云罗绣丛。"]'),
('yuanqu-4989','舞霓裳','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','愿取群贤尽贞忠，尽贞忠。',68,'元曲/yuanqu.json','["愿取群贤尽贞忠，尽贞忠。", "管取云台画形容，画形容。", "时清无报君恩重，惟有一封书上劝东封，更撰个河清德颂。", "乾坤正，看玉柱擎天又何用？(合唱)。"]'),
('yuanqu-4990','忆秦娥','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','长吁气，自怜薄命相遭际。',26,'元曲/yuanqu.json','["长吁气，自怜薄命相遭际。", "相遭际，晚年舅姑，薄情夫婿。"]'),
('yuanqu-4991','清平乐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','夫妻两月，一旦成分别。',168,'元曲/yuanqu.json','["夫妻两月，一旦成分别。", "没主公婆甘旨缺，几度思量悲切。", "家贫先自艰难，那更不遇丰年。", "恁的千辛万苦，苍天也不相怜。", "奴家自从儿夫出去，遭此饥荒；况兼公婆年老，朝不保夕。", "教奴家独自，如何区处？婆婆日夜埋冤公公，当初不合教孩儿出去。", "如今饥荒，教媳妇怎生区处。", "公公又不伏善，只管在家煎妙。", "免不得等公公婆婆出来，待奴家着些产道理，劝解则个。", "(外上唱)。"]'),
('yuanqu-4992','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','孩儿一去无消息，双亲老景难存济。',16,'元曲/yuanqu.json','["孩儿一去无消息，双亲老景难存济。"]'),
('yuanqu-4993','金索挂梧桐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','区区个孩儿，两口相依倚。',122,'元曲/yuanqu.json','["区区个孩儿，两口相依倚。", "没事为着功名，不要他供甘旨。", "教他去做官，要改换门闾。", "他做得官时你做鬼，老贼！你图他三牲五鼎供朝夕，今日里要一口粥汤却教谁与你？相连累，我孩儿因你做不得好名儒。", "(合)空争着闲非闲是，空争着闲非闲是，只落得双垂泪。", "(外唱)。"]'),
('yuanqu-4994','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','孩儿虽暂离，须有日回家里。',108,'元曲/yuanqu.json','["孩儿虽暂离，须有日回家里。", "奴自有些金珠，解当充粮米。", "公公婆婆休争么，教旁人道媳妇每，有甚差池，致使公婆争恁地。", "婆婆，他心中爱子只望功名就；公公，他眼下无儿必是埋冤语。", "难逃避，兀的不是从天降下这灾危？(合前)(外唱)。"]'),
('yuanqu-4995','刘泼帽','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我每不久须倾弃，叹当初足我不是。',48,'元曲/yuanqu.json','["我每不久须倾弃，叹当初足我不是。", "苦！不如我死了到无他虑。", "(合)一度思量，一度也肝肠碎。", "(净唱)。"]'),
('yuanqu-4996','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','有儿却遣他出去，教媳妇怎生区处？媳妇，可怜误你芳年纪。',36,'元曲/yuanqu.json','["有儿却遣他出去，教媳妇怎生区处？媳妇，可怜误你芳年纪。", "(合前)(旦唱)。"]'),
('yuanqu-4997','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媳妇便是亲儿女，劳役本分当为。',32,'元曲/yuanqu.json','["媳妇便是亲儿女，劳役本分当为。", "但愿公婆从此去，相和美。", "(合前)。"]'),
('yuanqu-4998','似娘儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','华发渐星星，怜爱女欲遂姻盟，蟾宫仙子才堪并。',39,'元曲/yuanqu.json','["华发渐星星，怜爱女欲遂姻盟，蟾宫仙子才堪并。", "红楼此日。", "红丝待选，须教红叶传情。"]'),
('yuanqu-4999','醉太平','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','张家李家，都来唤我。',36,'元曲/yuanqu.json','["张家李家，都来唤我。", "我每须胜别媒婆，(末白)为甚么？(丑唱)有动使惹多。"]'),
('yuanqu-5000','琐窗郎','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','吾家一女娉婷，不曾许与公卿。',69,'元曲/yuanqu.json','["吾家一女娉婷，不曾许与公卿。", "昨承帝旨，选他书生。", "媒婆，你对他说：不须用白壁、黄金为聘。", "(合)若是姻缘前世已曾定，今日里，共欢庆。", "(丑唱)。"]'),
('yuanqu-5001','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','在东京极有名声，论媒婆非自逞。',46,'元曲/yuanqu.json','["在东京极有名声，论媒婆非自逞。", "今朝事体，管取圆成。", "怕有一轻一重，全凭官秤。", "(合前)(末唱)。"]'),
('yuanqu-5002','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','然虽他高占魁名，得相招多少荣。',42,'元曲/yuanqu.json','["然虽他高占魁名，得相招多少荣。", "荣依绣幕，选中雀屏。", "媒婆，你此去，他必从命。", "(合前)。"]'),
('yuanqu-5003','高阳台','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','梦远亲闱，愁深旅邸，那更音信辽绝。',59,'元曲/yuanqu.json','["梦远亲闱，愁深旅邸，那更音信辽绝。", "凄楚情怀，怕逢凄楚时节。", "重门半掩黄昏雨，奈寸肠此际千结。", "守寒窗，一点孤灯，照人明灭。"]'),
('yuanqu-5004','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','当时轻散轻别。',60,'元曲/yuanqu.json','["当时轻散轻别。", "叹玉箫声杳，小楼明月。", "一段愁烦，番成两下悲切。", "忱边万点思亲泪，伴漏声到晓方彻。", "锁愁眉，慵临青镜，顿添华发。"]'),
('yuanqu-5005','木兰花','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','鳌头可羡，须知富贵非吾愿。',179,'元曲/yuanqu.json','["鳌头可羡，须知富贵非吾愿。", "雁足难凭，没个音书寄此情。", "田园荒了，不知松菊犹存否？光景无多，争奈椿萱老去何？自家为父亲所强，来此赴选。", "谁知逗留在此，竟然不归？今又复拜皇恩，除为议郎。", "虽则任居清要，争奈父母年老，安可久留他乡？天那！知我的父母安否如何？知我的妻室如何看待我的父母？待自家上表辞官，又未知圣意如何？正是：好似和针吞却线，刺人肠肚系人心。", "(末丑上唱)。"]'),
('yuanqu-5006','胜葫芦','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','特奉皇恩赐结亲，来此把信音传。',37,'元曲/yuanqu.json','["特奉皇恩赐结亲，来此把信音传。", "若是仙郎，肯谐缱绻，一场好事管取今朝便团圆。"]'),
('yuanqu-5007','高阳台','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','宦海沉身，京尘迷目，名缰利锁难脱。',72,'元曲/yuanqu.json','["宦海沉身，京尘迷目，名缰利锁难脱。", "目断家乡，空劳魂梦飞越。", "闲聒，闲藤野蔓休缠也，俺自有正兔丝和那的亲瓜葛。", "是谁人，无端调引，谩劳饶舌。", "(末唱)。"]'),
('yuanqu-5008','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','华阅，紫阁名公，黄扉元宰，三槐位里排列。',74,'元曲/yuanqu.json','["华阅，紫阁名公，黄扉元宰，三槐位里排列。", "金屋婵娟，妖娆那更贞洁。", "(丑唱)欢悦，红楼此日招凤侣，遣妾每特来执伐。", "望君家，殷勤首肯，早谐结发。", "(生唱)。"]'),
('yuanqu-5009','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','不达，相府寻亲，侯门纳礼，你却拒他不屑。',77,'元曲/yuanqu.json','["不达，相府寻亲，侯门纳礼，你却拒他不屑。", "绣幕奇葩，春光正当十八。", "(丑唱)休撇，知君是个折桂手，留此花待君来扳折。", "况亲奉，丹墀诏旨，非我自相撺掇。", "(生唱)。"]'),
('yuanqu-5010','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','迂阔，他势压朝班，威倾京国，你却与他相别。',37,'元曲/yuanqu.json','["迂阔，他势压朝班，威倾京国，你却与他相别。", "只怕他转日回天，那时须有个决裂。"]'),
('yuanqu-5011','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','秀才堪笑，故阻佯推不肯从。',42,'元曲/yuanqu.json','["秀才堪笑，故阻佯推不肯从。", "岂是我无佳婿得乘龙？他有甚福缘能跨凤？料想书生，只是命穷。"]'),
('yuanqu-5012','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媒婆告相公知：恨那人作怪跷蹊。',38,'元曲/yuanqu.json','["媒婆告相公知：恨那人作怪跷蹊。", "道始得及第，纵有花貌休提。", "骂相公，骂小娘……。"]'),
('yuanqu-5013','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','恩官且听咨启：蔡状元闻说愁眉。',74,'元曲/yuanqu.json','["恩官且听咨启：蔡状元闻说愁眉。", "忠和孝，恩和义。", "念父母八十年余，况已娶了妻室，再婚重娶非礼。", "待早朝，上表文，要辞官家去，请相公别选一佳婿。", "(外笑介)。"]'),
('yuanqu-5014','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他原来要奏丹墀，敢和我厮挺相持。',46,'元曲/yuanqu.json','["他原来要奏丹墀，敢和我厮挺相持。", "(合)读书辈，没道理，不思量违背圣旨。", "只教他辞婚辞官俱未得。"]'),
('yuanqu-5015','剔银灯','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','忒过分爹行所为，但索强全不顾人议。',61,'元曲/yuanqu.json','["忒过分爹行所为，但索强全不顾人议。", "背飞鸟硬求来谐比翼，隔墙花强扳来做连理。", "姻缘，还是怎的？我待说呵，婚姻事女孩儿家怎提？。"]'),
('yuanqu-5016','桂枝香','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','书生愚见，忒不通变。',62,'元曲/yuanqu.json','["书生愚见，忒不通变。", "不肯坦腹东床，谩自去哀求金殿。", "想他每就里，将人轻贱。", "非爹胡缠，怕被人传：道你是相府公侯女，不能勾嫁状元。"]'),
('yuanqu-5017','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','百年姻眷，须教情愿。',62,'元曲/yuanqu.json','["百年姻眷，须教情愿。", "他那里抵死推辞，俺这里不索留恋。", "想他每就里，有些儿牵绊。", "怕恩多成怨。", "满皇都少甚么公侯子，何须去嫁状元？。"]'),
('yuanqu-5018','北点降唇','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','夜色将阑，晨光欲散。',32,'元曲/yuanqu.json','["夜色将阑，晨光欲散。", "把珠帘卷，移步丹墀，摆列着金龙案。", "(又唱)。"]'),
('yuanqu-5019','北混江龙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','官居宫苑，谩道是天威咫尺近龙颜。',99,'元曲/yuanqu.json','["官居宫苑，谩道是天威咫尺近龙颜。", "每日价亲随车驾，只听鸣鞭。", "去螭头上拜跪，随着那豹尾盘旋。", "朝朝宿卫，早早随班。", "做不得卿相当朝一品贵，到先做他朝臣待漏五更寒。", "休嗟叹，山寺日高僧未起，算来兀的名利不如闲。"]'),
('yuanqu-5020','点绛唇','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','月淡星稀，建章宫里，千门晓。',52,'元曲/yuanqu.json','["月淡星稀，建章宫里，千门晓。", "御炉烟袅，隐隐鸣梢杳。", "忽忆年时，问寝高堂早。", "鸡鸣了，闷萦怀抱，此际愁多少！。"]'),
('yuanqu-5021','神仗儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','杨尘舞蹈，扬尘舞蹈，遥瞻天表，见龙鳞日耀。',82,'元曲/yuanqu.json','["杨尘舞蹈，扬尘舞蹈，遥瞻天表，见龙鳞日耀。", "(黄门白)不得升殿。", "(生又唱)咫尺重瞳高照。", "(末)何文字，只须在此，一一分剖。", "(生)遥拜著赭黄袍，遥拜著赭黄袍。", "(生唱)。"]'),
('yuanqu-5022','滴溜子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','臣邕的，臣邕的，荷蒙圣朝。',55,'元曲/yuanqu.json','["臣邕的，臣邕的，荷蒙圣朝。", "臣邕的，臣邕的，拜还紫诰。", "念邕非嫌官小，那家乡万里遥，双亲又老。", "干渎天威，万乞恕饶。"]'),
('yuanqu-5023','入破第一','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','议郎臣蔡邕启：今日蒙恩旨，除臣为郎官职，重蒙婚赐牛氏。',118,'元曲/yuanqu.json','["议郎臣蔡邕启：今日蒙恩旨，除臣为郎官职，重蒙婚赐牛氏。", "干渎天威，臣谨诚惶诚恐，顿首顿首：伏念微臣，初来有志，诵诗书，力学躬耕修已，不复贪荣利。", "事父母，乐田里，初心愿如此而已。", "不想州司，谬取臣邕充试。", "到京畿，岂料愚蒙，叨居上第。", "(又唱)。"]'),
('yuanqu-5024','破第二','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','重蒙圣恩，婚以牛公女。',53,'元曲/yuanqu.json','["重蒙圣恩，婚以牛公女。", "草茅疏贱，如何当此隆遇？但臣亲老，一从别后，光阴又几。", "庐舍田园，荒芜久矣。", "(又唱)。"]'),
('yuanqu-5025','衮第三','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','那更老亲，鬓垂白，筋力皆癯瘁。',68,'元曲/yuanqu.json','["那更老亲，鬓垂白，筋力皆癯瘁。", "形只影单，无弟兄，谁奉侍？况隔千山万水，生死存亡，虽有音书难寄。", "最可悲，他甘旨不供，我食禄有愧。", "(又唱)。"]'),
('yuanqu-5026','歇拍','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','不告父母，怎谐匹偶？臣又听得，家乡里，遭水旱，遇荒饥。',54,'元曲/yuanqu.json','["不告父母，怎谐匹偶？臣又听得，家乡里，遭水旱，遇荒饥。", "多想臣亲，必做沟渠之鬼，末可知。", "怎不教臣，悲伤汨垂？。"]'),
('yuanqu-5027','中衮第四','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','臣享厚禄。',55,'元曲/yuanqu.json','["臣享厚禄。", "纡朱紫，出入承明地。", "独念二亲，寒无衣，饥无食，丧沟渠。", "忆昔先朝！买臣出，守会稽；司马相如，持节锦归。"]'),
('yuanqu-5028','煞尾','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他遭遇圣时，皆得回乡里。',60,'元曲/yuanqu.json','["他遭遇圣时，皆得回乡里。", "臣何故，别父母，远乡闾，没音书，此心违？伏惟陛下，特悯微臣下之志。", "遣臣归，得事双亲，隆恩怎比！。"]'),
('yuanqu-5029','出破','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','若还念臣有微能，乡郡望安置。',43,'元曲/yuanqu.json','["若还念臣有微能，乡郡望安置。", "庶使臣，忠心孝意，得全美。", "臣无任瞻天望圣，激切屏营之至！。"]'),
('yuanqu-5030','滴溜子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','天应念，天应念，蔡邕拜祷：双亲的，双亲的，死生未保，可怜恩深难报。',54,'元曲/yuanqu.json','["天应念，天应念，蔡邕拜祷：双亲的，双亲的，死生未保，可怜恩深难报。", "一封奏九重，知他听否？会合分离，都在这遭。"]'),
('yuanqu-5031','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','今日里，今日里，议郎进表，传达上，传达上，圣目看了。',56,'元曲/yuanqu.json','["今日里，今日里，议郎进表，传达上，传达上，圣目看了。", "道太师昨日先奏，把乘龙女婿招，多少是好！见有玉音，临降听剖。"]'),
('yuanqu-5032','啄木儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','苦！我亲衰老，妻幼娇，万里关山音信杳。',73,'元曲/yuanqu.json','["苦！我亲衰老，妻幼娇，万里关山音信杳。", "他那里举目凄凄，我这里回首迢迢。", "他那里望得眼穿儿不到，俺这里哭得泪干亲难保。", "闪杀人么一封丹凤诏。", "(黄门唱)。"]'),
('yuanqu-5033','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','何须虑，不用焦，人世上离多欢会少。',69,'元曲/yuanqu.json','["何须虑，不用焦，人世上离多欢会少。", "大丈夫当万里封侯，肯守着故园空老？毕竟事君事亲一般道，人生怎全得忠和孝？却不见母死王陵归汉朝？(生唱)。"]'),
('yuanqu-5034','三段子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','这怀怎剖？望丹墀天高听高。',63,'元曲/yuanqu.json','["这怀怎剖？望丹墀天高听高。", "这苦怎逃？望白云山遥路遥。", "(黄门唱)你做官与亲添荣耀，高堂管取加封号，与你改换门闾偏不好？(生唱)。"]'),
('yuanqu-5035','归朝天','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','冤家的，冤家的，苦苦见招，俺媳妇埋冤怎了？饥荒岁，饥荒岁，怕他怎熬？俺爹娘们不做沟渠中饿殍？(黄门唱)譬如四方战争多征调，从军远戍沙场草，也只为国忘家怎惮劳？。',80,'元曲/yuanqu.json','["冤家的，冤家的，苦苦见招，俺媳妇埋冤怎了？饥荒岁，饥荒岁，怕他怎熬？俺爹娘们不做沟渠中饿殍？(黄门唱)譬如四方战争多征调，从军远戍沙场草，也只为国忘家怎惮劳？。"]'),
('yuanqu-5036','普贤歌','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','身充里正实难当。',37,'元曲/yuanqu.json','["身充里正实难当。", "杂泛应承日夜忙。", "官司点义仓，并无些子粮，拚一个拖番吃大棒。"]'),
('yuanqu-5037','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','身充社长管官仓，老小一家得仓里养。',42,'元曲/yuanqu.json','["身充社长管官仓，老小一家得仓里养。", "事发尽不妨，里正先吃棒。", "尊兄，打了都官，方打社长。"]'),
('yuanqu-5038','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','亲承朝命赈饥荒，跃马扬鞭来到此方。',44,'元曲/yuanqu.json','["亲承朝命赈饥荒，跃马扬鞭来到此方。", "里正那里？疾忙开义仓，支与百姓粮。", "咳！从实支收休要谎。"]'),
('yuanqu-5039','吴织机','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','肚又饥，眼又昏，家私没半分，子哭儿啼不可闻。',38,'元曲/yuanqu.json','["肚又饥，眼又昏，家私没半分，子哭儿啼不可闻。", "闻知相公来济民，请些官粮去救窘。"]'),
('yuanqu-5040','捣练子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','叹命薄，叹年艰，含羞和泪向人前，只恐公婆悬望眼。',24,'元曲/yuanqu.json','["叹命薄，叹年艰，含羞和泪向人前，只恐公婆悬望眼。"]'),
('yuanqu-5041','普天乐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我儿夫一向留都下。',42,'元曲/yuanqu.json','["我儿夫一向留都下。", "(净白)你家里有谁？(旦唱)俺只有年老的爹和妈。", "(净白)更有谁？。"]'),
('yuanqu-5042','锁南枝','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','儿夫去，竟不还，公婆两人都老年。',60,'元曲/yuanqu.json','["儿夫去，竟不还，公婆两人都老年。", "从昨日到如今，不能勾得餐饭。", "奴请粮，他在家悬望眼。", "念我老公婆，做方便。", "(丑介)(旦唱)。"]'),
('yuanqu-5043','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','乡官可怜见，这是公婆命所关。',83,'元曲/yuanqu.json','["乡官可怜见，这是公婆命所关。", "若是必须将去，宁可脱了奴衣裳，就问乡官换。", "(丑白)不要，你身上寒冷。", "(旦唱)宁使奴，身上寒。", "只要与公婆，救残喘。", "(丑夺谷介下)(旦介唱)。"]'),
('yuanqu-5044','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你夺将去，真可怜，公婆望奴奴不见。',52,'元曲/yuanqu.json','["你夺将去，真可怜，公婆望奴奴不见。", "纵然他不埋怨，道我做媳妇还何干？他忍饥，添我夫罪愆。", "怎得见，我夫面？。"]'),
('yuanqu-5045','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','将身赴井泉，思量左右难。',62,'元曲/yuanqu.json','["将身赴井泉，思量左右难。", "我丈夫当年分散，叮咛祝付爹娘，教我与他相看筲。", "我死却，他形影单。", "夫婿与公婆，可不两埋冤？(外上唱)。"]'),
('yuanqu-5046','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媳妇去，不见还，教我在家凝望眼。',16,'元曲/yuanqu.json','["媳妇去，不见还，教我在家凝望眼。"]'),
('yuanqu-5047','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','苦！思量我命乖蹇，不由人不珠泪涟。',62,'元曲/yuanqu.json','["苦！思量我命乖蹇，不由人不珠泪涟。", "料想终须饥死，不如早赴黄泉，免把你相牵绊。", "媳妇，婆年老，不久延。", "你须是，好看管。", "(旦唱)。"]'),
('yuanqu-5048','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','公公，伊还身弃，我苦怎言！公还死了婆怎免？两人一旦身亡，教我独自如何展？算来吃苦辛，其实难过遣。',64,'元曲/yuanqu.json','["公公，伊还身弃，我苦怎言！公还死了婆怎免？两人一旦身亡，教我独自如何展？算来吃苦辛，其实难过遣。", "我痛伤悲，只得强相劝。", "(外唱)。"]'),
('yuanqu-5049','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媳妇，你衣衫尽皆典。',75,'元曲/yuanqu.json','["媳妇，你衣衫尽皆典。", "囊箧又罄然。", "纵然目前存活，到底日久日深，你与我难相恋。", "衣食缺，要行孝难。", "不如活冤家，早拆散。", "(外投井介)(旦救住)(末挑谷上唱)。"]'),
('yuanqu-5050','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','不丰岁，荒歉年，生离死别真可怜。',45,'元曲/yuanqu.json','["不丰岁，荒歉年，生离死别真可怜。", "纵有八口人家，饥饿应难免。", "子忍饥，妻忍寒。", "痛哭声，恁哀怨。"]'),
('yuanqu-5051','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','本为泉下人，谢你救我一命存。',38,'元曲/yuanqu.json','["本为泉下人，谢你救我一命存。", "只恨我不久身广，报不得媳妇恩。", "(合前)(夫唱)。"]'),
('yuanqu-5052','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','见说不可闻，况我托在邻。',31,'元曲/yuanqu.json','["见说不可闻，况我托在邻。", "终不然我享安荣，忍见伊受窘？(合前)。"]'),
('yuanqu-5053','蛮牌令','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','终日走千遭，走得脚无毛。',60,'元曲/yuanqu.json','["终日走千遭，走得脚无毛。", "何曾见汤水面？也不见半钱糟。", "倒不如做虔婆顶老，也得哔鸭汁吃饱。", "穷酸秀才直恁乔，老婆与他妆甚腰？。"]'),
('yuanqu-5054','金蕉叶','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','恨多怨多，俺爹娘知他怎么？摆不去功名奈何？送将来冤家怎躲？。',30,'元曲/yuanqu.json','["恨多怨多，俺爹娘知他怎么？摆不去功名奈何？送将来冤家怎躲？。"]'),
('yuanqu-5055','三换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','名缰利锁，先自将人摧锉。',61,'元曲/yuanqu.json','["名缰利锁，先自将人摧锉。", "况鸾拘风束，甚日得到家？我也休怨他咱，这其间，只是我，不合来，长安看花。", "闷杀我爹娘也，珠泪窄暗堕。"]'),
('yuanqu-5056','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','鸾台妆罢，鹊桥初驾，佳期近也。',61,'元曲/yuanqu.json','["鸾台妆罢，鹊桥初驾，佳期近也。", "请仙郎到呵，明知萦挂。", "这其问，只得把，那雄厢，且都拚舍。", "他奉着君王诏，怎生别了他。", "(合前)。"]'),
('yuanqu-5057','传言玉女','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','烛影摇红，帘幕瑞烟浮动，画堂中珠围翠拥。',43,'元曲/yuanqu.json','["烛影摇红，帘幕瑞烟浮动，画堂中珠围翠拥。", "妆台对月，下鸾鹤神仙仪从。", "玉箫声里，一双鸣凤。"]'),
('yuanqu-5058','水调歌头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','屏开金孔雀，褥隐绣芙蓉。',154,'元曲/yuanqu.json','["屏开金孔雀，褥隐绣芙蓉。", "兽炉烟袅，莲台绛蜡吐春红。", "广设珊瑚席子，高把真珠帘卷，环列翠屏风。", "人间丞相府，天上蕊珠宫。", "锦遮围，花熳烂，玉玲珑。", "繁弦脆管，欢声鼎沸画堂中。", "簇拥金钗十二，座列三千珠履？谈笑尽王公。", "正是门阑多喜气，女婿近乘龙。", "(外白)状元来了未？(末白)远远望见一簇人马闹炒，想是状元来了。", "(生上唱)。"]'),
('yuanqu-5059','女冠子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','马蹄笃速，传呼齐拥雕毂。',87,'元曲/yuanqu.json','["马蹄笃速，传呼齐拥雕毂。", "(外唱)宫花帽簇，天香袍染，丈夫得志，佳婿乘龙。", "(贴上唱)妆成闻唤促，义将娇面重遮，羞蛾轻蹙。", "(净丑执掌扇上唱)这姻缘不俗。", "(合)金榜题名，洞房花烛。"]'),
('yuanqu-5060','画眉序','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','扳桂步蟾宫，岂料丝萝在乔木。',64,'元曲/yuanqu.json','["扳桂步蟾宫，岂料丝萝在乔木。", "喜书中今日，有女如玉。", "堪观处丝幕牵红，恰正是荷衣穿绿。", "(合)这回好个风流婿，偏称洞房花烛。", "(外唱)。"]'),
('yuanqu-5061','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','君才冠天禄，我的门楣稍贤淑。',50,'元曲/yuanqu.json','["君才冠天禄，我的门楣稍贤淑。", "看相辉清润，莹然冰玉。", "光掩映孔雀屏开，花烂熳芙蓉隐褥。", "(合前)(贴唱)。"]'),
('yuanqu-5062','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','频催少膏沐，金凤斜飞鬓云矗。',40,'元曲/yuanqu.json','["频催少膏沐，金凤斜飞鬓云矗。", "已逢他萧史，愧非弄玉。", "清风引佩下瑶台，明月妆成金屋。"]'),
('yuanqu-5063','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','湘裙颤六幅，似天上嫦娥降尘俗。',51,'元曲/yuanqu.json','["湘裙颤六幅，似天上嫦娥降尘俗。", "喜蓝田今日，种成双玉。", "风月赛阆苑三千，云雨笑巫山二六。", "(合前)(生唱)。"]'),
('yuanqu-5064','滴溜子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','谩说道姻缘，果谐凤卜。',60,'元曲/yuanqu.json','["谩说道姻缘，果谐凤卜。", "细思之此事，岂吾意欲？有人在高堂孤独。", "可惜新人笑语喧，不知旧人哭。", "兀的东床，难教我坦腹。", "(合唱)。"]'),
('yuanqu-5065','鲍老催','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','翠眉谩蹙，赤绳已系夫妇足，芳名已注婚姻牍。',62,'元曲/yuanqu.json','["翠眉谩蹙，赤绳已系夫妇足，芳名已注婚姻牍。", "空嗟怨，枉叹息，休推速。", "画堂富贵如金谷，休恋故乡生处乐，受恩深处亲骨肉。", "(合唱)。"]'),
('yuanqu-5066','鲍老催','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','意深爱笃，文章富贵珠万斛，天教艳质为眷属。',61,'元曲/yuanqu.json','["意深爱笃，文章富贵珠万斛，天教艳质为眷属。", "似蝶恋花，凤栖梧，鸾停竹。", "男儿有书须勤读，书中自黄金屋，也自有千钟粟。", "(合唱)。"]'),
('yuanqu-5067','双声子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','郎多福，郎多福，看紫绶黄金束。',57,'元曲/yuanqu.json','["郎多福，郎多福，看紫绶黄金束。", "娘分福，娘分福，看花诰纹犀轴。", "两意笃，两意笃。", "岂非福，岂非福。", "似文鸳彩凤，两两相逐。"]'),
('yuanqu-5068','玉井莲后','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','忍饿担饥，未知何日是了？。',13,'元曲/yuanqu.json','["忍饿担饥，未知何日是了？。"]'),
('yuanqu-5069','罗鼓令','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我终朝的受馁，你将来的饭怎吃？疾忙便抬，非干是我有些馋态。',135,'元曲/yuanqu.json','["我终朝的受馁，你将来的饭怎吃？疾忙便抬，非干是我有些馋态。", "(外唱)你看他衣衫都解，好茶饭将甚去买？婆婆，兀的是天灾，教他媳妇每难布摆。", "(旦唱)婆婆息怒且休罪，待奴家一霎时却得再安排。", "(合)思量到此，珠泪满腮。", "看看做鬼，沟渠里埋。", "纵然不死也难捱，教人只恨蔡伯喈。", "(净唱)。"]'),
('yuanqu-5070','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','如今我试猜：多应址你独口童病来？多应是你买些鲑菜？我吃饭他缘何不在？这些意真乃是歹？(外唱)婆婆，他和你甚相爱，不应反面直恁的乖。',97,'元曲/yuanqu.json','["如今我试猜：多应址你独口童病来？多应是你买些鲑菜？我吃饭他缘何不在？这些意真乃是歹？(外唱)婆婆，他和你甚相爱，不应反面直恁的乖。", "(旦唱)我千辛万苦，有甚情怀？可不道我脸儿黄瘦骨如柴。", "(合前)。"]'),
('yuanqu-5071','山坡羊','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','乱荒荒不丰稔的年岁，远迢迢不回来的夫婿。',94,'元曲/yuanqu.json','["乱荒荒不丰稔的年岁，远迢迢不回来的夫婿。", "急煎煎不耐烦的二亲，软怯怯不济事的孤身己。", "衣尽典，寸丝不挂体。", "几番要卖了奴身己，争奈没主公婆教谁看取？(合)思之，虚飘飘命怎期？难捱，实丕丕灾共危。"]'),
('yuanqu-5072','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','滴溜溜难穷尽的珠泪，乱纷纷难宽解的愁绪。',95,'元曲/yuanqu.json','["滴溜溜难穷尽的珠泪，乱纷纷难宽解的愁绪。", "骨崖崖难扶持的病体，战钦钦难捱过的时和岁。", "这糠呵，我待不吃你，教奴怎忍饥？我待吃呵，怎吃得？(介)苦！思量起来不如奴先死，图得不知他亲死时。", "(合前)。"]'),
('yuanqu-5073','孝顺歌','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','呕得我肝肠痛，珠泪垂，喉咙尚兀自牢嗄住。',84,'元曲/yuanqu.json','["呕得我肝肠痛，珠泪垂，喉咙尚兀自牢嗄住。", "糠！遭砻被舂杵，筛你簸扬你，吃尽控持。", "悄似奴家身狼狈，千辛万苦皆经历。", "苦人吃着苦味，两苦相逢，可知道欲吞不去。", "(吃吐介)(唱)。"]'),
('yuanqu-5074','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','糠和米，本是两倚依，谁人簸扬你作两处飞？一贱与一贵，好似奴家共夫婿，终无见期。',103,'元曲/yuanqu.json','["糠和米，本是两倚依，谁人簸扬你作两处飞？一贱与一贵，好似奴家共夫婿，终无见期。", "丈夫，你便是米么，米在他方没寻处。", "奴便是糠么，怎的把糠救得人饥馁？好似儿夫出去，怎的教奴，供给得公婆甘旨？(不吃放碗介)(唱)。"]'),
('yuanqu-5075','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','思量我生无益，死又值甚的！不如忍饥为怨鬼。',88,'元曲/yuanqu.json','["思量我生无益，死又值甚的！不如忍饥为怨鬼。", "公婆年纪老，靠着奴家相依倚，只得苟活片时。", "片时苟活虽容易，到底日久也难相聚。", "谩把糠来相比，这糠尚兀自有人吃，奴家骨头，知他埋在何处？。"]'),
('yuanqu-5076','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','这是谷中膜，米上皮，将来逼逻堪疗饥。',64,'元曲/yuanqu.json','["这是谷中膜，米上皮，将来逼逻堪疗饥。", "(外净白)这是糠，你却怎的吃得？(旦唱)尝闻古贤书，狗彘食人食，公公，婆婆，须强如草根树皮。"]'),
('yuanqu-5077','雁过沙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他沉沉向迷途，空教我耳边呼。',69,'元曲/yuanqu.json','["他沉沉向迷途，空教我耳边呼。", "公公，婆婆，我不能尽心相奉事，番教你为我归黄土。", "公公，婆婆，人道你死缘何故？公公，婆婆，你怎生割舍抛弃了奴？。"]'),
('yuanqu-5078','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媳妇，你耽饥事公姑。',76,'元曲/yuanqu.json','["媳妇，你耽饥事公姑。", "媳妇，你耽饥怎生度？错埋冤你也不肯辞，我如今始信有糟糠妇。", "媳妇，我料应不久归阴府。", "媳妇，你休便为我死的把生的受苦。", "(旦叫婆婆介唱)。"]'),
('yuanqu-5079','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','婆婆，你还死教奴家怎支吾？你若死教我怎生度？我千辛万苦回护丈夫，如今到此难回护。',68,'元曲/yuanqu.json','["婆婆，你还死教奴家怎支吾？你若死教我怎生度？我千辛万苦回护丈夫，如今到此难回护。", "我只愁母死难留父，况衣衫尽解，囊箧又无。", "(外叫净介唱)。"]'),
('yuanqu-5080','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','婆婆，我当初不寻思，教孩儿往皇都。',55,'元曲/yuanqu.json','["婆婆，我当初不寻思，教孩儿往皇都。", "把媳妇闪得苦又孤，把婆婆送入黄泉路，只怨是我相耽误。", "我骨头未知埋在何处所？。"]'),
('yuanqu-5081','玉包肚','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','千般生受，教奴家如何措手？终不然把他骸骨，没棺椁送在荒丘？(合)相看到此，不由人不珠泪流，正是不是冤家不聚头。',60,'元曲/yuanqu.json','["千般生受，教奴家如何措手？终不然把他骸骨，没棺椁送在荒丘？(合)相看到此，不由人不珠泪流，正是不是冤家不聚头。", "(末唱)。"]'),
('yuanqu-5082','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','不须多忧，送婆婆是我身下有。',98,'元曲/yuanqu.json','["不须多忧，送婆婆是我身下有。", "你但小心承直公公，莫教又成不救。", "(合前)(旦白)如此，谢得公公！只为无钱送老娘。", "(末白)娘子放心，须知此事有商量。", "(合)正是：归家不敢高声哭，只恐人闻也断肠。", "(并下)。"]'),
('yuanqu-5083','一枝花','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','闲庭槐影转，深院荷香满。',53,'元曲/yuanqu.json','["闲庭槐影转，深院荷香满。", "帘垂清昼水，怎消遣？十二阑杆，无事闲凭遍。", "困来湘簟展，梦到家山，又被翠竹敲风惊断。"]'),
('yuanqu-5084','南乡子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','万竹影摇金，水殿帘栊映碧阴。',146,'元曲/yuanqu.json','["万竹影摇金，水殿帘栊映碧阴。", "人静昼长无外事，请吟，碧酒金樽懒去斟。", "幽恨苦相寻，谁知离别经年无信音？寒暑相催人易老，关心，却把闲愁付玉琴。", "左右过来。", "(末上白)黄卷看来消白日，朱弦动处引清风。", "炎蒸不到珠帘下，人在瑶池阆苑中。", "琴书见在。", "(生)你与我叫两个学童出来。", "(末叫介)(净把扇丑把香炉上唱)。"]'),
('yuanqu-5085','金钱花','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','自小承值书房，书房。',42,'元曲/yuanqu.json','["自小承值书房，书房。", "快活其实难当，难当。", "只管把扇与烧香，荷亭畔好乘凉，吃饱饭上眠床。"]'),
('yuanqu-5086','懒画眉','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','强对南熏奏虞弦，只见指下余音不似前，那些个流水共高山？呀！怎的只见满眼风波恶，似离别当年怀水仙。',48,'元曲/yuanqu.json','["强对南熏奏虞弦，只见指下余音不似前，那些个流水共高山？呀！怎的只见满眼风波恶，似离别当年怀水仙。"]'),
('yuanqu-5087','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','顿觉余音转愁烦，还似别雁孤鸿和断猿，又如别凤乍离鸾。',48,'元曲/yuanqu.json','["顿觉余音转愁烦，还似别雁孤鸿和断猿，又如别凤乍离鸾。", "呀！怎的只见杀声在弦中见？敢只是螳螂来捕蝉。"]'),
('yuanqu-5088','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','日暖蓝田玉生烟，似望帝春心托杜鹃，好姻缘还似恶姻缘。',41,'元曲/yuanqu.json','["日暖蓝田玉生烟，似望帝春心托杜鹃，好姻缘还似恶姻缘。", "只怕知音少，争得鸾胶续断弦？。"]'),
('yuanqu-5089','满江红','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','嫩绿池塘。',53,'元曲/yuanqu.json','["嫩绿池塘。", "梅雨歇熏风乍转。", "见清新华尾，已飞乳燕。", "簟展湘波纨扇冷，歌传令缕琼卮暖。", "是炎燕不到水亭中，珠帘卷。"]'),
('yuanqu-5090','桂枝香','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','危弦已断，新弦不惯。',39,'元曲/yuanqu.json','["危弦已断，新弦不惯。", "旧弦再上不能，我待撇了新弦难拚。", "一弹再鼓，又被宫商错乱，。"]'),
('yuanqu-5091','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','非弦已断，只是你意慵心懒。',98,'元曲/yuanqu.json','["非弦已断，只是你意慵心懒。", "没，你既道是寡鹊孤鸾，又道是昭君宫怨，那更思归别鹤，无非愁叹。", "相公，你心里多敢想着谁？(生)不想甚么人。", "(贴)你既不然，我理会得了，你道是除了知音听，道我不是知音不与弹。"]'),
('yuanqu-5092','烧夜香','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','楼台倒影入池塘，绿树阴浓夏正长，一架荼靡只见满院香。',51,'元曲/yuanqu.json','["楼台倒影入池塘，绿树阴浓夏正长，一架荼靡只见满院香。", "(贴)满院香，和你饮霞觞。", "傍晚卷起帘儿，明月正上。"]'),
('yuanqu-5093','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','蔷薇帘箔，荷花池馆，一点风来香满。',93,'元曲/yuanqu.json','["蔷薇帘箔，荷花池馆，一点风来香满。", "香奁日永，香销宝篆沉烟。", "谩有枕欹寒王，扇动齐纨，怎遂得黄香愿？(泪下介)(贴)做甚么？(生介唱)猛然心地热，透香汗，我欲向南窗一醉眠。", "(合前)(贴唱)。"]'),
('yuanqu-5094','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','向晚来雨过南轩，见池面红妆零乱。',72,'元曲/yuanqu.json','["向晚来雨过南轩，见池面红妆零乱。", "渐轻雷隐隐，雨收云散。", "只见荷香十里，新月一钩，此景佳无限。", "兰汤初浴罢，晚妆残，深院黄昏懒去眠。", "(合前)(生唱)。"]'),
('yuanqu-5095','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','柳阴中忽听新蝉，更流萤飞来庭院。',75,'元曲/yuanqu.json','["柳阴中忽听新蝉，更流萤飞来庭院。", "听菱歌何处？画舡归晚。", "只见玉绳低度，朱户无声，此景尤堪恋。", "起来携素手，鬓云乱，月照纱窗人未眠。", "(合前)(净丑末合唱)。"]'),
('yuanqu-5096','节节高','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','涟漪戏彩鸳，把荷翻，清香泻下琼珠溅。',65,'元曲/yuanqu.json','["涟漪戏彩鸳，把荷翻，清香泻下琼珠溅。", "香风扇，芳沼边，闲亭畔。", "坐来不觉人清健，蓬莱阆苑何足羡。", "(合)只恐西风又惊秋，不觉暗中流年换。"]'),
('yuanqu-5097','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','清宵思爽然，好凉天，瑶台月下清虚殿。',56,'元曲/yuanqu.json','["清宵思爽然，好凉天，瑶台月下清虚殿。", "神仙眷，开玳筵，重欢宴。", "从教玉漏催银箭，水晶宫里把笙歌按。", "(合前)(合唱)。"]'),
('yuanqu-5098','余文','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','光阴迅速如飞电，好良宵可惜渐阑，拚取欢娱歌笑喧。',24,'元曲/yuanqu.json','["光阴迅速如飞电，好良宵可惜渐阑，拚取欢娱歌笑喧。"]'),
('yuanqu-5099','霜天晓角','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','难捱怎避，灾祸重重至？最苦婆婆死矣，公公病，又将危。',26,'元曲/yuanqu.json','["难捱怎避，灾祸重重至？最苦婆婆死矣，公公病，又将危。"]'),
('yuanqu-5100','犯胡兵','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','囊无半点挑药费，良医怎求？纵然救得目前，饭食何处有？料应难到后。',47,'元曲/yuanqu.json','["囊无半点挑药费，良医怎求？纵然救得目前，饭食何处有？料应难到后。", "谩说道有病遇良医，饥荒怎救？。"]'),
('yuanqu-5101','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','公公这病呵，百愁万苦千生受，妆成这症候。',76,'元曲/yuanqu.json','["公公这病呵，百愁万苦千生受，妆成这症候。", "便做这药吃时呵，纵然救得目前，怎免得忧与愁？料应不会久。", "他只为不见孩儿么？这病可时，除非是子孝父心宽，方才可救。"]'),
('yuanqu-5102','霜天晓角','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','悄然魂似飞，料应不久矣。',31,'元曲/yuanqu.json','["悄然魂似飞，料应不久矣。", "纵然抬头强起，(介)形衰倦，怎支持？。"]'),
('yuanqu-5103','香遍满','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','论来汤药，须索是子尝方进与父母，公公，莫不是为无子先尝你便寻思苦？(外强吃吐介白)我吃不得了。',65,'元曲/yuanqu.json','["论来汤药，须索是子尝方进与父母，公公，莫不是为无子先尝你便寻思苦？(外强吃吐介白)我吃不得了。", "(旦唱)你只索□□，怎舍得一命殂？。"]'),
('yuanqu-5104','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他万千愁苦，堆积柞闷怀成气蛊，可知道你吃了吞还吐。',63,'元曲/yuanqu.json','["他万千愁苦，堆积柞闷怀成气蛊，可知道你吃了吞还吐。", "(外白)媳妇，我敢不济事，只是死。", "孩儿又不回来，只亏了你。", "(旦)公公且宽心。"]'),
('yuanqu-5105','哥儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媳妇，三年谢得你相奉事，只恨我当初，将你相耽误。',63,'元曲/yuanqu.json','["媳妇，三年谢得你相奉事，只恨我当初，将你相耽误。", "我欲待报你的深恩，待来生我做你的媳妇。", "怨只怨蔡伯喈不孝子，苦只苦赵五娘辛勤妇。"]'),
('yuanqu-5106','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','寻思：一怨你死了谁祭祀；二怨你有孩儿，不得他相看顾；三怨你三年，没一个饱暖的日子。',62,'元曲/yuanqu.json','["寻思：一怨你死了谁祭祀；二怨你有孩儿，不得他相看顾；三怨你三年，没一个饱暖的日子。", "三载相看甘共苦，一朝分别难同死。", "(外唱)。"]'),
('yuanqu-5107','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媳妇，我死呵，你将我骨头休埋在土。',17,'元曲/yuanqu.json','["媳妇，我死呵，你将我骨头休埋在土。"]'),
('yuanqu-5108','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','思之，公公，你死呵，公婆已得做一处所。',61,'元曲/yuanqu.json','["思之，公公，你死呵，公婆已得做一处所。", "料想奴家，不久归阴府。", "苦！可惜一家，三个怨鬼在冥途。", "三载相看甘共苦，一朝分别难同死。"]'),
('yuanqu-5109','罗帐里坐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媳妇，你艰辛万千，是我耽伊误伊。',103,'元曲/yuanqu.json','["媳妇，你艰辛万千，是我耽伊误伊。", "你不嫁呵，你身衣口食，怎生区处？休休，当原是我误了你，今日又教你嫁人，若嫁不得个好人，怨我如何？终不然又教你，守着灵帏？(放笔介)已知死别在须臾，更与什么生人做主？(末唱)。"]'),
('yuanqu-5110','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','中间就里，我难说怎提？小娘子，若不嫁人，恐非活计；若不守孝，又被人淡议。',59,'元曲/yuanqu.json','["中间就里，我难说怎提？小娘子，若不嫁人，恐非活计；若不守孝，又被人淡议。", "(合)可怜家破与人离，怎不教人泪垂。", "(旦唱)。"]'),
('yuanqu-5111','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','公公严命。',39,'元曲/yuanqu.json','["公公严命。", "非奴敢违。", "只怕再如伯喈，却不误了我一世？公公，我一鞍一马，誓无他志。"]'),
('yuanqu-5112','喜迁莺','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','终朝思想，但恨在眉头，人在心上。',63,'元曲/yuanqu.json','["终朝思想，但恨在眉头，人在心上。", "凤侣添愁，鱼书绝寄，空劳两处相望。", "青镜瘦颜羞照，宝瑟清音绝响。", "归梦杳，绕屏山烟树，那是家乡？。"]'),
('yuanqu-5113','踏莎行','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','怨极愁多，歌慵笑懒，只因添个鸳鸯伴。',74,'元曲/yuanqu.json','["怨极愁多，歌慵笑懒，只因添个鸳鸯伴。", "他乡游子不能归，高堂父母无人管。", "湘浦鱼沉，衡阳雁断，音书要寄无方便。", "人生光景几多时，蹉跎负却平生愿。", "(生再唱)。"]'),
('yuanqu-5114','雁渔锦','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','思量，那日离故乡。',75,'元曲/yuanqu.json','["思量，那日离故乡。", "记临歧送别多惆怅，携手共那人不厮放。", "教他好看承，我爹娘，料他每应不会遗忘。", "闻知饥与荒，只怕捱不过岁月难存养。", "若望不见信音却把谁倚仗。"]'),
('yuanqu-5115','二犯渔家傲','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','思量，幼读文章，论事亲为子也须要成模样。',109,'元曲/yuanqu.json','["思量，幼读文章，论事亲为子也须要成模样。", "真情未讲，怎知道吃尽多磨障？被亲强来赴选场，被君强官为议郎，被婚强效鸾凰。", "三被强衷肠说与谁行？埋冤难禁这两厢，这壁厢道咱是个不撑达害羞的乔相识，那壁厢道咱是个不睹是负心的薄幸郎。"]'),
('yuanqu-5116','雁渔序','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','悲伤，鹭序鸳行，怎如乌鸟反哺能终养？谩把金章，绾着紫绶；试问斑衣，今在何方？斑衣罢想，纵然归去，又怕带麻执杖。',76,'元曲/yuanqu.json','["悲伤，鹭序鸳行，怎如乌鸟反哺能终养？谩把金章，绾着紫绶；试问斑衣，今在何方？斑衣罢想，纵然归去，又怕带麻执杖。", "只为他云梯月殿多劳攘，落得泪雨似珠两鬓霜。"]'),
('yuanqu-5117','渔家喜雁灯','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','几回梦里，忽闻鸡唱。',88,'元曲/yuanqu.json','["几回梦里，忽闻鸡唱。", "忙惊觉错呼旧妇，同问寝堂上。", "待朦胧觉来，依然新人凤衾和象床。", "怎不怨香愁玉无心绪？更思想被他拦挡。", "教我，怎不悲伤？俺这耻欢蜈仅宿笑蓉帐，他那里寂寞偏嫌更漏长。"]'),
('yuanqu-5118','金珑璁','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','饥荒先自窘。',40,'元曲/yuanqu.json','["饥荒先自窘。", "那堪连丧双亲，身独自怎支分？衣衫都典尽，首饰并没分文，无计策剪香云。"]'),
('yuanqu-5119','蝶恋花','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','万苦千辛难摆拨，力尽心穷两泪空流血。',192,'元曲/yuanqu.json','["万苦千辛难摆拨，力尽心穷两泪空流血。", "裙布钗荆今已竭，萱花椿树连摧折。", "金剪盈盈明素雪，空照乌云远映愁眉月。", "一片孝心难尽说，一齐分付青丝发。", "奴家在先婆婆没了，却是张大公周济。", "如今公公又亡过了，无钱资送，难再去求张大公，寻思起没奈何，只得剪下青丝细发，卖几贯钱为送终之用。", "虽然这头发值不得恁多钱，也只把做些意儿，一似教化一般。", "正是：不幸丧双亲，求人不可频。", "聊将青鬓发，断送白头人。", "(旦唱)。"]'),
('yuanqu-5120','香罗带','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','一从鸾凤分，谁梳鬓云？妆台不临生暗尘，那更钗梳首饰典无存也，头发，是我耽阁你，度青春。',80,'元曲/yuanqu.json','["一从鸾凤分，谁梳鬓云？妆台不临生暗尘，那更钗梳首饰典无存也，头发，是我耽阁你，度青春。", "如今又剪你，资送老亲。", "剪发伤情也，只怨着结发的薄幸人。", "(剪又放介)(唱)。"]'),
('yuanqu-5121','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','思量薄幸人，辜奴此身，欲剪未剪教我珠泪零。',104,'元曲/yuanqu.json','["思量薄幸人，辜奴此身，欲剪未剪教我珠泪零。", "我当初早披剃入空门也，做个尼姑去，今日免艰辛。", "只一件，只有我的头发恁的，少什么嫁人的，珠围翠簇兰麝熏。", "呀！似这般光景，我的身死，骨自无埋处，说什么头发愚妇人！(介)。"]'),
('yuanqu-5122','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','堪怜愚妇人，单身又贫。',85,'元曲/yuanqu.json','["堪怜愚妇人，单身又贫。", "我待不剪你头发卖呵，开口告人羞怎忍。", "我待剪呵，金刀下处应心疼也。", "休休，却将堆鸦髻，舞鸾鬓，与乌鸟报答，白发的亲。", "教人道雾鬓云鬟女，断送他霜鬟雪鬓人。"]'),
('yuanqu-5123','临江仙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','连丧双亲无计策，只得剪下香云，非奴苦要孝名传。',37,'元曲/yuanqu.json','["连丧双亲无计策，只得剪下香云，非奴苦要孝名传。", "正是上山擒虎易，开口告人难。"]'),
('yuanqu-5124','梅花塘','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','卖头发，买的休论价。',49,'元曲/yuanqu.json','["卖头发，买的休论价。", "念我受饥荒，囊箧无些个。", "丈夫出去，那更连丧了公婆，没奈何，只得卖头发，资送他。"]'),
('yuanqu-5125','香柳娘','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','看青丝细发，剪来堪爱，如何卖也没人买？若论这饥荒死丧，怎教我女裙钗，当得这狼狈？况我连朝受馁，我的脚儿怎抬？其实难捱。',69,'元曲/yuanqu.json','["看青丝细发，剪来堪爱，如何卖也没人买？若论这饥荒死丧，怎教我女裙钗，当得这狼狈？况我连朝受馁，我的脚儿怎抬？其实难捱。", "(倒介)(再起唱)。"]'),
('yuanqu-5126','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','望前街后街，并无人在。',82,'元曲/yuanqu.json','["望前街后街，并无人在。", "我待再叫呵，咽喉气噎，无如之奈。", "苦！我如今便死，暴露我尸骸，谁人与遮盖？天天！我到底也只是个死。", "待我将头发去卖，卖了把公婆葬埋，奴便死何害？。"]'),
('yuanqu-5127','前曲','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你儿夫曾付托，我怎生违背？你无钱使用，我须当代。',72,'元曲/yuanqu.json','["你儿夫曾付托，我怎生违背？你无钱使用，我须当代。", "交你把头发剪了，又跌倒在长街，都缘是我之罪。", "(合)叹一家破坏，否极何时泰来？各出着泪。", "(旦唱)。"]'),
('yuanqu-5128','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','谢公公可怜，把钱相贷，我公婆在地下相感戴。',47,'元曲/yuanqu.json','["谢公公可怜，把钱相贷，我公婆在地下相感戴。", "只恐奴此身，死也没人埋，公公，谁还你恩债？(合前)。"]'),
('yuanqu-5129','凤凰阁','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','寻鸿觅雁，寄个音书无便。',40,'元曲/yuanqu.json','["寻鸿觅雁，寄个音书无便。", "谩劳回首望家山，和那白云不见。", "泪痕如线，想镜里孤鸾影单。"]'),
('yuanqu-5130','一封书','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','一从你去离，我家中常念你。',82,'元曲/yuanqu.json','["一从你去离，我家中常念你。", "是么，我也常想家里。", "功名事怎的？想多应折桂枝。", "我功名事成了。", "幸得爹娘和媳妇，各保安康无祸危。", "且喜家中安乐。", "见家书，可知之，及早回来莫更迟。"]'),
('yuanqu-5131','下山虎','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','蔡邕百拜，大人尊前：一自离膝下，顿觉数年。',77,'元曲/yuanqu.json','["蔡邕百拜，大人尊前：一自离膝下，顿觉数年。", "目断家山，镇长望悬。", "一向那堪音信断，名利事叹牵绾，谩空劳珠泪涟。", "上表辞金殿，要辞了官，争奈君王不见怜。", "(又唱)。"]'),
('yuanqu-5132','蛮牌令','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','忽尔拜尊翰，极切慰拳拳。',56,'元曲/yuanqu.json','["忽尔拜尊翰，极切慰拳拳。", "喜爹娘和媳妇，尽安康。", "况儿身淹留在此，不能勾承奉慈颜。", "匆匆的聊附寸笺，草草伏乞尊照不宣。"]'),
('yuanqu-5133','驻马听','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','书寄乡关，说起教人心痛酸。',81,'元曲/yuanqu.json','["书寄乡关，说起教人心痛酸。", "你传示俺八旬爹妈，道与我两月妻房，隔涉万水千山。", "啼痕缄外翠绡斑，梦魂飞绕银屏远，(合)报道平安，想一家贺喜，只说道他日再相见。", "(末唱)。"]'),
('yuanqu-5134','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','遥忆乡关，有个人人凝望眼。',58,'元曲/yuanqu.json','["遥忆乡关，有个人人凝望眼。", "他频看飞雁，望断归舟，倚遍危阑。", "见这银钩飞动彩云笺，又索玉箸界破残妆面。", "(合前)(净唱)。"]'),
('yuanqu-5135','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','西出阳关，却叹今朝行路难。',62,'元曲/yuanqu.json','["西出阳关，却叹今朝行路难。", "念取经年离别，带着一纸云笺。", "跋涉程途，只怕豺狼纷绕路途间，又怕雁鸿不到你家乡畔。", "(合前)(末唱)。"]'),
('yuanqu-5136','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','满纸云烟，说尽离愁千万千。',56,'元曲/yuanqu.json','["满纸云烟，说尽离愁千万千。", "想那层楼十二，有个人人，倚着危阑。", "他望归期，数飞雁，阻关山，见书如见经年面。", "(合前)。"]'),
('yuanqu-5137','挂真儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','四顾青山静悄悄，思量起暗里魂消。',33,'元曲/yuanqu.json','["四顾青山静悄悄，思量起暗里魂消。", "黄土伤心，丹枫染泪，谩把孤坟自造。"]'),
('yuanqu-5138','菩萨蛮','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','白杨萧瑟悲风起，天寒日淡空山里。',115,'元曲/yuanqu.json','["白杨萧瑟悲风起，天寒日淡空山里。", "虎啸与猿啼，愁人添惨凄。", "穷泉深杳杳，长夜何由晓。", "洒泪泣双亲，双亲闻不闻？奴家自丧了公婆，谁相扶助？到如今免不得造一所坟，把公婆葬了。", "又无钱雇人，又无人得央靠，只得独自搬泥运土。", "(罗裙包土介)(唱)。"]'),
('yuanqu-5139','五更传','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','把土泥独抱，罗裙裹来难打熬。',116,'元曲/yuanqu.json','["把土泥独抱，罗裙裹来难打熬。", "空山静寂无人吊，但我情真实切，到此不惮劳。", "苦！何曾见葬亲儿不到？又道是三匝围丧，那些个卜其宅兆？思量起，是老亲合颠倒。", "公公，你图他折桂看花早，不道自把一身，送在白杨衰草。", "谩自苦，(介)这苦凭谁告？(介)。"]'),
('yuanqu-5140','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我只凭十爪，如何能勾坟上高？(介)只见鲜血淋漓湿衣袄，苦！我形衰力倦，死也只这遭。',115,'元曲/yuanqu.json','["我只凭十爪，如何能勾坟上高？(介)只见鲜血淋漓湿衣袄，苦！我形衰力倦，死也只这遭。", "休休！骨头葬处任他流血好，此唤作骨血之亲，也教人称道。", "教人道：赵五娘亲行孝。", "苦！心穷力尽形枯槁，只有这鲜血，到如今也出了。", "这坟成后，只怕我的身难保。"]'),
('yuanqu-5141','卜算先','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','坟土未曾高，筋力还先倦。',17,'元曲/yuanqu.json','["坟土未曾高，筋力还先倦。", "(睡介)。"]'),
('yuanqu-5142','粉蝶儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','赵女堪悲，天教小神相济。',12,'元曲/yuanqu.json','["赵女堪悲，天教小神相济。"]'),
('yuanqu-5143','好姐姐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','五娘听分付与：吾特奉玉皇敕旨，怜伊孝心故遣我来助你。',52,'元曲/yuanqu.json','["五娘听分付与：吾特奉玉皇敕旨，怜伊孝心故遣我来助你。", "(净丑合唱)坟成矣。", "葬了二亲寻夫婿，改换衣装往帝畿。"]'),
('yuanqu-5144','卜算后','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','梦里分明有鬼神，想是天怜念。',14,'元曲/yuanqu.json','["梦里分明有鬼神，想是天怜念。"]'),
('yuanqu-5145','五更传','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','怨苦知多少？两三人只道同做饿莩。',152,'元曲/yuanqu.json','["怨苦知多少？两三人只道同做饿莩。", "公公，婆婆，我待不葬了你，又不了；待葬了你，穷泉一闭无日晓，叹从今永别，再无由相倚靠。", "我死和你做一处埋呵，也得相伏事。", "只愁我死在他途道，我的骨头，何由来到？从今去，这坟呵，只愿得中干燥，福孙荫子也都难料；便荫得个三公，也济不得亲老。", "泪暗滴，把苍天祷。", "(末同丑带锄器上唱)。"]'),
('yuanqu-5146','铧锹儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','悲风四起吹松柏，山云惨淡日无色。',43,'元曲/yuanqu.json','["悲风四起吹松柏，山云惨淡日无色。", "猿啼与虎啸。", "怎不惨戚！趱步行来到峭壁，都与孝妇添助力。"]'),
('yuanqu-5147','好姐姐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','念奴流血满指，奈独自要坟成无计，深感老天暗中相护持。',54,'元曲/yuanqu.json','["念奴流血满指，奈独自要坟成无计，深感老天暗中相护持。", "(合)坟成矣。", "葬了二亲寻夫婿，改换衣装往帝畿。", "(末唱)。"]'),
('yuanqu-5148','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我每方将小二，待欲与你添助力气，谁知有神暗中救济。',34,'元曲/yuanqu.json','["我每方将小二，待欲与你添助力气，谁知有神暗中救济。", "(合前)(丑唱)。"]'),
('yuanqu-5149','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你每真个见鬼，这松柏孤坟在何处？恰才小鬼是我妆做的。',31,'元曲/yuanqu.json','["你每真个见鬼，这松柏孤坟在何处？恰才小鬼是我妆做的。", "(合前)。"]'),
('yuanqu-5150','临江仙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','玉作人间秋万顷，银葩点破琉璃。',39,'元曲/yuanqu.json','["玉作人间秋万顷，银葩点破琉璃。", "(贴)瑶台风露冷仙衣，天香飘下处，此景有谁知？。"]'),
('yuanqu-5151','生查子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','逢人曾寄书，书去神亦去。',24,'元曲/yuanqu.json','["逢人曾寄书，书去神亦去。", "今夜好清光，可惜人千里。"]'),
('yuanqu-5152','酹江月','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','玉楼绛气，卷霞绡云浪寒光澄澈。',137,'元曲/yuanqu.json','["玉楼绛气，卷霞绡云浪寒光澄澈。", "丹桂飘香清思爽，人在瑶台银阙。", "(生)影透空帏，光窥罗帐，露冷蛩声切。", "关山今夜，照人几处离别。", "(净)须信离合悲欢，还如玉兔，有阴晴圆缺。", "便做人生长宴会，几见冰轮皎洁？(丑)此夜明多，隔生期远，莫放金樽歇。", "(合)但愿人长久，年年同赏明月。", "(贴唱)。"]'),
('yuanqu-5153','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','孤影，南枝乍冷，见乌鹊缥缈惊飞，栖止不定。',67,'元曲/yuanqu.json','["孤影，南枝乍冷，见乌鹊缥缈惊飞，栖止不定。", "万点苍山，何处是，修竹吾庐三径？追省，丹桂留扳，嫦娥相爱，故人千里谩同情。", "(合前)(贴唱)。"]'),
('yuanqu-5154','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','愁听，吹笛关山，敲砧门巷，月中都是断肠声。',64,'元曲/yuanqu.json','["愁听，吹笛关山，敲砧门巷，月中都是断肠声。", "人去远，几见明月亏盈。", "惟应，边塞征人，深闺思妇，怪他偏向别离明。", "(合前)(净丑合唱)。"]'),
('yuanqu-5155','古轮台','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','峭寒生，鸳瓮瓦冷玉壶冰，阑干露湿人犹凭，贪看玉镜。',107,'元曲/yuanqu.json','["峭寒生，鸳瓮瓦冷玉壶冰，阑干露湿人犹凭，贪看玉镜。", "况万里清冥，皓彩十分端正。", "三五良宵，此时独胜。", "(丑)把清光都付与酒杯倾，从教酩酊，拚夜深沉醉还醒。", "酒阑绮席，漏催银箭，香消金鼎。", "斗转与参横，银河耿，辘轳声已断金井。"]'),
('yuanqu-5156','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','闲评，月有圆缺与阴晴，人世有离合悲欢，从来不定。',113,'元曲/yuanqu.json','["闲评，月有圆缺与阴晴，人世有离合悲欢，从来不定。", "深院闲庭，处处清光相映。", "也有得意人人，两情畅咏；也有独守长门伴孤冷，君恩不幸。", "(丑)有广寒仙子娉婷，孤眠长夜，如何捱得，更阑寂静？此事果无凭，但愿人长永，小楼看月共同登。", "(合)。"]'),
('yuanqu-5157','余文','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','声哀诉促织鸣，(贴)俺这里欢娱未听。',18,'元曲/yuanqu.json','["声哀诉促织鸣，(贴)俺这里欢娱未听。"]'),
('yuanqu-5158','胡捣练','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','辞别去，到荒丘，只愁出路煞生受。',32,'元曲/yuanqu.json','["辞别去，到荒丘，只愁出路煞生受。", "画取真容聊藉手，逢人将此免哀求。"]'),
('yuanqu-5159','三仙桥','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','一从他每死后，要相逢不能勾。',115,'元曲/yuanqu.json','["一从他每死后，要相逢不能勾。", "除非梦里，暂时略聚首。", "若要描，描不就，暗想象，教我未写先泪流。", "写，写不得他苦心头；描，描不出他饥证候；画，画不出他望孩儿的睁睁两眸。", "只画得他发飕飕，和那衣衫敝垢。", "休休，若画做好容颜，须不是赵五娘的姑舅。"]'),
('yuanqu-5160','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我待画你个庞儿带厚，你可又饥荒消瘦。',170,'元曲/yuanqu.json','["我待画你个庞儿带厚，你可又饥荒消瘦。", "我待画你个庞儿展舒，你自来长恁皱。", "若写出来，真是丑，那更我心忧，也做不出他欢容笑口。", "不是我不画着好的，我从嫁来他家，只见两月稍优游，他其余都是愁。", "那两月稍优游。", "可又忘了。", "这三四年间，我只记得他形衰貌朽。", "这画呵，便做他孩儿收，也认不得是当初父母。", "休休，纵认不得是蔡伯喈当初爹娘，须认得是赵五娘近日来的姑舅。"]'),
('yuanqu-5161','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','公公，婆婆，非是我寻夫远游，只怕你公婆绝后。',136,'元曲/yuanqu.json','["公公，婆婆，非是我寻夫远游，只怕你公婆绝后。", "奴见夫便回，此行安敢久。", "苦！路途中，奴怎走？望公婆，相保佑我出外州；(介)苦！他骨肉自没人倚恃，他如何来相保佑？这坟呵，只怕奴家去后，冷清清有谁来拜扫？纵使遇春秋，一陌银钱怎有？休休，生是受冻馁的公婆，死做个绝祭祀的孤魂么姑舅。"]'),
('yuanqu-5162','鹧鸪天','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','娘子，死别多应梦里逢，谩劳孝妇写遗踪。',85,'元曲/yuanqu.json','["娘子，死别多应梦里逢，谩劳孝妇写遗踪。", "可怜不得图家庆，辜负丹青泣画工。", "衣破损，鬓蓬松，千愁万恨在眉峰。", "蔡郎不识年来面，赵女空描别后容。", "我听得你远行，有几贯钱与你添做盘缠。"]'),
('yuanqu-5163','忆多娇','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他魂渺漠，我身没倚着。',53,'元曲/yuanqu.json','["他魂渺漠，我身没倚着。", "程途万里，教我怀夜壑。", "此去孤坟，望公公看着。", "(合)举目消索，满眼盈盈泪落。", "(末唱)。"]'),
('yuanqu-5164','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','承委托，当领略。',38,'元曲/yuanqu.json','["承委托，当领略。", "孤坟我自看守，决不爽约。", "只愿你途中身安乐。", "(合前)(旦唱)。"]'),
('yuanqu-5165','斗黑麻','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','奴深谢公公，便辱许诺。',71,'元曲/yuanqu.json','["奴深谢公公，便辱许诺。", "从来的深恩，怎敢忘却！只怕途路远，体怯弱；病染孤身，力衰倦脚。", "(合)孤坟寂寞，路途滋味恶。", "两处堪悲，万愁怎摸？(末唱)。"]'),
('yuanqu-5166','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','伊夫婿多应是，贵官显爵。',54,'元曲/yuanqu.json','["伊夫婿多应是，贵官显爵。", "伊家去，须当市个好恶。", "只怕你这般乔打扮，他怎知觉？一贵一贫，怕他将错就错。", "(合前)。"]'),
('yuanqu-5167','菊花新','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','封书自远到亲闱，又见关河朔雁飞。',30,'元曲/yuanqu.json','["封书自远到亲闱，又见关河朔雁飞。", "梧叶满庭除，还如我闷怀堆积。"]'),
('yuanqu-5168','生查子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','封书寄远人，寄与万里亲。',97,'元曲/yuanqu.json','["封书寄远人，寄与万里亲。", "书去神亦去，兀然空一身。", "自家昨得家书，报道家中平安，极切自喜。", "当时亦付一书回去。", "不知如何？常怀想念，番成忧闷。", "正是：虽无千丈线，万里系人心。", "好闷！(介)(坐)(贴上喜)。"]'),
('yuanqu-5169','意难忘','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','绿鬓仙郎，懒拈花弄柳，劝酒持觞。',40,'元曲/yuanqu.json','["绿鬓仙郎，懒拈花弄柳，劝酒持觞。", "长颦知有恨，何事苦思量？(生唱)些介事，恼人肠。"]'),
('yuanqu-5170','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','相公，莫不是丈人行性气乖？(生)不是。',153,'元曲/yuanqu.json','["相公，莫不是丈人行性气乖？(生)不是。", "(贴)莫不是妾根前缺管待？(生)不是。", "(贴)莫不是画堂中少了三千客？(生)不是。", "(贴)莫不是绣屏前少了十二钗？(生)那里是？不是。", "(介)(贴)又不是。", "这意儿教人怎猜？这意儿教人怎解？(介)我今番猜着了，敢只是楚馆秦楼有一个得意情人也，闷恹恹不放怀？(生)不是。", "(唱)。"]'),
('yuanqu-5171','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','有个人人在天一涯，我不能勾见他，只落得脸销红眉锁黛。',39,'元曲/yuanqu.json','["有个人人在天一涯，我不能勾见他，只落得脸销红眉锁黛。", "(贴)我道什么来？却又是。"]'),
('yuanqu-5172','西地锦','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','好怪吾家门婿，镇日不展愁眉。',29,'元曲/yuanqu.json','["好怪吾家门婿，镇日不展愁眉。", "教人心下常萦系，也只为着门楣。"]'),
('yuanqu-5173','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','只道儿夫何意，如今事理方知。',31,'元曲/yuanqu.json','["只道儿夫何意，如今事理方知。", "万里家山要同归去，不审爹意何如？。"]'),
('yuanqu-5174','狮子序','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他媳妇须有之，念奴须是，他孩儿的妻。',40,'元曲/yuanqu.json','["他媳妇须有之，念奴须是，他孩儿的妻。", "那曾有媳妇不事亲帏？(外)你去有甚么勾当？。"]'),
('yuanqu-5175','太平歌','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他求科举，指望锦衣归，不想道你留他为女婿。',39,'元曲/yuanqu.json','["他求科举，指望锦衣归，不想道你留他为女婿。", "(外)有缘千里能相会，须强他不得，。"]'),
('yuanqu-5176','赏宫花','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他终朝惨凄，我如何忍见之？(外)他自伤悲，你须不曾。',41,'元曲/yuanqu.json','["他终朝惨凄，我如何忍见之？(外)他自伤悲，你须不曾。", "(贴)若论为夫妇，须是共欢娱。"]'),
('yuanqu-5177','降黄龙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','须知，非是奴痴迷，已嫁从夫。',176,'元曲/yuanqu.json','["须知，非是奴痴迷，已嫁从夫。", "怎违公议？(外)你去不妨，只是我没亲的人，如何放你去得？(贴)爹犹念女，怎教他爹娘不念孩儿？(外)不是我不放你去，既道有媳妇在家里，你去时节，只恐怕担阁了你。", "(贴)休提，纵把奴担阁，比担阁他的爹娘何如？(外)恁地，教伯喈自去便了。", "(贴)爹爹。", "那些个，夫唱妇随，嫁鸡逐鸡飞？(外)孩儿，他是贫贱之家，你如何伏事他家？(贴唱)。"]'),
('yuanqu-5178','大圣乐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','婚姻事难论高低，论高低何如休嫁与。',89,'元曲/yuanqu.json','["婚姻事难论高低，论高低何如休嫁与。", "假如亲贱孩儿贵，终不然便抛弃？(外)他的孩儿撇不得，你怕甚么？(贴)奴是他亲生儿子亲媳妇，难道他是何人我是谁？(外)你怎地只管把言语来冲撞我？。"]'),
('yuanqu-5179','称人心','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','撇呆打堕，早被那人瞧破，要同归知爹肯么？料他每，不见许。',64,'元曲/yuanqu.json','["撇呆打堕，早被那人瞧破，要同归知爹肯么？料他每，不见许。", "(介)夫人，你缘何独坐？想你爹爹不肯么？伊家道俐齿伶牙，争奈你爹行不可。"]'),
('yuanqu-5180','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我爹爹，全不怕，人笑呵，这其间只是见差。',54,'元曲/yuanqu.json','["我爹爹，全不怕，人笑呵，这其间只是见差。", "祸根芽，从此起，灾来怎躲？他只道我从着夫言，骂我不听亲话。", "(生唱)。"]'),
('yuanqu-5181','红衫儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你不信我教伊休说破，到此如何？算你爹心性，我岂不料过。',63,'元曲/yuanqu.json','["你不信我教伊休说破，到此如何？算你爹心性，我岂不料过。", "我为甚胡掩胡遮？只为着这些。", "你直待要打破了砂锅，是你招灾揽祸。", "(贴唱)。"]'),
('yuanqu-5182','醉太平','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','蹉跎，光阴易谢。',73,'元曲/yuanqu.json','["蹉跎，光阴易谢。", "纵归来已晚，归计无暇。", "名牵利锁，奔走在海角天涯。", "知么？多应我老死在京华，孝情事一笔都勾罢。", "这般摧锉，伤情万感，泪珠偷随。", "(贴唱)。"]'),
('yuanqu-5183','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','非诈，奴甘死也。',70,'元曲/yuanqu.json','["非诈，奴甘死也。", "纵奴不死时，君去须不可。", "奴身值甚么？只因奴误你一家。", "差讹，假饶做夫妇也难和，我心怨你心萦挂。", "奴此身拚舍，成伊孝名，救伊爹妈。"]'),
('yuanqu-5184','月云高','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','路途劳倦，行行甚时近？未到得洛阳县，那盘缠使尽。',70,'元曲/yuanqu.json','["路途劳倦，行行甚时近？未到得洛阳县，那盘缠使尽。", "回首孤坟，空教我望孤影。", "他那里谁秋采？俺这里将谁投奔？正是西出阳关无故人，须信道家贫不是贫。"]'),
('yuanqu-5185','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','暗叫思忖，此去好无准。',76,'元曲/yuanqu.json','["暗叫思忖，此去好无准。", "只怕他身荣贵，把咱不队。", "若是他不瞧，可不空教我受艰辛？没，他未必忘恩。", "我这坦自闲评论，他须记一夜夫妻百夜恩，怎做得区区陌路上人？。"]'),
('yuanqu-5186','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','只是一件，他在府堂深隐，奴身怎生进？他在驷马高车下，我又难将他认。',85,'元曲/yuanqu.json','["只是一件，他在府堂深隐，奴身怎生进？他在驷马高车下，我又难将他认。", "我有个道理，来到他根前，只提起他二亲真。", "又怕消瘦庞儿。", "他尤难十分信。", "他不到得非亲却是亲，我自须防人不仁。"]'),
('yuanqu-5187','番下算','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','儿女话难听，使我心疑惑。',26,'元曲/yuanqu.json','["儿女话难听，使我心疑惑。", "暗中思忖觉前非，有个团圆策。"]'),
('yuanqu-5188','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','泪眼滴如珠，愁事萦如织。',26,'元曲/yuanqu.json','["泪眼滴如珠，愁事萦如织。", "早知今日悔当初，何似休明白。"]'),
('yuanqu-5189','四边静','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你去陈留子细询端的，专心去寻觅。',59,'元曲/yuanqu.json','["你去陈留子细询端的，专心去寻觅。", "请过两三人，途中须好承直。", "(合)休忧怨忆，寄书咫尺。", "眼望旌捷旗，耳听好消息。", "(生唱)。"]'),
('yuanqu-5190','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','饥荒散乱无踪迹，存亡想不测。',35,'元曲/yuanqu.json','["饥荒散乱无踪迹，存亡想不测。", "何意路途间，难禁这劳役。", "(合前)(贴唱)。"]'),
('yuanqu-5191','福马郎','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','李旺，你休说新婚在牛氏宅。',73,'元曲/yuanqu.json','["李旺，你休说新婚在牛氏宅。", "(外)孩儿，说便又待怎地？(贴)他须怨我相耽误；归未得，旁人闻，把奴责。", "(合)若是到京国，相逢处作个好筵席。", "(丑唱)，。"]'),
('yuanqu-5192','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','多与盘缠添气力，万水千山路，曾惯历。',87,'元曲/yuanqu.json','["多与盘缠添气力，万水千山路，曾惯历。", "(拜介)辞却恩官去，免忧忆。", "(合前)(外白)限伊半载望回音。", "(生贴)路上看承须小心。", "(丑)但愿应时还得见，(合)果然胜似岳阳金。", "(并下)。"]'),
('yuanqu-5193','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','途路上，实难捱。',44,'元曲/yuanqu.json','["途路上，实难捱。", "盘缠都尽了，好狼狈。", "试把瑟琶拨，逢人乞丐。", "荐公婆魂魄免沉埋，特来赴佛会。"]'),
('yuanqu-5194','销金帐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','听奴诉与：奴是良人妇，为儿夫相耽误。',81,'元曲/yuanqu.json','["听奴诉与：奴是良人妇，为儿夫相耽误。", "一向赴选及第，未归乡故。", "饥荒丧了，丧了亲的舅姑，我造坟墓。", "今为寻夫来此。", "(净丑白)你儿夫在那里？(旦唱)寻夫未知，在何处所？。"]'),
('yuanqu-5195','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','凡人养子，最是十月怀耽苦，更三年劳役抱负。',72,'元曲/yuanqu.json','["凡人养子，最是十月怀耽苦，更三年劳役抱负。", "休言他受湿推干，万千劳事。", "真个千般爱惜，千般爱护。", "儿有些不安，父母忧惶无措。", "直待他可了，可了欢忻似初。"]'),
('yuanqu-5196','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','儿行几步，父母欢相顾，渐能言能出路。',65,'元曲/yuanqu.json','["儿行几步，父母欢相顾，渐能言能出路。", "指望饮食羹汤，自朝及暮。", "悬悬望他，知他几度？为择良师，又怕孩儿愚鲁。", "略得他长俊，可便欢忻赏赐。"]'),
('yuanqu-5197','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','朝经暮史，教子勤诗赋，为春闱催教赴。',66,'元曲/yuanqu.json','["朝经暮史，教子勤诗赋，为春闱催教赴。", "指望他耀祖荣亲，改换门户。", "悬悬望他，望他腰金衣紫。", "儿在程途，又怕餐凤宿露。", "求神问卜，把归期暗数。"]'),
('yuanqu-5198','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','儿还念父母，及早归乡土，念慈乌亦能返哺。',70,'元曲/yuanqu.json','["儿还念父母，及早归乡土，念慈乌亦能返哺。", "莫学我的儿夫，把亲耽误。", "常言养子，养子方知父慈。", "算五逆儿男，和孝顺爹娘之子，若无报应，果是乾坤有私。"]'),
('yuanqu-5199','缕缕金','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','时不利，命何乖！双亲在途路上，怕他灾。',53,'元曲/yuanqu.json','["时不利，命何乖！双亲在途路上，怕他灾。", "(末丑唱)此是弥陀寺，略停车盖。", "(合)办虔心恳祷拜莲台，特来赴佛会。"]'),
('yuanqu-5200','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','能吃酒，会口童斋。',47,'元曲/yuanqu.json','["能吃酒，会口童斋。", "吃得醺醺醉，便去搂新戒。", "讲经和回向，全然尴尬。", "你官人若是有文才，休来看佛会。"]'),
('yuanqu-5201','江儿水','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','如来证明，鉴兹邕启：我双亲在途路不知如何的？仰惟菩萨大慈悲。',56,'元曲/yuanqu.json','["如来证明，鉴兹邕启：我双亲在途路不知如何的？仰惟菩萨大慈悲。", "(合)龙天鉴知，龙天护持，护持他赞山渡水。", "(净唱)。"]'),
('yuanqu-5202','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','如来证明，览兹情音。',37,'元曲/yuanqu.json','["如来证明，览兹情音。", "蔡邕的父母掣相保庇。", "仰惟功德不思议。", "(合前)(末唱)。"]'),
('yuanqu-5203','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我东人尽日，常怀忧虑。',39,'元曲/yuanqu.json','["我东人尽日，常怀忧虑。", "只愁二亲在途路里，孝思情意真个感神祗。", "(合前)(丑唱)。"]'),
('yuanqu-5204','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我闻知做会，特来随喜。',34,'元曲/yuanqu.json','["我闻知做会，特来随喜。", "馒头素食多多与，若还不与我自入斋厨。", "(合前)。"]'),
('yuanqu-5205','缕缕金','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','原来是，蔡伯喈。',46,'元曲/yuanqu.json','["原来是，蔡伯喈。", "马前那喝道，状元来。", "料想双亲象，他每留在。", "敢天教。", "夫妇再和谐，都因这佛会？。"]'),
('yuanqu-5206','十二时','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','心事无靠托，这几日番成悲也。',41,'元曲/yuanqu.json','["心事无靠托，这几日番成悲也。", "父意方回，夫愁稍可。", "未卜程途里的如何，教我怎生放下？。"]'),
('yuanqu-5207','绕池游','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','凤餐水卧，甚日能安妥？问天天怎生结果？(贴介唱)梳妆淡雅，看风措堪描堪画。',45,'元曲/yuanqu.json','["凤餐水卧，甚日能安妥？问天天怎生结果？(贴介唱)梳妆淡雅，看风措堪描堪画。", "是何人教来问咱。"]'),
('yuanqu-5208','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','嗟呀，心忧貌苦，真情怎假？你为着公婆珠泪堕，姑姑，我公婆自有，不能勾承奉杯茶。',84,'元曲/yuanqu.json','["嗟呀，心忧貌苦，真情怎假？你为着公婆珠泪堕，姑姑，我公婆自有，不能勾承奉杯茶。", "姑姑，你比我没个公婆得承奉呵，不枉了教人做话靶。", "我且问伊咱：你公婆，为甚的双双命掩黄沙？。"]'),
('yuanqu-5209','啭林萦','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','荒年万般遭坎坷，丈夫又在京华。',69,'元曲/yuanqu.json','["荒年万般遭坎坷，丈夫又在京华。", "糟糠暗吃担饥饿，公婆死卖头发去埋他。", "把孤坟自造，土泥尽是我罗裙包裹。", "也非夸，手指伤。", "血痕尚在衣罗。", "(贴唱)。"]'),
('yuanqu-5210','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','愁人见说愁转多，使我珠泪如麻。',97,'元曲/yuanqu.json','["愁人见说愁转多，使我珠泪如麻。", "我丈夫亦久别双亲下，他要辞官被我爹蹉跎。", "(旦介)他家有谁？(贴)他妻虽有么，怕不似恁着承爹妈。", "(旦)如今在那里？夫人。", "(贴)在天涯，谩去取，知他路上如何？(旦唱)。"]'),
('yuanqu-5211','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','错中错，讹上讹，只管来鬼门前空占卦。',40,'元曲/yuanqu.json','["错中错，讹上讹，只管来鬼门前空占卦。", "夫人，若要识蔡伯喈的妻房，(贴)他在那里？。"]'),
('yuanqu-5212','金衣公子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','一样做浑家，我安然伊受祸，你名为孝妇我吃旁人骂。',72,'元曲/yuanqu.json','["一样做浑家，我安然伊受祸，你名为孝妇我吃旁人骂。", "公死为我，婆死为我，情愿把你孝衣来穿着把浓妆罢。", "(合)事多磨，冤家到此，逃不得这波查。", "(旦唱)。"]'),
('yuanqu-5213','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他当原也没奈何，被强将来赴选科，辞爹爹不肯听他话。',58,'元曲/yuanqu.json','["他当原也没奈何，被强将来赴选科，辞爹爹不肯听他话。", "(贴)辞官不可，辞婚不可。", "(合)三不从做成灾社祸天来大。", "(合前)。"]'),
('yuanqu-5214','天下乐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','一片花飞故苑空，随凤飘泊到帘栊。',32,'元曲/yuanqu.json','["一片花飞故苑空，随凤飘泊到帘栊。", "玉人怪问惊春梦，只怕东风羞落红。"]'),
('yuanqu-5215','醉扶归','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我钉缘结发曾相共，难道是无缘对面不相逢？我凤枕驾衾也和他同，到凭兔毫茧纸将他功。',61,'元曲/yuanqu.json','["我钉缘结发曾相共，难道是无缘对面不相逢？我凤枕驾衾也和他同，到凭兔毫茧纸将他功。", "休休，毕竟一齐分付与东风，把往事也如春梦。"]'),
('yuanqu-5216','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','彩笔墨润鸾封重，只为五箫声断凤楼空。',99,'元曲/yuanqu.json','["彩笔墨润鸾封重，只为五箫声断凤楼空。", "这牛氏夫人，也怕我蓝缕上头，怕伯喈不相认，我须带孝来。", "还是教妾若为容？我不写诗打动蔡伯喈呵，只怕为你难移宠。", "(介)纵认不得这丹青怕他貌不同，他若认我翰墨教心先痛。"]'),
('yuanqu-5217','鹊桥仙','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','披香随宴，上林游赏，醉后人扶马上。',33,'元曲/yuanqu.json','["披香随宴，上林游赏，醉后人扶马上。", "金莲花炬照回廊，正院宇梅梢月上。"]'),
('yuanqu-5218','解三酲','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','叹双亲把儿指望，教儿读古老文章。',85,'元曲/yuanqu.json','["叹双亲把儿指望，教儿读古老文章。", "比我会读书的到把亲撇漾，少甚么不识字的到得终养。", "书，我只为你其中自有黄金屋，却教我撇却椿庭萱草堂。", "还思想，休休，毕竟是文章误我，我误爹娘。"]'),
('yuanqu-5219','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','比似我做了亏心台馆客，到不如守义终身田舍郎。',85,'元曲/yuanqu.json','["比似我做了亏心台馆客，到不如守义终身田舍郎。", "白头吟记得不曾忘，绿鬓妇何故在他方？书，我只为你其中有女颜如玉，却教我撇却糟糠妻下堂。", "还思想，休休，毕竟是文章误我，我误妻房。"]'),
('yuanqu-5220','太师引','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','细端详，这是谁笔仗？觑着他教我心儿好感伤。',127,'元曲/yuanqu.json','["细端详，这是谁笔仗？觑着他教我心儿好感伤。", "(细看介)好似我双亲模佯。", "没，我看我媳妇会针指生活，便做我的爹娘呵，怎穿着破损衣裳？他前日书道，别后容颜无恙，怎这般凄凉形状？谅着我要寄一封书，不能勾到，谁往来直将到洛阳？天下少甚么厮象的，须知仲尼和阳虎一般庞。"]'),
('yuanqu-5221','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我理会得了：这是街坊，谁劣相，砌庄家形衰貌黄。',118,'元曲/yuanqu.json','["我理会得了：这是街坊，谁劣相，砌庄家形衰貌黄。", "比我爹娘呵，若没一个媳妇相傍，少不得也这般凄凉。", "(心动介)敢是神图佛象？更不是，却怎地我正看间，猛可的小鹿儿心头撞？这也不是神佛样子，敢是当原画的不是了。", "丹青匠山他主张，须知汉毛延寿误正嫱。"]'),
('yuanqu-5222','夜游湖','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','惟恐他心思未到，教他题诗句暗中指挑。',36,'元曲/yuanqu.json','["惟恐他心思未到，教他题诗句暗中指挑。", "翰墨开心，丹青入眼，强如把语言相告。"]'),
('yuanqu-5223','铧锹儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你说得好笑，可见心儿窄小。',100,'元曲/yuanqu.json','["你说得好笑，可见心儿窄小。", "我决不学那黄允的，没来由漾却苦李，再寻甜桃。", "古人云：弃妻有七出之条，他不嫉不淫与不盗，终无去条。", "你道那弃妻的，众所诮；那不弃妻的，人所褒。", "纵然他丑貌，怎肯相休去了？(贴唱)。"]'),
('yuanqu-5224','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','虽然如此，伊家富贵，那更青春年少。',76,'元曲/yuanqu.json','["虽然如此，伊家富贵，那更青春年少。", "看你紫袍着体，金带垂腰。", "做你的媳妇呵，应须有封号，金花紫诰。", "必俊倬，须媚娇。", "若还他丑貌，相公，怎不相休去了？(生唱)。"]'),
('yuanqu-5225','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你言颠语倒，恼得我心儿焦燥。',88,'元曲/yuanqu.json','["你言颠语倒，恼得我心儿焦燥。", "呵呵，莫不是你把咱奚落，特骨的妆乔？引得我泪痕交，扑簌簌这遭。", "夫人，题诗的是谁？(贴)你待怎地？(生)他把我嘲，难恕饶。", "说与我知道，怎肯干休住了？。"]'),
('yuanqu-5226','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我心中忖料，想不是个薄情分晓。',98,'元曲/yuanqu.json','["我心中忖料，想不是个薄情分晓。", "管教分夫妇会合，定在今朝。", "相公，你认得题诗的人么？(生)我不认得。", "(贴)伊家枉然焦，骨自未瞧。", "这题诗的呵，是伊大嫂，身姓赵。", "正要说与你知道，怎肯干休住了？(旦上唱)。"]'),
('yuanqu-5227','赚','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','听得闹炒，敢是我儿夫看诗罗唣。',125,'元曲/yuanqu.json','["听得闹炒，敢是我儿夫看诗罗唣。", "(贴)姐姐出来。", "(旦)是谁忽叫姐姐？料想是夫人召，必有分剖。", "(贴介唱)是他题诗你还认得否？(生)夫人，他却那里来？(贴)他从陈留为你来寻讨。", "(生认介唱)是你怎地穿着破袄；衣衫尽是素缟？呀！莫是我的，双亲不保？(旦介唱)。"]'),
('yuanqu-5228','前腔换头','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','从别后，遭水旱，(生)是水旱来。',16,'元曲/yuanqu.json','["从别后，遭水旱，(生)是水旱来。"]'),
('yuanqu-5229','山桃红','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','蔡邕不孝，把父母相抛。',108,'元曲/yuanqu.json','["蔡邕不孝，把父母相抛。", "爹爹，妈妈，我与别时，也不恁地。", "早知你形衰耄，怎留汉朝？娘子，你为我受烦恼，你为我受劬劳。", "谢你送我爹，送我娘，你的恩难报也！又道养子能代老。", "(合)这苦知多少，此恨怎消？天降灾殃人怎逃？(旦唱)。"]'),
('yuanqu-5230','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','仪容想象，是我亲描。',77,'元曲/yuanqu.json','["仪容想象，是我亲描。", "教化把琵琶拨，怎禁路遥？丈夫，说甚么受烦恼？说甚么受劬劳？不信看你爹，看你娘，比别时尚兀自形枯槁也。", "我的一身难打熬。", "(合前)(贴唱)。"]'),
('yuanqu-5231','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','说着圈套，被我爹相招。',78,'元曲/yuanqu.json','["说着圈套，被我爹相招。", "逼为东床婿，怎行孝道？姐姐。", "你为我受波查，你为我路途遥。", "丈夫，是我误你爹，误你娘，误你名为不孝也。", "做不得妻贤夫祸少。", "(合前)(生唱)。"]'),
('yuanqu-5232','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','捋却巾帽，解却衣袍。',75,'元曲/yuanqu.json','["捋却巾帽，解却衣袍。", "(旦)你急上辞官表，只这两朝。", "(贴)丈夫，我岂敢惮烦恼？岂敢惮劬劳？归去拜你爹，拜你娘，亲把坟茔扪也。", "与地下亡魂添荣耀。", "(合前)。"]'),
('yuanqu-5233','尾声','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','几年分别无音耗，奈千山万水迢遥。',27,'元曲/yuanqu.json','["几年分别无音耗，奈千山万水迢遥。", "只为三不从生出这祸苗。"]'),
('yuanqu-5234','虞美人','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','青山今古何时了，断送人多少！孤坟谁与扫苍苔？邻冢阴风吹送纸钱来。',32,'元曲/yuanqu.json','["青山今古何时了，断送人多少！孤坟谁与扫苍苔？邻冢阴风吹送纸钱来。"]'),
('yuanqu-5235','玉楼春','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','冥冥长夜不知晓，寂寂空山几度秋。',77,'元曲/yuanqu.json','["冥冥长夜不知晓，寂寂空山几度秋。", "泉下长眠人醒未，悲风萧瑟起松楸。", "老汉曾蒙赵五娘之所托，教我与他看管这坟台。", "这几日有些贫冗，不及来看。", "呀！怎地？(末介唱)。"]'),
('yuanqu-5236','步步娇','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','只见黄叶飘飘把坟头复。',82,'元曲/yuanqu.json','["只见黄叶飘飘把坟头复。", "(逐介)厮赶的皆狐兔。", "(望介)敢是谁斫了木头，怎地松楸渐渐疏？(滑倒介)苔把砖封，笋迸着泥路。", "休休，罢罢，只恐你难保百年坟，教凭谁看你三尺土。"]'),
('yuanqu-5237','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','渡水登山多劳苦，到得这荒村坞。',46,'元曲/yuanqu.json','["渡水登山多劳苦，到得这荒村坞。", "远观见一老夫，试问他家，住在何处。", "趱步向前行，却是一所荒坟墓。"]'),
('yuanqu-5238','风入松','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你不须提起蔡伯喈，说他每哏歹！。',16,'元曲/yuanqu.json','["你不须提起蔡伯喈，说他每哏歹！。"]'),
('yuanqu-5239','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','一从他别后遇荒灾，更无人倚赖。',15,'元曲/yuanqu.json','["一从他别后遇荒灾，更无人倚赖。"]'),
('yuanqu-5240','犯衮','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他公婆的亲看见，双双死，无钱送，剪头发卖买棺材。',88,'元曲/yuanqu.json','["他公婆的亲看见，双双死，无钱送，剪头发卖买棺材。", "(丑)他那般无钱，如何筑一所坟台？(末)他左空山里，把裙包上，血流指，感得神明助与他筑坟台。", "(丑)这小娘子如今在那里？(末唱)。"]'),
('yuanqu-5241','风入松','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','他如今直往帝京来。',179,'元曲/yuanqu.json','["他如今直往帝京来。", "(丑)他把甚么做盘缠？(末)他弹着琵琶做乞丐。", "(丑)苦！蔡相公特教我来取，老员外、老安人又都死了，小娘子却又去了，交我空走了这一遭。", "(末叫介)老员外、老安人，你孩儿做官，教人来取你。", "苦！叫他不应魂何在？空教我珠泪盈腮。", "(丑)我如今回去，教相公多做些功果，追荐他便了。", "(末笑介)他生不能事，死不能葬，葬不能祭，这三不孝逆天罪大，空打醮枉修斋。"]'),
('yuanqu-5242','犯朝','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','你如今便回，道张老的道与蔡伯喈。',16,'元曲/yuanqu.json','["你如今便回，道张老的道与蔡伯喈。"]'),
('yuanqu-5243','风入松','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','原来他也只是无奈，恁地好似鬼使神差。',60,'元曲/yuanqu.json','["原来他也只是无奈，恁地好似鬼使神差。", "便是他当原在家辞赴选，他父母也不从他，这是三不从把他厮禁害。", "恁的呵，三不孝亦非其罪。"]'),
('yuanqu-5244','风入松慢','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','女萝松柏望相依，况景入桑榆。',45,'元曲/yuanqu.json','["女萝松柏望相依，况景入桑榆。", "他椿庭萱室齐倾弃，怎不想家山桃李？中雀误看屏里，乘龙难驻门楣。"]'),
('yuanqu-5245','光光乍','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','女婿要同归，岳丈意何如？忽叫奴家缘何的？想必与他作区处。',28,'元曲/yuanqu.json','["女婿要同归，岳丈意何如？忽叫奴家缘何的？想必与他作区处。"]'),
('yuanqu-5246','女冠子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','媳妇事舅姑合体例，怎不教女孩儿同去？当初是相公相留住，今日里怨着谁？(外)我不教女孩儿同去，又待怎地？(净)事须近理，怎挟威势？休道朝中太师威如火，更有路上行人',102,'元曲/yuanqu.json','["媳妇事舅姑合体例，怎不教女孩儿同去？当初是相公相留住，今日里怨着谁？(外)我不教女孩儿同去，又待怎地？(净)事须近理，怎挟威势？休道朝中太师威如火，更有路上行人口似碑。", "(合)想起，此事费人区处。", "(末唱)。"]'),
('yuanqu-5247','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我相公只虑多娇女，怕跋涉万山千水。',79,'元曲/yuanqu.json','["我相公只虑多娇女，怕跋涉万山千水。", "相公，女生向外从来语，况既已做人妻。", "夫唱妇随，不须疑虑。", "相公，这是蓝田种玉结亲误，今日里到海，沉船补漏迟。", "(合前)(外唱)。"]'),
('yuanqu-5248','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','当初是我不仔细，谁知道事成差池？念深闺幼女多娇媚，怎跋涉万余里？我嫡亲有谁，怎生分离？休休，不教爱女扭烦恼，也被旁人道是非。',62,'元曲/yuanqu.json','["当初是我不仔细，谁知道事成差池？念深闺幼女多娇媚，怎跋涉万余里？我嫡亲有谁，怎生分离？休休，不教爱女扭烦恼，也被旁人道是非。"]'),
('yuanqu-5249','五供养','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','终朝垂泪，为双亲教我心疼。',62,'元曲/yuanqu.json','["终朝垂泪，为双亲教我心疼。", "(贴)坟头须共守，只得离宸京。", "(生)商量个计策，犹恐你爹心不肯。", "(合)若是他不从，只说道君王有命。"]'),
('yuanqu-5250','催拍','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','念伯喈为双亲命倾，遭不孝逆天罪名，今辞了汉廷。',63,'元曲/yuanqu.json','["念伯喈为双亲命倾，遭不孝逆天罪名，今辞了汉廷。", "感岳丈深恩，非敢忘情。", "欲待不归，又负他亡灵。", "(合)辞别去同到坟茔，心戚戚泪盈盈。"]'),
('yuanqu-5251','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','念奴家离乡背井，谢相公教孩儿共行。',56,'元曲/yuanqu.json','["念奴家离乡背井，谢相公教孩儿共行。", "非独故里荣，我阴世公婆，死也目瞑。", "我自看待你孩儿，不须可咛。", "(合前)(外唱)。"]'),
('yuanqu-5252','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','辞别去你的吉凶未凭，再来时我的存亡未明。',63,'元曲/yuanqu.json','["辞别去你的吉凶未凭，再来时我的存亡未明。", "伯喈，吾今已老景。", "毕竟你没爹娘，我没亲生。", "若念骨肉一家，须早办回程。", "(合前)(贴唱)。"]'),
('yuanqu-5253','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','觑着爹颜衰鬓星，痛点点教别泪暗零。',56,'元曲/yuanqu.json','["觑着爹颜衰鬓星，痛点点教别泪暗零。", "爹爹，我左难右难：误了公婆，被人讥评；撇了亲爹，又没人看承。", "(合前)(生唱)。"]'),
('yuanqu-5254','一撮棹','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','宽心等，何须苦牵萦？(外)把音书写，但频频寄邮亭。',83,'元曲/yuanqu.json','["宽心等，何须苦牵萦？(外)把音书写，但频频寄邮亭。", "(贴)老姥姥，爹年老，我去呵，伊家须好看承。", "(合)程途里，只愿保安宁。", "死别全无准，生离又难定。", "今去也，何日到京城？。"]'),
('yuanqu-5255','哭相思','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','最苦生离难拚舍，知他别再会何时也？(并下)。',22,'元曲/yuanqu.json','["最苦生离难拚舍，知他别再会何时也？(并下)。"]'),
('yuanqu-5256','柳穿鱼','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','心忙似箭走如飞，历尽艰辛有谁知？夜静水寒鱼不食，满船空载月明归。',48,'元曲/yuanqu.json','["心忙似箭走如飞，历尽艰辛有谁知？夜静水寒鱼不食，满船空载月明归。", "归来后到庭除，未知相公在何处？。"]'),
('yuanqu-5257','玩仙灯','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','门外有人声，是谁来喧哗闹炒？。',15,'元曲/yuanqu.json','["门外有人声，是谁来喧哗闹炒？。"]'),
('yuanqu-5258','风帖儿','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','到得陈留，逢一个故老，在他每爹娘坟上拜扫。',54,'元曲/yuanqu.json','["到得陈留，逢一个故老，在他每爹娘坟上拜扫。", "他爹娘呵，果然饥荒都死了；他媳妇，也来到；枉教人走这遭。", "(外唱)。"]'),
('yuanqu-5259','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我如今去，朝廷上表，说蔡氏一门孝道。',43,'元曲/yuanqu.json','["我如今去，朝廷上表，说蔡氏一门孝道。", "管取吾皂降丹诏，加封号，把他召。", "我自去陈留走一遭。"]'),
('yuanqu-5260','梅花引','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','伤心满目故人疏，看郊墟尽荒芜。',54,'元曲/yuanqu.json','["伤心满目故人疏，看郊墟尽荒芜。", "(旦贴上唱)惟有青山，添得个坟墓。", "(合)恸哭无由长夜晓，问泉下有人还听得无？。"]'),
('yuanqu-5261','玉雁子','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','孩儿相误，为功名相误了父母。',87,'元曲/yuanqu.json','["孩儿相误，为功名相误了父母。", "都是孩儿不得归乡故，怎便归到黄土？爹爹，妈妈，乾坤岂容不孝子？名亏行缺不如死，呀！只愁我死缺祭祀。", "(合)对真容形哀貌枯，想灵魂悲忆痛苦。", "(贴唱)。"]'),
('yuanqu-5262','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','不孝的媳妇，恨当初担阁我夫。',84,'元曲/yuanqu.json','["不孝的媳妇，恨当初担阁我夫。", "吃人笑谈生何补？我待死呵，又羞见公姑。", "公公，婆婆，我生前未能相奉事，何如事你向黄泉路？只一件，我死呵，家中老父，教谁看顾？(合前)(旦唱)。"]'),
('yuanqu-5263','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','今来庐墓，望双亲相与保扶。',65,'元曲/yuanqu.json','["今来庐墓，望双亲相与保扶。", "(旦介)亲还有灵歆受此，望恕我儿夫。", "呀！空劳死后没祭祀，何如在日供喉嗉？知他享么？知他居何所？(合前)。"]'),
('yuanqu-5264','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','楼台银铺，遍青山犹如画图。',69,'元曲/yuanqu.json','["楼台银铺，遍青山犹如画图。", "乾坤似你衰素，添个缟带飞舞。", "你擗踊痛哭直恁苦，那堪雪片添凄楚。", "休恁地哭，且逆来顺受么。", "抑情就理通今古。", "(合前)。"]'),
('yuanqu-5265','玉山供','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','公公尊赐，念天寒特来问吾。',40,'元曲/yuanqu.json','["公公尊赐，念天寒特来问吾。", "公公，我双亲受三载饥寒，我怎不禁一日凄楚？(末)请请。"]'),
('yuanqu-5266','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','劳公尊步，念天寒特来问奴。',63,'元曲/yuanqu.json','["劳公尊步，念天寒特来问奴。", "(末)夫人，请请。", "(贴)公公，这里是冢上坟间，比不得暖阁红炉。", "这般天气呵，谁人将护？将护我家中亲父。"]'),
('yuanqu-5267','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','钗荆裙布，谢得公公诸般应副。',55,'元曲/yuanqu.json','["钗荆裙布，谢得公公诸般应副。", "叹奴身未得报深恩，如今再蒙相顾。", "非奴独感德，我爹娘也衔恩在阴府。", "(合前)(末唱)。"]'),
('yuanqu-5268','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','人生如朝露，论生死荣枯有定数。',53,'元曲/yuanqu.json','["人生如朝露，论生死荣枯有定数。", "相公，休只管恸哭爹娘，也须要继承宗祖。", "况腰金背紫，不枉了光荣门户。", "(合前)。"]'),
('yuanqu-5269','刘衮','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','乘驿骑，乘驿骑，陈留去开旨。',64,'元曲/yuanqu.json','["乘驿骑，乘驿骑，陈留去开旨。", "(净丑上唱)略请行轩，到此少住。", "(外)唯，此间是何处？住此还怎地？(净丑)此间站里，待将鞍马来换取。"]'),
('yuanqu-5270','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','闻知道，闻知道，相公忽来至。',41,'元曲/yuanqu.json','["闻知道，闻知道，相公忽来至。", "喏！不及迎接，万乞罪恕。", "(外)不索要讲礼，疾忙与分例。"]'),
('yuanqu-5271','逍遥乐','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','寂寞谁怜我，空对孤坟将泪堕。',41,'元曲/yuanqu.json','["寂寞谁怜我，空对孤坟将泪堕。", "(合)光阴拈指过三春，幽魂渺渺，夜府沉沉，谁与招魂？。"]'),
('yuanqu-5272','六么令','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','连枝异木，见这坟台，兔走如驯。',56,'元曲/yuanqu.json','["连枝异木，见这坟台，兔走如驯。", "禽虫草木尚怀仁，这一封诏，必因君。", "(合)料天也会相怜悯，料天也会相怜悯。", "(生唱)。"]'),
('yuanqu-5273','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','皇恩若念臣，我也不图，禄及吾身。',41,'元曲/yuanqu.json','["皇恩若念臣，我也不图，禄及吾身。", "只愁恩不到双亲，空孤负，这孤坟。", "(合前)(旦唱)。"]'),
('yuanqu-5274','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','知他假和真？谢得公公，报说殷勤。',39,'元曲/yuanqu.json','["知他假和真？谢得公公，报说殷勤。", "公公，空教你为我受艰辛，今日有谁，旌表你门庭。"]'),
('yuanqu-5275','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','来的是甚人？闷中无由，一声询问。',16,'元曲/yuanqu.json','["来的是甚人？闷中无由，一声询问。"]'),
('yuanqu-5276','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','敕书已来近，闹得街坊上，人乱纷纷。',38,'元曲/yuanqu.json','["敕书已来近，闹得街坊上，人乱纷纷。", "我每听得便忙奔，办香案，接皇恩。", "(合前)。"]'),
('yuanqu-5277','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','风霜满鬓，玉勒雕鞍，走遍红尘。',36,'元曲/yuanqu.json','["风霜满鬓，玉勒雕鞍，走遍红尘。", "今日到此喜忻忻，重相见，解愁闷。", "(合前)。"]'),
('yuanqu-5278','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','心荒步紧，想着皇恩，已到寒门。',36,'元曲/yuanqu.json','["心荒步紧，想着皇恩，已到寒门。", "披袍秉笏更垂绅，冠和帔，一番新。", "(合前)。"]'),
('yuanqu-5279','一封书','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','我亲奉帝旨，涉程途千万里。',71,'元曲/yuanqu.json','["我亲奉帝旨，涉程途千万里。", "念亲亲的意美，探这孩儿并女婿。", "孩儿，数载艰辛虽自苦，一旦荣华人怎知？(合)耀门闾，进官职，孝义名传天下知。", "(生唱)。"]'),
('yuanqu-5280','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','儿不孝有甚德？蒙岳父特主维。',55,'元曲/yuanqu.json','["儿不孝有甚德？蒙岳父特主维。", "呀！何如免丧亲，又何须名显贵？可惜二亲饥寒死，博换得孩儿名利归。", "(合前)(旦唱)。"]'),
('yuanqu-5281','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','把真容再画取，如今日封赠伊。',56,'元曲/yuanqu.json','["把真容再画取，如今日封赠伊。", "把这眉头放展舒，只愁瘦容难做肥。", "岂特奴心知感德，料他也衔恩泉世里。", "(合前)(贴唱)。"]'),
('yuanqu-5282','前腔','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','从别后痛哀戚，况家中音信稀。',57,'元曲/yuanqu.json','["从别后痛哀戚，况家中音信稀。", "为公姑多怨忆，为爹行又长垂泪。", "本见公姑无愧色，又得与爹行相倚依。", "(合前)(末净丑唱)。"]'),
('yuanqu-5283','永团圆','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','名传四海人怎比？岂独是耀门闾？人生怕不全孝义，圣明世岂相弃。',88,'元曲/yuanqu.json','["名传四海人怎比？岂独是耀门闾？人生怕不全孝义，圣明世岂相弃。", "这隆恩美誉，从教管领何所愧，万古青编记。", "如今便去，相随到京畿。", "拜谢君恩了，归庭宇，一家贺喜。", "共设华筵会，四景常欢聚。"]'),
('yuanqu-5284','尾声','高明《蔡伯喈琵琶记》','元','元曲','yuanqu','','[]','显文明开盛治，□说孝男并义女。',25,'元曲/yuanqu.json','["显文明开盛治，□说孝男并义女。", "玉烛调和，圣主垂衣。"]'),
('yuanqu-5285','南吕・一枝花隐居','胡用和','元','元曲','yuanqu','','[]','左右依两壁山，横竖盖三间屋。',63,'元曲/yuanqu.json','["左右依两壁山，横竖盖三间屋。", "高低田五六亩，周围柳数十株。", "活计萧疏，偏容俺闲人物。", "两般儿亲自取：不用买江上风生，谁要请天边月出。"]'),
('yuanqu-5286','梁州第七・兴到也吟诗数首，懒来时静坐观书。消闲几个知心侣：负薪樵','胡用和','元','元曲','yuanqu','','[]','子，执钓渔夫，烹茶石鼎，沽酒葫芦。',92,'元曲/yuanqu.json','["子，执钓渔夫，烹茶石鼎，沽酒葫芦。", "崎岖山几里平途，萧疏景无半点尘俗。", "染秋光红叶黄花，铺月色清风翠竹，起风声老树苍梧。", "有如，画图。", "闲中自有闲中趣，看乌兔自来去，百岁光阴迅指无，甲子须臾。"]'),
('yuanqu-5287','尾声・矮窗低屋随缘度，土炕蒲团乐有余，散诞逍遥少荣辱。嗟吁叹吁，','胡用和','元','元曲','yuanqu','','[]','心足意足，伴着这松竹梅花做宾主。',16,'元曲/yuanqu.json','["心足意足，伴着这松竹梅花做宾主。"]'),
('yuanqu-5288','中吕・粉蝶儿题金陵景','胡用和','元','元曲','yuanqu','','[]','万里翱翔，太平年四方归向，定乾坤万国来降。',50,'元曲/yuanqu.json','["万里翱翔，太平年四方归向，定乾坤万国来降。", "谷丰登，民安乐，鼓腹讴唱。", "读书人幸遇尧唐，五云楼九重天上。"]'),
('yuanqu-5289','醉春风・宫殿紫云浮，江上清气爽。把京都佳致略而间讲，讲。景物稀奇，','胡用和','元','元曲','yuanqu','','[]','凤城围绕，士民高尚。',10,'元曲/yuanqu.json','["凤城围绕，士民高尚。"]'),
('yuanqu-5290','朱履曲・论富贵京都为上，数繁华海内无双，风流人物貌堂堂。云山迷远','胡用和','元','元曲','yuanqu','','[]','树，雪浪涌长江，暮追欢朝玩赏。',15,'元曲/yuanqu.json','["树，雪浪涌长江，暮追欢朝玩赏。"]'),
('yuanqu-5291','魔合罗・东南佳丽山河壮，助千古京都气象，人稠物穰景非常，真乃是鱼','胡用和','元','元曲','yuanqu','','[]','龙变化之乡。',42,'元曲/yuanqu.json','["龙变化之乡。", "山形盘踞藏龙虎，台榭崔巍落凤凰。", "堪崇尚，载编简累朝盛士，撼乾坤万代传扬。"]'),
('yuanqu-5292','十一煞・景阳台名尚存，周处台姓且香，拜郊台古迹钟山上。乌龙潭雨至','胡用和','元','元曲','yuanqu','','[]','风雷起，白鹭洲潮回烟水茫，雨花台曾有天花降。',38,'元曲/yuanqu.json','["风雷起，白鹭洲潮回烟水茫，雨花台曾有天花降。", "跃马涧烟笼曙色，钓鱼台月漾波光。"]'),
('yuanqu-5293','十煞・南北乾道桥，东西锦绣乡，四时歌管长春巷。峥嵘高阁侵云表，奇','胡用和','元','元曲','yuanqu','','[]','观层楼接上苍，清溪阁烟波荡，忠勤楼风云福地，尊经阁诗礼文场。',30,'元曲/yuanqu.json','["观层楼接上苍，清溪阁烟波荡，忠勤楼风云福地，尊经阁诗礼文场。"]'),
('yuanqu-5294','九煞・朝天宫道友多，天界寺僧众广，天禧寺古塔霞光放。三山香火年年','胡用和','元','元曲','yuanqu','','[]','盛，十庙英灵世世昌，宝宁寺一境多幽况，鸡鸣山烟笼佛寺，神乐观云拥仙乡。',35,'元曲/yuanqu.json','["盛，十庙英灵世世昌，宝宁寺一境多幽况，鸡鸣山烟笼佛寺，神乐观云拥仙乡。"]'),
('yuanqu-5295','七煞・山围龙虎国，城连锦绣乡，四时美景宜欢赏。春风桃李参差吐，夏','胡用和','元','元曲','yuanqu','','[]','日榴花取次芳，秋天菊绽冬梅放。',31,'元曲/yuanqu.json','["日榴花取次芳，秋天菊绽冬梅放。", "歌岁稔风调雨顺，庆丰年国泰民康。"]'),
('yuanqu-5296','六煞・到春来观音寺赏牡丹，拥翠园玩海棠，逍遥西圃名园广。怕花残朝','胡用和','元','元曲','yuanqu','','[]','朝携妓歌《金缕》，恐春去日日邀朋饮玉浆，有百千处堪游赏。',50,'元曲/yuanqu.json','["朝携妓歌《金缕》，恐春去日日邀朋饮玉浆，有百千处堪游赏。", "泛轻舟桃叶渡观山玩水，跨蹇驴杏花庄拾翠寻芳。"]'),
('yuanqu-5297','五煞・到夏来清凉寺暑气无，赏心亭夏日长，石头城烟雨风生浪。秦淮河','胡用和','元','元曲','yuanqu','','[]','急水龙舟渡，马公洞薰风菡萏香，翠微亭绿阴深处炎威爽。',42,'元曲/yuanqu.json','["急水龙舟渡，马公洞薰风菡萏香，翠微亭绿阴深处炎威爽。", "仪凤楼满窗江月，建龙关四壁山光。"]'),
('yuanqu-5298','四煞・到秋来玄武湖碧水澄，青龙山翠色苍，携壶策杖登高赏。崇因寺内','胡用和','元','元曲','yuanqu','','[]','芙蓉绽，普照庵中桂子香，家家庭院秋砧响。',36,'元曲/yuanqu.json','["芙蓉绽，普照庵中桂子香，家家庭院秋砧响。", "水波涛江横白露，雁初飞菊吐新黄。"]'),
('yuanqu-5299','三煞・到冬来助江天雪正飞，撼楼台风力狂，喜的是红炉画阁羊羔酿。霎','胡用和','元','元曲','yuanqu','','[]','时间银砌就钱婆岭，顷刻处玉妆成石子岗。',38,'元曲/yuanqu.json','["时间银砌就钱婆岭，顷刻处玉妆成石子岗。", "动弦管声嘹亮，庆太平有象，贺丰稔时光。"]'),
('yuanqu-5300','二煞・遗图古迹多，今朝事业昌，太平风景真佳况。诗人有意题难足，胜','胡用和','元','元曲','yuanqu','','[]','境无穷咏未详。',24,'元曲/yuanqu.json','["境无穷咏未详。", "曾到处闲中想，莺花世界，诗酒排场。"]'),
('yuanqu-5301','一煞・陈钧佐才俊高，藏彦弘笔力强，缪唐臣慢调偏宜唱。章浩德能吟翰','胡用和','元','元曲','yuanqu','','[]','苑清诗句，谷子敬惯捏梨园新乐章，陈清简善画真容像，卢仲敬品玉箫寰中第一，冷起敬操瑶琴世上无双。',47,'元曲/yuanqu.json','["苑清诗句，谷子敬惯捏梨园新乐章，陈清简善画真容像，卢仲敬品玉箫寰中第一，冷起敬操瑶琴世上无双。"]'),
('yuanqu-5303','小石调・青杏儿','赵秉文','元','元曲','yuanqu','','[]','风雨替花愁，风雨过花也应休。',37,'元曲/yuanqu.json','["风雨替花愁，风雨过花也应休。", "劝君莫惜花前醉，今朝花谢，明朝花谢，白了人头。"]'),
('yuanqu-5304','幺・乘兴两三瓯，拣溪山好处追游。但教有酒身无事，有花也好，无花也','赵秉文','元','元曲','yuanqu','','[]','好，选甚春秋。',7,'元曲/yuanqu.json','["好，选甚春秋。"]'),
('yuanqu-5305','商角调・黄莺儿','庾吉甫','元','元曲','yuanqu','','[]','怀古，怀古，废兴两字，干弋疑虑戈几度？问当时富贵谁家？陈宫后主。',32,'元曲/yuanqu.json','["怀古，怀古，废兴两字，干弋疑虑戈几度？问当时富贵谁家？陈宫后主。"]'),
('yuanqu-5306','踏莎行・残照底西风老树，据秦淮终是帝王都。爱山围水绕，龙蟠虎踞。','庾吉甫','元','元曲','yuanqu','','[]','依稀睹，六朝风物。',9,'元曲/yuanqu.json','["依稀睹，六朝风物。"]'),
('yuanqu-5307','盖天旗・光阴迅速，多半晴天变雨。待拣搭溪山好处，吞一杯，嚎数曲。','庾吉甫','元','元曲','yuanqu','','[]','身有欢娱，事无荣辱。',10,'元曲/yuanqu.json','["身有欢娱，事无荣辱。"]'),
('yuanqu-5308','应天长・引一仆，着两壶。谢老东山，黄花时好去。适意林泉游未足。烟','庾吉甫','元','元曲','yuanqu','','[]','波暮，堪凝伫，谪仙诗句。',12,'元曲/yuanqu.json','["波暮，堪凝伫，谪仙诗句。"]'),
('yuanqu-5309','尾・一线寄乌衣，二水分白鹭。台上凤凰游，井口胭脂污。想玉树后庭花，','庾吉甫','元','元曲','yuanqu','','[]','好金陵建康府。',36,'元曲/yuanqu.json','["好金陵建康府。", "怀古，怀古，物换千年，星移几度。", "想当时帝子元婴，阎公都督。"]'),
('yuanqu-5310','踏莎行・彩射龙光，云埋铁柱。迷津烟暗，渡水平湖。高士词堂，旌阳殿','庾吉甫','元','元曲','yuanqu','','[]','洪恩路，藕花无数。',9,'元曲/yuanqu.json','["洪恩路，藕花无数。"]'),
('yuanqu-5311','盖天旗・残碑淋雨，留得王郎佳句。信步携筇，登临闲伫。雁惊寒，衡阳','庾吉甫','元','元曲','yuanqu','','[]','秋水长天，落霞孤鹜。',10,'元曲/yuanqu.json','["秋水长天，落霞孤鹜。"]'),
('yuanqu-5312','应天长・东接吴，南甸楚。绀坞荒村，苍烟古木。俯挹遥岑伤未足。夕阳','庾吉甫','元','元曲','yuanqu','','[]','暮，空无语，昔人何处？。',12,'元曲/yuanqu.json','["暮，空无语，昔人何处？。"]'),
('yuanqu-5313','尾・孤塔插晴空，高阁临江渚。栋飞南浦云，帘卷西山雨。观胜概，壮江','庾吉甫','元','元曲','yuanqu','','[]','山，叹鸣銮，罢歌舞。',41,'元曲/yuanqu.json','["山，叹鸣銮，罢歌舞。", "别况无语，无语，闷人怕到，江天日暮。", "大都来一种相思，柔肠万缕。"]'),
('yuanqu-5315','垂丝钓・求神问卜，道须有团圆一处。奈目下佳期，未得相逢愁最苦。正','庾吉甫','元','元曲','yuanqu','','[]','值着秋光，暮天凄楚。',10,'元曲/yuanqu.json','["值着秋光，暮天凄楚。"]'),
('yuanqu-5316','应长天・愁成阵，更压着宋玉。便是铁石人，也今宵耽不去。早是栖惶能','庾吉甫','元','元曲','yuanqu','','[]','对付。',18,'元曲/yuanqu.json','["对付。", "难禁处，凄凉景，窗儿外眼撮聚。"]'),
('yuanqu-5317','随煞・起一阵菊花风，下几点芭蕉雨。风送得菊花香，雨打得芭蕉絮。芭','庾吉甫','元','元曲','yuanqu','','[]','焦雨敌庭梧，菊花风战槛竹。',13,'元曲/yuanqu.json','["焦雨敌庭梧，菊花风战槛竹。"]'),
('yuanqu-5318','商调・定风波思情','庾吉甫','元','元曲','yuanqu','','[]','迤秋来到，正露冷风寒，微雨初收，凉风儿透冽襟袖。',39,'元曲/yuanqu.json','["迤秋来到，正露冷风寒，微雨初收，凉风儿透冽襟袖。", "自别来愁万感，遣离情不堪回首。"]'),
('yuanqu-5319','金菊香・到秋来还有许多忧，一寸心怀无限愁，离情镇日如病酒。似这等','庾吉甫','元','元曲','yuanqu','','[]','恹恹，终不肯断了风流。',11,'元曲/yuanqu.json','["恹恹，终不肯断了风流。"]'),
('yuanqu-5320','凤鸾吟・题起来羞，这相思何日休，好姻缘不到头。饮几盏闷酒，醉了时','庾吉甫','元','元曲','yuanqu','','[]','罢手，则怕酒醒了时还依旧。',36,'元曲/yuanqu.json','["罢手，则怕酒醒了时还依旧。", "我为他使尽了心，他为我添消瘦，都一般减了风流。"]'),
('yuanqu-5321','醋葫芦・人病久，何日休，思情欲待罢无由。哎！你个多情你可便怎下的','庾吉甫','元','元曲','yuanqu','','[]','辜负！子我知伊主意，料应来倚仗着脸儿羞。',20,'元曲/yuanqu.json','["辜负！子我知伊主意，料应来倚仗着脸儿羞。"]'),
('yuanqu-5322','尾声・本待要弃舍了你个冤家，别寻一个玉人儿成配偶。你道是强似你那','庾吉甫','元','元曲','yuanqu','','[]','模样儿的呵，说道我也不能够。',31,'元曲/yuanqu.json','["模样儿的呵，说道我也不能够。", "我道来胜似你心肠儿的呵，到处里有。"]'),
('yuanqu-5323','关云长千里独行・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','我则怕他用心机，敢可兀的铺谋定计。',92,'元曲/yuanqu.json','["我则怕他用心机，敢可兀的铺谋定计。", "我想这曹操是那智足奸雄，信着俺小叔莽戆多英勇。", "(带云)主公，哎！(唱)你则合操士马教三军明堤备破曹兵，则怕他排队伍暗伏兵，则要你得胜也把他这干戈来定。"]'),
('yuanqu-5324','关云长千里独行・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','俺可便奔走东西，气冲两肋，心生计。',66,'元曲/yuanqu.json','["俺可便奔走东西，气冲两肋，心生计。", "恨不的插翅如飞，飞不出剑洞枪林内。", "(小旦云)姐姐，玄德公信着三叔叔的计策，全不是了也。", "(正旦唱)。"]'),
('yuanqu-5325','关云长千里独行・混江龙','无名氏','元','元曲','yuanqu','','[]','谁想这徐州失利，送的俺弟兄姊妹两分离。',127,'元曲/yuanqu.json','["谁想这徐州失利，送的俺弟兄姊妹两分离。", "闪杀我也仁慈的玄德，送了我也莽撞张飞。", "本来也无战争平白的起战争，你正是得便宜翻做了落便宜。", "(小旦云)姐姐，你见么，兀的城头上不是二叔叔云长也。", "(正旦唱)我这里猛抬头见二叔叔在城头上立，曹丞相倚强压弱，俺如今受困遭危。"]'),
('yuanqu-5326','关云长千里独行・油葫芦','无名氏','元','元曲','yuanqu','','[]','则俺这兄弟张飞谁近的，他端的有见识，使一条点钢枪敢与万人敌，他便安排着打凤捞龙计，谁着他便搜寻出劫寨偷营智。',118,'元曲/yuanqu.json','["则俺这兄弟张飞谁近的，他端的有见识，使一条点钢枪敢与万人敌，他便安排着打凤捞龙计，谁着他便搜寻出劫寨偷营智。", "(小旦云)姐姐，玄德定计，曹操他怎生便知道来？(正旦唱)曹丞相暗地里，他可早先准备。", "打了个拷栳圈围在垓心内，人和马怎生走不能飞。"]'),
('yuanqu-5327','关云长千里独行・天下乐','无名氏','元','元曲','yuanqu','','[]','可正是船到江心补漏迟，(关末云)嫂嫂，如今曹丞相要招安我，我不降他来，则怕曹丞相伤害着你性命也。',659,'元曲/yuanqu.json','["可正是船到江心补漏迟，(关末云)嫂嫂，如今曹丞相要招安我，我不降他来，则怕曹丞相伤害着你性命也。", "(正旦云)叔叔，俺可打甚么不紧也。", "(正旦唱)则这曹也波贼，恐害着你。", "(关末云)我想哥哥兄弟之情，我怎生归降他？(正旦唱)你若是不归降他怒从心上起。", "一壁厢统着士卒，一壁厢探着阵势，(云)叔叔，你若不肯投降，曹丞相将俺这三房头家小，叫声杀坏了。", "(唱)你那其间敢眼睁睁怎近得。", "(关末云)嫂嫂，我待投降来，想俺兄弟三人，对天盟誓，一在三在，一亡三亡；我若不降来，这三房家小，见在曹营，倘若有些好歹呵，如之奈何？(张辽云)二将军你见么？你这三房头家小，都在俺曹营。", "你若不降呵，这三房头家小，怎生了也？(关末云)张文远，你说与你那曹丞相，他若依我三桩事，我便投降。", "(张辽云)二将军，你但言的事，俺丞相都依着。", "(关末云)我头一桩，我虽然投降，我可不降你丞相，我是降汉不降曹；第二桩。", "我和俺哥哥兄弟家属，一宅分两院；第三桩，我若打听的俺哥哥兄弟信息，我便寻去，可不许您拦当。", "你说去。", "(张辽云)我知道。", "丞相，云长投降，叫丞相依他三桩事，他便降。", "(曹末云)那三桩事？(张辽云)头一桩，他降汉不降曹；第二桩，他和他嫂嫂家小一宅分两院；第三桩，他但是打听的他哥哥兄弟信息，他便去寻去。", "(曹末云)这其间知道他那哥哥兄弟有也无，都依的他。", "开了门，我和他厮见，咱。", "(张辽云)二将军，俺丞相都依了也。", "你开门和俺丞相厮见咱。", "(关末云)小校，开了城门。", "(曹末云)俺入的这城来。", "张文远，教他那三房头老小，与他厮见咱。", "(张辽云)理会的。", "请两个夫人与二将军厮见咱。"]'),
('yuanqu-5328','关云长千里独行・金盏儿','无名氏','元','元曲','yuanqu','','[]','刀剑-时催，弓弩似电光飞。',189,'元曲/yuanqu.json','["刀剑-时催，弓弩似电光飞。", "伏兵四面一齐起，饶你有通天武艺，怎施威。", "骤征马宛寻家计，插翅走如飞。", "他可甚鞭敲金镫响，人和凯歌回。", "(曹末与关末相见科)(曹末云)云长，一别许久也。", "则今日咱便往京师，见了圣人，将你重重赐赏加官。", "一壁厢准备车乘，老小每上车。", "(关末云)嫂嫂，您上车儿先行。", "(正旦云)多谢叔叔。", "(关末云)嫂嫂，关羽不敢。", "(小旦云)姐姐，若不是二叔叔，俺岂有今日也。", "(正旦唱)。"]'),
('yuanqu-5329','关云长千里独行・尾声','无名氏','元','元曲','yuanqu','','[]','今日个救出我这乱军中，不枉了结义在桃园内。',119,'元曲/yuanqu.json','["今日个救出我这乱军中，不枉了结义在桃园内。", "救了俺这姊妹残生顷刻，俺便似太山般一家儿倚靠着你。", "从今后照顾您这亲戚，则今后信音稀，要见他容易，则除是一枕南柯梦儿里。", "谁想我与玄德公厮离，俺可也是关着前世，玄德公也正是要便宜翻做落便宜。", "(同下)。"]'),
('yuanqu-5330','关云长千里独行・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','今日个难除我腹内忧，怎解我眉间皱。',113,'元曲/yuanqu.json','["今日个难除我腹内忧，怎解我眉间皱。", "我可也心怀家国恨，则我这眉锁他这个庙堂愁。", "我可便有信难投，眼睁睁无人救，今日个这凄凉何日休。", "(小旦云>当日都是三叔叔张飞的不是了也。", "(正旦唱)你当日逞英雄与曹操做敌头，则被他倒空营俺着他机彀。"]'),
('yuanqu-5331','关云长千里独行・梁州','无名氏','元','元曲','yuanqu','','[]','则俺这姊妹淹留在许昌，则被那兄弟每失散在徐州。',513,'元曲/yuanqu.json','["则俺这姊妹淹留在许昌，则被那兄弟每失散在徐州。", "(小旦云)姐姐，俺想玄德公何日相见也？(正旦唱)我想这英雄玄德仁慈厚，他端的忠直慷慨，壮志难酬，豁达大度，纳谏如流。", "我这里扑簌簌泪满星眸，俺可便看他何日乐矣忘忧。", "我、我、我折倒的骨捱捱身似柴蓬，是、是、是俺可也病恹恹黄干黑瘦，呀、呀、呀俺可便每口家绿惨红愁。", "怎生做个解忧？半生勤苦干生受。", "俺叔叔花也成蜜也就，可便地久天长怎了救？(小旦云)姐姐省烦恼。", "俺好歹有一日见玄德公也。", "(正旦唱)好教我无了无休。", "(正旦云)妹子，俺这里闲攀着话，看有甚么人来。", "(关末上，云)欢来不似今朝，喜来那逢今日。", "关羽也，我恰才本无酒，我听的那厮说我哥哥兄弟在古城，我故意推醉。", "来到这宅中，有俺嫂嫂逐日烦恼，他则说俺哥哥兄弟不见，每日思念。", "谁想哥哥兄弟，如今见在古城。", "我如今到于嫂嫂宅中，我且不说哥哥兄弟还有哩，我则推醉，看他说甚么。", "报复去，道有关羽在于门首。", "(报复科)(正旦云)呀，既然二叔叔来了也，叔叔请坐。", "(关末推醉科，云)嫂嫂，关羽不必坐。", "好酒也，我醉了也。", "(正旦云)妹子，你看俺二叔叔好快活也。", "(关末云)我怎么不快活？我如今封官为寿亭侯，每日筵宴管待，正好受用也。", "(正旦云)叔叔你的是也。", "(唱)。"]'),
('yuanqu-5332','关云长千里独行・红芍药','无名氏','元','元曲','yuanqu','','[]','你道是新来加你做寿亭侯，(关末云)我上马一提金，下马一提银。',150,'元曲/yuanqu.json','["你道是新来加你做寿亭侯，(关末云)我上马一提金，下马一提银。", "(正旦唱)枉受了些肥马轻裘。", "这的是你桃园结义下场头，枉了宰白马杀乌牛。", "(关末云)我三日一小宴，五日一大宴。", "(正旦唱)你每日吃堂食饮御酒，你全不记往日的冤仇。", "想着您同行同坐数年秋，到如今一笔哎都勾！(关末云)我如今官封为寿亭侯哩。", "(正旦唱)。"]'),
('yuanqu-5333','关云长千里独行・菩萨梁州','无名氏','元','元曲','yuanqu','','[]','今日个你建节来封侯，登时间忘旧。',137,'元曲/yuanqu.json','["今日个你建节来封侯，登时间忘旧。", "知书的小叔，你可便枉看了些《左传》《春秋》。", "我这里听言说罢泪交流，弟兄今日难相守，甚日个得完就。", "准想你结义宾朋不到头，则他这岁月淹留。", "(关末云)我将这条凳椅桌都打碎了，幔帐纱橱都扯掉了。", "(正旦云)叔叔烦恼了也。", "妹子，咱与叔叔陪话去来。", "(唱)。"]'),
('yuanqu-5334','关云长千里独行・骂玉郎','无名氏','元','元曲','yuanqu','','[]','则我这心中负屈应难受，不由我便扑簌簌泪交的流，我见他扑登忿怒难收救。',55,'元曲/yuanqu.json','["则我这心中负屈应难受，不由我便扑簌簌泪交的流，我见他扑登忿怒难收救。", "他那里踢翻椅桌，攫了幔幕，紧揎起那征袍袖。"]'),
('yuanqu-5335','关云长千里独行・采茶歌','无名氏','元','元曲','yuanqu','','[]','叔叔你早则么皱着眉头，休记冤仇，叔叔你与我停嗔息怒。',314,'元曲/yuanqu.json','["叔叔你早则么皱着眉头，休记冤仇，叔叔你与我停嗔息怒。", "寿亭侯，则你那失散了的哥哥不知道无共有，方信道知心的这相识可也到头休。", "(云)妹妹，俺跪着。", "二叔叔，可怜见俺姊妹二人。", "(正旦、小旦都跪科)(关末云)嫂嫂请起。", "你休烦恼，你欢喜咱。", "(二旦云)我有甚么欢喜？(关末云)嫂嫂，你不知俺哥哥兄弟，见在古城有哩。", "(正旦云)叔权，谁那般道？(关末云)嫂嫂，今日曹丞相请我赴宴。", "有一个张虎来说，我哥哥兄弟杀退了他，哥哥兄弟如今见在古城。", "我故意推醉，我特来报与嫂嫂知道。", "(二旦云)是真个？(关末云)是真个。", "我将曹丞相赐与我的金银和这寿亭侯牌印，我都锁在宜阳宅。", "不分星夜，便出许都。", "(正旦云)是真个？惭愧也。", "叔叔，则今日收拾行李，便索长行。", "(唱)。"]'),
('yuanqu-5336','关云长千里独行・尾声','无名氏','元','元曲','yuanqu','','[]','则你那忠直勇烈依了你口，谁想这刘备、张飞见在有。',66,'元曲/yuanqu.json','["则你那忠直勇烈依了你口，谁想这刘备、张飞见在有。", "打听的兄弟哥哥有时候，忙离了许州，盼不到地头，俺遥望着千里的这红尘路儿上走。", "(下)。"]'),
('yuanqu-5337','关云长千里独行・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','则你那途路迢遥，趁西风斜阳古道，催几鞭行色劬劳。',56,'元曲/yuanqu.json','["则你那途路迢遥，趁西风斜阳古道，催几鞭行色劬劳。", "践红尘，登紫陌，领着些关西小校。", "不索辞曹，恨不的一时间古城行到。"]'),
('yuanqu-5338','关云长千里独行・醉春风','无名氏','元','元曲','yuanqu','','[]','你今日弃印觅亲兄，你则待封金谒故交。',169,'元曲/yuanqu.json','["你今日弃印觅亲兄，你则待封金谒故交。", "独行千里探哥哥，似叔叔的少、少、少。", "他把你官上加官，禄上赠禄，曹丞相傲也那不傲。", "(关末云)兀的后面有军马至了。", "(曹末同张辽、许褚上，云)兀的前面不是云长？(做唤关末科，云)寿亭侯兄弟也，且住者。", "(关末云>真个是丞相领兵赶来。", "(正旦云)叔叔，曹丞相领兵赶将来，你小心在意者。", "(关末云)不妨事。", "(正旦唱)。"]'),
('yuanqu-5339','关云长千里独行・红绣鞋','无名氏','元','元曲','yuanqu','','[]','曹孟德能施谋略，则要你个关云长牢把鞍桥，咱可便嘴尾相衔紧随着，暗暗的便埋着军将，明明的列着枪刀，可休似徐州城失散了。',231,'元曲/yuanqu.json','["曹孟德能施谋略，则要你个关云长牢把鞍桥，咱可便嘴尾相衔紧随着，暗暗的便埋着军将，明明的列着枪刀，可休似徐州城失散了。", "(云)叔叔，小心在意者。", "(关末云)嫂嫂放心，我自知道。", "(曹末上见住)(做下马科，云)寿亭侯兄弟也，怎生不辞而去？(关末云)丞相勿罪，我不下马来也。", "(许褚云)呀，可早一条计也。", "(曹末云)将酒来。", "(许褚做斟酒科)(曹末递酒科，云)云长，既然你要去也，你下马来满饮一杯。", "(正旦云)叔叔，你休下马去。", "(关末云)嫂嫂，他与咱送路，他有甚么歹意？(正旦唱)。"]'),
('yuanqu-5340','关云长千里独行・快活三','无名氏','元','元曲','yuanqu','','[]','则他那饯行的意虽好，铺谋的智难逃。',35,'元曲/yuanqu.json','["则他那饯行的意虽好，铺谋的智难逃。", "不妨马上接了香醪，我与你附耳低低道。"]'),
('yuanqu-5341','关云长千里独行・朝天子','无名氏','元','元曲','yuanqu','','[]','我这里望着，定睛的觑了，曹丞相百万军都来到。',87,'元曲/yuanqu.json','["我这里望着，定睛的觑了，曹丞相百万军都来到。", "据着他兴心主意不相饶，折算你谁知道。", "我见他厚礼卑辞，亲捧香醪，这里面安排下斩人刀。", "叔叔你喑约，则依着你嫂嫂，则怕他酒里面藏有机妙。"]'),
('yuanqu-5342','关云长千里独行・上小楼','无名氏','元','元曲','yuanqu','','[]','他待使些雕心鹰爪，安排下龙韬虎略。',67,'元曲/yuanqu.json','["他待使些雕心鹰爪，安排下龙韬虎略。", "他一个个执锐披坚，勒马横枪，举斧轮刀。", "他将一领锦征袍，盘内托，我可便观了容貌，他那里曲躬躬一身伏着。"]'),
('yuanqu-5343','关云长千里独行・幺篇','无名氏','元','元曲','yuanqu','','[]','又不向盘内取，则向刀刃上挑。',59,'元曲/yuanqu.json','["又不向盘内取，则向刀刃上挑。", "险些儿惊杀许褚，荒杀曹公，唬杀张辽。", "他每都，紧赶着，奸雄曹操。", "我问你那锦征袍要也那不要？。"]'),
('yuanqu-5344','关云长千里独行・尾声','无名氏','元','元曲','yuanqu','','[]','袭车胄武艺能，刺颜良名分高。',50,'元曲/yuanqu.json','["袭车胄武艺能，刺颜良名分高。", "用尽自己心，惹的旁人笑。", "哎，你个奸雄曹操，到陪了西川十样锦征袍。", "(下)。"]'),
('yuanqu-5345','关云长千里独行・双调/新水令','无名氏','元','元曲','yuanqu','','[]','你保护的俺一家儿妯娌得安康，则他弟和兄这其间别来无恙。',60,'元曲/yuanqu.json','["你保护的俺一家儿妯娌得安康，则他弟和兄这其间别来无恙。", "叔叔你是那檠天白玉柱，架海的紫金梁。", "义勇忠良，俺今日团圆日不承望。"]'),
('yuanqu-5346','关云长千里独行・殿前欢','无名氏','元','元曲','yuanqu','','[]','若不是这汉云长，则为俺这家属不得已可便诈投降。',195,'元曲/yuanqu.json','["若不是这汉云长，则为俺这家属不得已可便诈投降。", "(刘末云)他受他封官来。", "(正旦唱)寿亭侯官职无心望，甚的他快乐的这心肠。", "(云)那一日与曹操饮酒，听的说主公与小叔叔在此，收拾便行。", "(咀)他封金印出许都，(带云)曹操赶至灞陵桥，三计要拿云长，二叔叔致怒。", "(唱)险唬杀那曹丞相，锦征袍便斜挑在他刀尖上。", "(带云)若不是二叔叔，俺三房头家小，都落在曹营。", "(唱)怎能勾那弟兄每完聚，也不能勾今日得这还乡。"]'),
('yuanqu-5347','关云长千里独行・川拨棹','无名氏','元','元曲','yuanqu','','[]','你那里自参详，张将军不料量。',42,'元曲/yuanqu.json','["你那里自参详，张将军不料量。", "他那里说短论长，数黑论黄。", "断不了村沙莽撞，你心中自忖量。"]'),
('yuanqu-5348','关云长千里独行・七弟兄','无名氏','元','元曲','yuanqu','','[]','他可便这厢那厢，他两个逞能强，怒忿忿豪气三千丈。',72,'元曲/yuanqu.json','["他可便这厢那厢，他两个逞能强，怒忿忿豪气三千丈。", "他丈八矛轮动怎生当，这青龙刀举起无遮当，好着我泪两行。", "便有些不停当，你心下自参详，你心下自参详。"]'),
('yuanqu-5349','关云长千里独行・喜江南','无名氏','元','元曲','yuanqu','','[]','呀，则你那哥哥兄弟好商量，不比你一勇性石亭驿里摔袁祥。',55,'元曲/yuanqu.json','["呀，则你那哥哥兄弟好商量，不比你一勇性石亭驿里摔袁祥。", "救了俺全家老小得安康，你自便料量，息怒波兴刘灭楚汉张良。"]'),
('yuanqu-5350','关云长千里独行・挂玉钩','无名氏','元','元曲','yuanqu','','[]','他恰才万马千军摆下战场，则见他忙把门旗放，显出那弃印封金有智量。',68,'元曲/yuanqu.json','["他恰才万马千军摆下战场，则见他忙把门旗放，显出那弃印封金有智量。", "他怎肯扶立起曹丞相，斩了蔡阳，在杀场上。", "才听的挝鼓三通，可又早得胜还乡。"]'),
('yuanqu-5351','双调・蟾宫曲','张子友','元','元曲','yuanqu','','[]','画堂深夜宴初开，香霭雕盘，烛焰银台。',67,'元曲/yuanqu.json','["画堂深夜宴初开，香霭雕盘，烛焰银台。", "妙舞轻歌，翠红乡十二金钗。", "会受用簪缨贵客，笑谁同量卷江淮。", "祗从安排，左右扶策，月转花梢，讯马回来。"]'),
('yuanqu-5352','中吕・普天乐春日多雨','王仲元','元','元曲','yuanqu','','[]','无一日惠风和，常四野彤云布，那里肯妆金点翠，只待要迸玉筛珠。',442,'元曲/yuanqu.json','["无一日惠风和，常四野彤云布，那里肯妆金点翠，只待要迸玉筛珠。", "这其间湖景阴，恰便似江天暮，冷清清孤山路，六桥迷雪压模糊。", "瞥见游春杜甫，只疑是寻梅浩然，莫不是相访林逋。", "赠美人柳眉新，桃腮嫩，酥凝琼腻，花艳芳温。", "歌声消天下愁，舞袖散人间闷。", "举止温柔娇风韵，司空见也索销魂。", "兰姿蕙魄，瑶花玉蕊，误染风尘。", "旅况树杈丫，藤缠挂，冲烟塞雁，接翅昏鸦。", "展江乡水墨图，列湖口潇湘画。", "过浦穿溪沿江汊，问孤航夜泊谁家。", "无聊倦客，伤心逆旅，恨满天涯。", "离情淹蓝桥，烧袄庙，镜鸾肠断，瑟凤魂销。", "玉容残倦艳妆，云髻乱慵梳掠。", "闷倚危阑闲凝眺，对斜阳分外无聊。", "秦川路远，阳台雨歇，楚岫云高。", "离恨拥鸳衾，歌珊枕，扫窗风竹，捣月寒砧，思量心别恨填，欢喜梦离愁禁。", "主意抛迟亏人甚，薄情郎何处留心。", "君怀幸短，盟山路险，誓海波深。", "相思泪盈波，眉愁锁，消香减腻，病鬼愁魔。", "炉烟飘怨气浮，襟袖湿啼痕污。", "无限凄凉来著抹，瘦身躯怎生存活。", "相思未脱，他愁为我，我病因他。", "离情远山攒，乌云乱，分钗破鉴，单枕孤鸾。", "芳心被闷织罗，病躯教愁羁绊。"]'),
('yuanqu-5353','双调・江儿水叹世','王仲元','元','元曲','yuanqu','','[]','谁待理他闲是非，紧把红尘避。',370,'元曲/yuanqu.json','["谁待理他闲是非，紧把红尘避。", "庵前绿水围，门外青山对，寻一个稳便处闲坐地。", "竹冠草鞋粗布衣，晦迹韬光计。", "灰残风月心，参得烟霞味，寻一个稳便处闲坐地。", "茅斋倚山门傍溪，镇日常关闭。", "安闲养此心，去住从吾意，寻一个稳便处闲坐地。", "功名玉关十万里，委实劳心力。", "争如四皓仙，不愿三公位，寻一个稳便处闲坐地。", "功劳既成名遂矣，便索抽身退。", "裴公绿野中，陶令东篱内，寻一个稳便处闲坐地。", "笑他卧龙因甚起？不了终身计。", "贪甚青史名？弃却红尘利，寻一个稳便处闲坐地。", "扁舟五湖越范蠡，有分烟波内。", "丝纶远是非，蓑笠多风味，寻一个稳便处闲坐地。", "红尘不来侵钓矶，别却风云会。", "一钓了此生，七里全身计，寻一个稳便处闲坐地。", "五柳绕庄菊满篱，自谓羲皇世。", "三径可怡颜，一榻堪容膝，寻一个稳便处闲坐地。", "妇人脸上笑靥一团儿可人纯是娇，妆点如花貌。", "抬叠起脸上秋，出落腮边俏，千金这窠里消费了。", "套数。"]'),
('yuanqu-5354','中吕・粉蝶儿集曲名题秋怨','王仲元','元','元曲','yuanqu','','[]','双雁儿声悲，景潇潇楚江秋意，胜阳关刮地风吹。',57,'元曲/yuanqu.json','["双雁儿声悲，景潇潇楚江秋意，胜阳关刮地风吹。", "满庭芳，梧桐树，金蕉叶坠。", "庆东原金菊香滴滴金堆，那更醉西湖干荷叶失翠。"]'),
('yuanqu-5355','迎仙客・都不念奴娇望远行，忘了初相见在武陵溪。骂玉郎有上梢没末尾，','王仲元','元','元曲','yuanqu','','[]','瘦削了柳丝玉芙蓉花面皮。',26,'元曲/yuanqu.json','["瘦削了柳丝玉芙蓉花面皮。", "这翠眉儿挛刺，捱这等相思会。"]'),
('yuanqu-5356','红绣鞋・上小楼凭阑人立，青山口日上平西。子听得乔木楂鹊踏枝叫声疾，','王仲元','元','元曲','yuanqu','','[]','莫不倘秀才馀音至？夜行船阮郎归，原来是牧羊关乌夜啼。',26,'元曲/yuanqu.json','["莫不倘秀才馀音至？夜行船阮郎归，原来是牧羊关乌夜啼。"]'),
('yuanqu-5357','石榴花・常记得赏花时节看花回，上京马醉扶扫，归来窗半月儿低，真个','王仲元','元','元曲','yuanqu','','[]','醉矣。',50,'元曲/yuanqu.json','["醉矣。", "柳青娘虞美人扶只，困腾腾上马娇无力，步步娇弄影儿行迟。", "似凤鸾交配答双鸳鸯对，人都道端正好夫妻。"]'),
('yuanqu-5358','斗鹌鹑・不误这万年观娱，翻做了荆湘怨忆。把一个玉翼婵娟，闪在瑶台','王仲元','元','元曲','yuanqu','','[]','月底。',35,'元曲/yuanqu.json','["月底。", "想曩日逍遥乐事迷，今日呆古朵自悔。", "子落得初问口长吁，哭皇天泪滴。"]'),
('yuanqu-5359','普天乐・空闲了愿成双，鸳鸯儿被。搅筝琶断毁，碧玉箫尘迷。四块玉簪','王仲元','元','元曲','yuanqu','','[]','折，一锭银瓶坠。',48,'元曲/yuanqu.json','["折，一锭银瓶坠。", "叹姻缘节节高天际，这淹证候越随煞愁的。", "想两相思病体，把红芍药枉吃，有圣药王难医。"]'),
('yuanqu-5360','醉春风・何日愿成双，几时能够端正好？只除是忆王孙合小桃红，怎消得','王仲元','元','元曲','yuanqu','','[]','这恼，恼，恼。',25,'元曲/yuanqu.json','["这恼，恼，恼。", "直吃得沉醉东风，武陵溪畔，后庭花落。"]'),
('yuanqu-5361','迎仙客・樱桃般点绛唇，杨柳般翠裙腰。红绣鞋轻移莲步小，柳眉颦一半','王仲元','元','元曲','yuanqu','','[]','儿娇。',20,'元曲/yuanqu.json','["儿娇。", "端的有络丝娘的妖娆，似一朵红芍药。"]'),
('yuanqu-5362','红绣鞋・上平西看看日落，念奴娇梦断魂劳。鹊踏枝黄昏里哨遍林梢，双','王仲元','元','元曲','yuanqu','','[]','雁儿呀呀叫。',21,'元曲/yuanqu.json','["雁儿呀呀叫。", "牧羊关外野猿号，怨别离难睡着。"]'),
('yuanqu-5363','石榴花・绿窗人去闷难煞，哭皇天和泪洒芭蕉。人月圆最好，愁杀我也凤','王仲元','元','元曲','yuanqu','','[]','友鸾交。',22,'元曲/yuanqu.json','["友鸾交。", "两相思真病难医疗，只除倘秀才赴蓝桥。"]'),
('yuanqu-5364','斗鹌鹑・想起那拨不断恩情，元和令下梢。上马娇郎君，看花回最好。归','王仲元','元','元曲','yuanqu','','[]','塞北恩情恨未消，呆古朵怎放脱了？石榴花裙儿，绵答絮睡着。',28,'元曲/yuanqu.json','["塞北恩情恨未消，呆古朵怎放脱了？石榴花裙儿，绵答絮睡着。"]'),
('yuanqu-5365','普天乐・卖花声，还惊觉。把一朵雪里梅，生扭的粉碎烟焦。骂玉郎，伤','王仲元','元','元曲','yuanqu','','[]','怀抱，几时捱得金鸡叫。',36,'元曲/yuanqu.json','["怀抱，几时捱得金鸡叫。", "凭阑人恨杀才敲，一枝花瘦了。", "穿窗月底，虞美人难熬。"]'),
('yuanqu-5366','尾・醉扶归入画堂，轻移步步娇。阮郎归一去无音耗，空踏遍台前寄生草。道情','王仲元','元','元曲','yuanqu','','[]','引的是白鹿玄鹤，向云水乡那答儿不到？药篮儿肩上斜挑，上云梯，穿石凳，猛然凝眺。',54,'元曲/yuanqu.json','["引的是白鹿玄鹤，向云水乡那答儿不到？药篮儿肩上斜挑，上云梯，穿石凳，猛然凝眺。", "不觉地老天高，正宜咱孟嘉落帽。"]'),
('yuanqu-5367','醉春风・玉露润菊花肥，金风催梧叶老。黄花红叶满秋山，此景畅是好、','王仲元','元','元曲','yuanqu','','[]','好、好。',19,'元曲/yuanqu.json','["好、好。", "野水横桥，淡烟衰草，晚峰残照。"]'),
('yuanqu-5368','迎仙客・见一座小道庵，盖的来一个茅，舍俗出家远市朝。俺那里水烟深，','王仲元','元','元曲','yuanqu','','[]','山势高，四壁周遭，不许些红尘到。',16,'元曲/yuanqu.json','["山势高，四壁周遭，不许些红尘到。"]'),
('yuanqu-5369','满庭芳・您道是为官是好，光阴断送，催逼了些宰相臣僚。细思量君起早','王仲元','元','元曲','yuanqu','','[]','时臣起早，俺也曾子细评跋。',58,'元曲/yuanqu.json','["时臣起早，俺也曾子细评跋。", "譬似去丹墀内穿靴着袍，怎如俺草庵中丫髻环绦？标写在凌烟阁，便做到太师太傅太保，难免折腰劳。"]'),
('yuanqu-5370','耍孩儿・俺那里香风不动松花老，比您那帝辇京师较好。每日看神仙神女','王仲元','元','元曲','yuanqu','','[]','住仙庄，俺吃的是仙酒仙桃。',47,'元曲/yuanqu.json','["住仙庄，俺吃的是仙酒仙桃。", "俺那里风花雪月人长久，春夏秋冬草不雕。", "观着星曜，清闲落魄，快活逍遥。"]'),
('yuanqu-5371','二・俺争将紫府游，斗把玉帝朝，辂车凤辇知多少。三更月底銮声远，万','王仲元','元','元曲','yuanqu','','[]','里风头鹤背高，每日价神仙闹。',24,'元曲/yuanqu.json','["里风头鹤背高，每日价神仙闹。", "屯合月窟，塞满天桥。"]'),
('yuanqu-5372','尾・竹林寺里无俺弟兄，桃源洞有俺故交。待教你寻真误入蓬莱岛，把你','王仲元','元','元曲','yuanqu','','[]','浊骨凡胎替换了。',8,'元曲/yuanqu.json','["浊骨凡胎替换了。"]'),
('yuanqu-5373','越调・斗鹌鹑咏雪','王仲元','元','元曲','yuanqu','','[]','云幕重封，风刀劲刮。',48,'元曲/yuanqu.json','["云幕重封，风刀劲刮。", "玉絮轻ㄎ，琼苞碎打，粉叶飘扬，盐花乱撒。", "一色白，六出花，密密疏疏，潇潇洒洒。"]'),
('yuanqu-5374','紫花儿・莹玉缘高山岭岫，水晶碾陆地楼台，玻璃砌老树槎丫。蚕食柔叶，','王仲元','元','元曲','yuanqu','','[]','蟹走平沙。',31,'元曲/yuanqu.json','["蟹走平沙。", "时霎，列壁铺琼迷万瓦，随风高下。", "蝶粉翩翩，蜂翅交杂。"]'),
('yuanqu-5375','秃厮儿・应时候在深冬暮腊，高盈户报丰稔年华，驱蝗入土将瘴气压。真','王仲元','元','元曲','yuanqu','','[]','祥瑞，耀国家，堪夸。',10,'元曲/yuanqu.json','["祥瑞，耀国家，堪夸。"]'),
('yuanqu-5376','尾・唤家童且把毡帘下，教侍妾高烧绛蜡。读书舍烹茶的淡薄多，销金帐','王仲元','元','元曲','yuanqu','','[]','里传杯的快活煞。',8,'元曲/yuanqu.json','["里传杯的快活煞。"]'),
('yuanqu-5377','玉箫女两世姻缘・仙吕/点绛唇','乔吉','元','元曲','yuanqu','','[]','云鬓花钿，舞裙歌扇，我却也无心恋。',32,'元曲/yuanqu.json','["云鬓花钿，舞裙歌扇，我却也无心恋。", "怕不道春正芳妍，只落得人轻贱。"]'),
('yuanqu-5378','玉箫女两世姻缘・混江龙','乔吉','元','元曲','yuanqu','','[]','我不比等闲行院，煞教我占场儿住老丽春园。',91,'元曲/yuanqu.json','["我不比等闲行院，煞教我占场儿住老丽春园。", "卖虚睥眉尖眼角，散和气席上尊前。", "是学的系玉敲金三百段，常则是撩云拨雨二十年，这家风愿天上有眼的休教见。", "我想来，但得个夫妻美满，煞强如旦末双全。"]'),
('yuanqu-5379','玉箫女两世姻缘・油葫芦','乔吉','元','元曲','yuanqu','','[]','有那等滴溜的猱儿不觅钱，他每都错怨天，情知那干村沙怎做的玉天仙。',107,'元曲/yuanqu.json','["有那等滴溜的猱儿不觅钱，他每都错怨天，情知那干村沙怎做的玉天仙。", "那里有野鸳鸯眼秃刷的在黄金殿，则这伙木鹦哥嘴骨邦的在仙音院。", "搽-个红颊腮似赤马猴，舒着双黑爪老似通臂猿，抱着面紫檀槽弹不的昭君怨，凤凰箫吹不出鹧鸪天。"]'),
('yuanqu-5380','玉箫女两世姻缘・天下乐','乔吉','元','元曲','yuanqu','','[]','哎，也算做闷向秦楼列管弦，(带云)到那三杯酒后呵，(唱)觑不的那抓掀。',166,'元曲/yuanqu.json','["哎，也算做闷向秦楼列管弦，(带云)到那三杯酒后呵，(唱)觑不的那抓掀。", "鬏髻偏，便似那披荷叶搭刺着个褐袖肩。", "(末云)他这等模样，倘那子弟道，你歌舞一会咱，他却如何？(正旦云)他便道我醉了，歌舞不的了。", "倘若再三央浼呵。", "(唱)狗沁歌嚎了几声，鸡爪风扭了半边。", "(云)投至临散时，可有一件好处。", "(末云)有甚好处？(正旦唱)抓着块羊骨头一道烟。"]'),
('yuanqu-5381','玉箫女两世姻缘・那吒令','乔吉','元','元曲','yuanqu','','[]','见一面半面，弃茶船米船；着一拳半拳，毁山田水田；待一年半年，卖南园北园。',64,'元曲/yuanqu.json','["见一面半面，弃茶船米船；着一拳半拳，毁山田水田；待一年半年，卖南园北园。", "我着他白玉妆了翡翠楼，黄金垒了鸳鸯殿，珍珠砌子流水桃源。"]'),
('yuanqu-5382','玉箫女两世姻缘・鹊踏枝','乔吉','元','元曲','yuanqu','','[]','他见我舞蹁跹，看的做玉婵娟；抹一块鼻凹里沙塘，流两行口角底顽涎。',53,'元曲/yuanqu.json','["他见我舞蹁跹，看的做玉婵娟；抹一块鼻凹里沙塘，流两行口角底顽涎。", "有那等花木瓜长安少年，他每不斟量隔屋撺椽。"]'),
('yuanqu-5383','玉箫女两世姻缘・幺篇','乔吉','元','元曲','yuanqu','','[]','俺娘休想投窄寨，常则待拽大举。',75,'元曲/yuanqu.json','["俺娘休想投窄寨，常则待拽大举。", "恰便是老妖精曾吵闹了蟠桃宴，凭着那巧舌头敢聒噪了森罗殿，拖着条黄桑棒直轮磨到悲田院。", "藕池中锯折并头莲，泥窝里掏杀双飞燕。"]'),
('yuanqu-5384','玉箫女两世姻缘・得胜乐','乔吉','元','元曲','yuanqu','','[]','将罗袖卷，香醪劝，请学士官人稳便，这的是酿清泉朝来新镟，直吃的金盏里倒垂莲。',54,'元曲/yuanqu.json','["将罗袖卷，香醪劝，请学士官人稳便，这的是酿清泉朝来新镟，直吃的金盏里倒垂莲。", "(卜儿上，打咳嗽科)(正旦唱)。"]'),
('yuanqu-5385','玉箫女两世姻缘・后庭花','乔吉','元','元曲','yuanqu','','[]','今日在汴河边倚画船，明日在天津桥闻杜鹃。',91,'元曲/yuanqu.json','["今日在汴河边倚画船，明日在天津桥闻杜鹃。", "最苦是相思病，极高的离恨天，空教我泪涟涟。", "凄凉杀花间莺燕，散东风榆荚钱，锁春愁杨柳烟。", "断肠在过雁前，销魂向落照边。", "苦恹恹恨怎言？急煎煎情惨然。"]'),
('yuanqu-5386','玉箫女两世姻缘・青歌儿','乔吉','元','元曲','yuanqu','','[]','天那！人在这离亭、离亭开宴，酒和愁怎生、怎生吞咽？狠毒娘下的也么天！情绪绵绵。',88,'元曲/yuanqu.json','["天那！人在这离亭、离亭开宴，酒和愁怎生、怎生吞咽？狠毒娘下的也么天！情绪绵绵。", "想柳畔花边，月下星前，共枕同眠，携手凭肩。", "离暮雨亭轩，望落日山川，问雕鞍何日是归年？俺和你重相见。"]'),
('yuanqu-5387','玉箫女两世姻缘・赚煞','乔吉','元','元曲','yuanqu','','[]','眼见的天阔雁书迟，赤紧的日近长安远，则怕我受官诰的缘薄分浅，则愿的一举成名在日边。',145,'元曲/yuanqu.json','["眼见的天阔雁书迟，赤紧的日近长安远，则怕我受官诰的缘薄分浅，则愿的一举成名在日边。", "(带云)你寄音书呵，(唱)休爱惜象管鸾笺。", "(末云)大姐，屈着指头儿数，不出三年，我便来也。", "(正旦唱)则愿的早三年，人月团圆，休教妾常倚东风泣断弦。", "你休恋京师帝辇，别求夫人宅眷，把咱好姻缘翻做了恶姻缘。", "(下)。"]'),
('yuanqu-5388','玉箫女两世姻缘・商调/集贤宾','乔吉','元','元曲','yuanqu','','[]','隔纱窗日高花弄影，听何处啭流莺。',99,'元曲/yuanqu.json','["隔纱窗日高花弄影，听何处啭流莺。", "虚飘飘半衾幽梦，困腾腾一枕春酲。", "趁着那游丝儿恰飞过竹坞桃溪，随着这蝴蝶儿又来到月榭风亭。", "觉来时倚着这翠云十二屏，恍惚似坠露飞萤。", "多咱是寸肠千万结，只落的长叹两三声！。"]'),
('yuanqu-5389','玉箫女两世姻缘・逍遥乐','乔吉','元','元曲','yuanqu','','[]','犹古自身心不定，倚遍危楼，望不见长安帝京。',74,'元曲/yuanqu.json','["犹古自身心不定，倚遍危楼，望不见长安帝京。", "何处也，薄情，多应恋金屋银屏。", "想则想于咱不志诚，空说于碜磕磕海誓山盟。", "赤紧的关河又远，岁月如流，鱼雁无凭。"]'),
('yuanqu-5390','玉箫女两世姻缘・尚京马','乔吉','元','元曲','yuanqu','','[]','我觑不的雁行弦断卧瑶筝，风嘴声残冷玉笙，兽面香消闲翠鼎。',45,'元曲/yuanqu.json','["我觑不的雁行弦断卧瑶筝，风嘴声残冷玉笙，兽面香消闲翠鼎。", "门半掩悄悄冥冥，断肠人和泪梦初醒。"]'),
('yuanqu-5391','玉箫女两世姻缘・梧叶儿','乔吉','元','元曲','yuanqu','','[]','火燎也似身躯热，锥剜也似额角疼，即渐里瘦子身形。',167,'元曲/yuanqu.json','["火燎也似身躯热，锥剜也似额角疼，即渐里瘦子身形。", "这几日茶饭上不待吃，睡卧又不甚宁。", "(卜儿云)我请医者看看你这脉息，知他是甚么症候。", "(正旦唱)若将这脉来凭，多管是废寝忘餐病症。", "(卜儿云)梅香，好生伏事您姐姐，我下边看些汤药来。", "(虚下)(梅香云)姐姐，你怎么这等想俺姐夫？(正旦云)我实瞒不的你，据着他那人物才学，如何教我不想也！(唱)。"]'),
('yuanqu-5392','玉箫女两世姻缘・醋葫芦','乔吉','元','元曲','yuanqu','','[]','看了他容貌儿实是撑，衣冠儿别样整，更风流、更洒落、更聪明。',65,'元曲/yuanqu.json','["看了他容貌儿实是撑，衣冠儿别样整，更风流、更洒落、更聪明。", "唱一篇小曲儿宫调清，一团儿软款温柔情性，兀的不坑下人性命、引了人魂灵！。"]'),
('yuanqu-5393','玉箫女两世姻缘・金菊香','乔吉','元','元曲','yuanqu','','[]','想着他锦心绣腹那才能，怎教我月下花前不动情！信口里小曲儿编捏成，端的足剪雪裁冰，惺惺的自古惜惺惺。',49,'元曲/yuanqu.json','["想着他锦心绣腹那才能，怎教我月下花前不动情！信口里小曲儿编捏成，端的足剪雪裁冰，惺惺的自古惜惺惺。"]'),
('yuanqu-5394','玉箫女两世姻缘・浪里来','乔吉','元','元曲','yuanqu','','[]','假若我乍吹箫别院声，他便眼巴巴帘下等，自等到星移斗转二三更。',84,'元曲/yuanqu.json','["假若我乍吹箫别院声，他便眼巴巴帘下等，自等到星移斗转二三更。", "入门来画堂春自生，紧紧的将咱搂定，那温存、那将惜、那劳承！(带云)解元呵，想起你那般风韵，害杀我也！(唱)。"]'),
('yuanqu-5395','玉箫女两世姻缘・后庭花','乔吉','元','元曲','yuanqu','','[]','想着他和蔷薇花露清，点胭脂红蜡冷，整花朵心偏耐，画蛾眉手惯经，梳说罢将玉肩凭，恰似对鸳鸯交颈。',94,'元曲/yuanqu.json','["想着他和蔷薇花露清，点胭脂红蜡冷，整花朵心偏耐，画蛾眉手惯经，梳说罢将玉肩凭，恰似对鸳鸯交颈。", "到如今玉叽骨减了九停，粉香消没了半星，空凝盼秋水横，甚情将云鬓整。", "骨岩岩瘦不胜，闷恹恹扮不成。"]'),
('yuanqu-5396','玉箫女两世姻缘・金菊香','乔吉','元','元曲','yuanqu','','[]','怕不待儿番落笔强施呈，争奈一段伤心画不能。',49,'元曲/yuanqu.json','["怕不待儿番落笔强施呈，争奈一段伤心画不能。", "腮斗上泪痕粉渍定，没颜色鬓乱钗横，和我这眼皮眉黛欠分明。"]'),
('yuanqu-5397','玉箫女两世姻缘・柳叶儿','乔吉','元','元曲','yuanqu','','[]','兀的不寂寞了菱花妆镜，自觑下白害心疼，将一片志诚心写入下冰绡巾争。',55,'元曲/yuanqu.json','["兀的不寂寞了菱花妆镜，自觑下白害心疼，将一片志诚心写入下冰绡巾争。", "这一篇相思令，寄与多情，道是人憔悴不似丹青。"]'),
('yuanqu-5398','玉箫女两世姻缘・浪里来','乔吉','元','元曲','yuanqu','','[]','你道个题侨的没倍行，驾乍的无准成。',69,'元曲/yuanqu.json','["你道个题侨的没倍行，驾乍的无准成。", "我把他汉相如厮敬重，不多争，我比那卓文君有稍没了四星，空教我叫天来不应。", "秀才呵，岂不闻举头三尺行神明！。"]'),
('yuanqu-5399','玉箫女两世姻缘・高过随调煞','乔吉','元','元曲','yuanqu','','[]','心事人拔下短筹，有情人太薄幸。',96,'元曲/yuanqu.json','["心事人拔下短筹，有情人太薄幸。", "他说道三年来，刊如今五载不回程，好教咱上天远，入地近，泼残生恰便似风内灯。", "(带云)小二哥，(唱)比及你见俺那亏心的短命，则我这一灵儿先《出洛阳城。", "(做死科，下)。"]'),
('yuanqu-5400','玉箫女两世姻缘・越调/斗鹌鹑','乔吉','元','元曲','yuanqu','','[]','翡翠窗纱，鸳鸯碧瓦，孔雀金屏，芙蓉绣榻。',51,'元曲/yuanqu.json','["翡翠窗纱，鸳鸯碧瓦，孔雀金屏，芙蓉绣榻。", "幕卷轻绡，香焚睡鸭。", "灯上上，帘下下，这的是南省尚书，东床驸马。"]'),
('yuanqu-5401','玉箫女两世姻缘・紫花儿序','乔吉','元','元曲','yuanqu','','[]','帐前年朱衣画戟，门下士锦带吴钩，坐上客绣帽宫花。',68,'元曲/yuanqu.json','["帐前年朱衣画戟，门下士锦带吴钩，坐上客绣帽宫花。", "本教坊歌舞，依内苑奢华。", "板撒红牙，一派箫韶准备上。", "则两行美人如画，有粉面银筝，玉手琵琶。"]'),
('yuanqu-5402','玉箫女两世姻缘・调笑令','乔吉','元','元曲','yuanqu','','[]','这生我那里也曾见他，莫不是我眼睛花？手抵着牙儿是记咱。',79,'元曲/yuanqu.json','["这生我那里也曾见他，莫不是我眼睛花？手抵着牙儿是记咱。", "(带云)好作怪也。", "(唱)不由我心儿里相牵挂，莫不是五百午欢喜冤家？何处绿杨曾系马，莫个是梦儿中云雨巫峡。"]'),
('yuanqu-5403','玉箫女两世姻缘・小桃红','乔吉','元','元曲','yuanqu','','[]','玉箫吹彻碧桃花，端的足一刻千金价。',142,'元曲/yuanqu.json','["玉箫吹彻碧桃花，端的足一刻千金价。", "(末偷视科)(正旦唱)他背影卫斜将眼稍抹，唬的我脸烘霞。", "(张延赏云！再满斟酒者。", "(旦把盏科，唱)俺上人酒杯嫌杀春风凹。", "(末低云)小娘子多大年纪？曾许配与谁？(正旦低唱)俺新年十八，未曾招嫁。", "(末云)小娘子是他亲生女儿么？(正旦唱)俺主人培养出牡丹芽。"]'),
('yuanqu-5404','玉箫女两世姻缘・鬼三台','乔吉','元','元曲','yuanqu','','[]','他说起凄凉话，和我也泪不做行儿上，兜的唤回我心猿意马。',173,'元曲/yuanqu.json','["他说起凄凉话，和我也泪不做行儿上，兜的唤回我心猿意马。", "我是朵娇滴滴洛阳花，呀！险些的露出风流话靶。", "(张延赏云)你这等胡说。", "你道与你亡妻相类，不道与你做了媳妇罢。", "(正旦唱)这言词道耍来不是耍，这公事道假来个是假。", "(末云)委实似我亡妻，非为借言调戏。", "(正旦唱)他那里拔树寻根，(张延赏云)韦皋，这是我亲生女儿，你做何人看承？(正旦唱)便似你指鹿道马。"]'),
('yuanqu-5405','玉箫女两世姻缘・秃厮儿','乔吉','元','元曲','yuanqu','','[]','我劝谏他似水耻纳瓜，他看觑咱如镜里观花。',43,'元曲/yuanqu.json','["我劝谏他似水耻纳瓜，他看觑咱如镜里观花。", "便做道书生自来情性耍，怎生调戏俺好人家娇娃？。"]'),
('yuanqu-5406','玉箫女两世姻缘・麻郎儿','乔吉','元','元曲','yuanqu','','[]','他如今管领着金戈铁甲，簇拥着鼓吹鸣笳，他虽足违茶犯法，咱无甚势剑铜铡。',35,'元曲/yuanqu.json','["他如今管领着金戈铁甲，簇拥着鼓吹鸣笳，他虽足违茶犯法，咱无甚势剑铜铡。"]'),
('yuanqu-5407','玉箫女两世姻缘・幺篇','乔吉','元','元曲','yuanqu','','[]','怎么，忭大。',42,'元曲/yuanqu.json','["怎么，忭大。", "便杀他！有罪呵，御阶前吃几金瓜。", "他掌着百十万军权柄把，建奇功收伏了两夏。"]'),
('yuanqu-5408','玉箫女两世姻缘・络丝娘','乔吉','元','元曲','yuanqu','','[]','不争你舞剑的田文意差，恼的个绝缨会将军怒发。',50,'元曲/yuanqu.json','["不争你舞剑的田文意差，恼的个绝缨会将军怒发。", "(觑末科，唱)那里有娶媳妇当筵厮暗哑，也合倩个官媒打话。"]'),
('yuanqu-5409','玉箫女两世姻缘・收尾','乔吉','元','元曲','yuanqu','','[]','从来秀才每个个色胆天来大，险把我小胆儿文材唬杀。',168,'元曲/yuanqu.json','["从来秀才每个个色胆天来大，险把我小胆儿文材唬杀。", "(张延赏云)若不看着故人分上，我必杀汝以雪吾之耻。", "(正旦唱)息怒波文火性卓王孙，(末云)待我奏过朝廷，那时不道和你干休了哩。", "(领众下)(正旦唱)噤声波强风情汉司马。", "(下)(张延赏云)请的好客，请的好客，兀的不气杀我也！我想他此一去，必然面奏朝廷。", "你去的，我也去的，大家奏，大家奏。", "(下)。"]'),
('yuanqu-5410','玉箫女两世姻缘・沉醉东风','乔吉','元','元曲','yuanqu','','[]','玉箫习学就诗山曲海，生长在柳陌花街。',138,'元曲/yuanqu.json','["玉箫习学就诗山曲海，生长在柳陌花街。", "燕莺集每日忙，鸳鸯社逐朝赛。", "(驾云)你可怎么入的驸马家里？(正旦唱)俺那老虔婆见钱多卖，一札脚王侯宰相宅，谁敢道半米儿山河易改！(驾云)玉箫，你认的那韦皋么？(正旦云)妾曾会过，见时尚自认的。", "(驾云)你向班部中试认者。", "(旦起认末科)(唱)。"]'),
('yuanqu-5411','玉箫女两世姻缘・乔牌儿','乔吉','元','元曲','yuanqu','','[]','见他裹着乌纱帽那气概，秉着白象笏那尊大。',41,'元曲/yuanqu.json','["见他裹着乌纱帽那气概，秉着白象笏那尊大。", "宽绰绰紫罗袍偏称金鱼带，气昂昂立在白玉阶。"]'),
('yuanqu-5412','玉箫女两世姻缘・水仙子','乔吉','元','元曲','yuanqu','','[]','这公曾绝缨会上戏裙钗，(末云)我在那里来？(正旦唱)也曾细柳营中大会垓。',171,'元曲/yuanqu.json','["这公曾绝缨会上戏裙钗，(末云)我在那里来？(正旦唱)也曾细柳营中大会垓。", "(末云)我却怎生闹起来？(正旦唱)你将个相公宅看觑似莺花寨。", "(末云)是他先怒了我来。", "(正旦唱)你道是他不该，便活佛也恼下下莲台。", "(末云)我是大元帅，他如何便敢欺我？(正旦唱)也是俺官官相为，你可甚贤贤易色，(末云)我是好意求亲，他怎敢恁的！(正旦唱)因此上不远千里而来。"]'),
('yuanqu-5413','玉箫女两世姻缘・揽筝琶','乔吉','元','元曲','yuanqu','','[]','众文武都惊怪，不由咱心上转疑猜。',67,'元曲/yuanqu.json','["众文武都惊怪，不由咱心上转疑猜。", "这个即世婆婆，莫不是前世的奶奶？小字儿唤的明白，絮叨叨怨怨哀哀。", "似绿窗前唤回我春梦来，和我也雨泪盈腮。"]'),
('yuanqu-5414','玉箫女两世姻缘・雁儿落','乔吉','元','元曲','yuanqu','','[]','都一般胭脂桃杏腮，都一般金粉芙蓉额。',36,'元曲/yuanqu.json','["都一般胭脂桃杏腮，都一般金粉芙蓉额。", "都一般为云为雨情，都一般倾国倾城态。"]'),
('yuanqu-5415','玉箫女两世姻缘・甜水令','乔吉','元','元曲','yuanqu','','[]','他说的是十八年前，三千里外，因此上弄玉错投胎。',125,'元曲/yuanqu.json','["他说的是十八年前，三千里外，因此上弄玉错投胎。", "(驾云)玉萧，你原来死后投胎，到今一十八岁。", "你是青春幼女，韦元帅他是已过中年的人了，你肯与他做夫妻么？(正旦跪，云)人命修短不齐，焉知妾不死于元帅之先？(唱)陛下道我，正在青春，他虽年迈，也都是天地安排。"]'),
('yuanqu-5416','玉箫女两世姻缘・折桂令','乔吉','元','元曲','yuanqu','','[]','儿的不桃源洞枯树花开，他是那八辅官员，生的来一品人材。',152,'元曲/yuanqu.json','["儿的不桃源洞枯树花开，他是那八辅官员，生的来一品人材。", "(卜儿云)孩儿，你这等年貌不齐，何不别求佳婿？(正旦唱)他也年未衰残，圣恩匹配，相守头白。", "(张延赏云)我是贵戚宰相之家，为女求配，必得少年佳客，为何嫁此老夫？(正旦唱)遮莫你广成子吹箫凤台，姜太公流水天台，情愿琴瑟和谐，连理双栽，生则同衾，死则同埋。"]'),
('yuanqu-5417','玉箫女两世姻缘・落梅风','乔吉','元','元曲','yuanqu','','[]','可知、可知卖弄那金花诰，(扯张科，云)过来，过来。',68,'元曲/yuanqu.json','["可知、可知卖弄那金花诰，(扯张科，云)过来，过来。", "(唱)休触抹着玉镜台。", "秀才价做的来整盐黄菜，温太真更做道情性乖，怎敢向晋明行人惊小怪。"]'),
('yuanqu-5418','玉箫女两世姻缘・沽美酒','乔吉','元','元曲','yuanqu','','[]','你麟阁上论战策，风池卫试文才。',60,'元曲/yuanqu.json','["你麟阁上论战策，风池卫试文才。", "(带云)元帅，你烦恼怎么？(唱)摇机斯挺春风门下客，更怕甚宋弘事不谐，放心波今上自裁划！。"]'),
('yuanqu-5419','玉箫女两世姻缘・太平令','乔吉','元','元曲','yuanqu','','[]','也是他买了个赔钱货无如之奈。',74,'元曲/yuanqu.json','["也是他买了个赔钱货无如之奈。", "笑你个强项侯不伏烧埋。", "那壁似狼吃了幞头般宁耐，这壁如草地卫球儿般打快。", "不索你插钗，下财纳采，有甚消不的你展脚伸崾两拜！。"]'),
